INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_presentation_A1_01','talk','/tɔːk/','verb','말하다','To speak about something to one or more people.','I will {talk} about my hobby today.','오늘 제 취미에 대해 말할게요.','talk','A1','presentation',1,'person speaking audience microphone stage'),
('w_presentation_A1_02','show','/ʃoʊ/','verb','보여주다','To make something visible or display it.','Let me {show} you this picture.','이 사진을 보여드릴게요.','show','A1','presentation',1,'presentation screen projector display showing'),
('w_presentation_A1_03','tell','/tel/','verb','말하다, 알리다','To give information or explain something to someone.','I will {tell} you about my project.','제 프로젝트에 대해 말씀드릴게요.','tell','A1','presentation',1,'person explaining talking hand gesture'),
('w_presentation_A1_04','start','/stɑːrt/','verb','시작하다','To begin doing or being something.','Let us {start} the presentation now.','이제 발표를 시작하겠습니다.','start','A1','presentation',1,'presentation beginning opening podium speaker'),
('w_presentation_A1_05','end','/end/','verb','끝내다','To come to a finish or bring to a close.','We will {end} the talk in five minutes.','5분 후에 발표를 마무리하겠습니다.','end','A1','presentation',1,'presentation closing finish applause audience'),
('w_presentation_A1_06','first','/fɜːrst/','adverb','첫 번째로','Before anything or anyone else.','{First}, let me introduce myself.','먼저 자기소개를 하겠습니다.','First','A1','presentation',1,'number one first podium speaker beginning'),
('w_presentation_A1_07','next','/nekst/','adverb','다음으로','Coming immediately after the present one.','{Next}, I will show the results.','다음으로 결과를 보여드리겠습니다.','Next','A1','presentation',1,'arrow next step forward presentation slide'),
('w_presentation_A1_08','last','/læst/','adjective','마지막의','Coming after all others in time or order.','The {last} point is very important.','마지막 요점이 매우 중요합니다.','last','A1','presentation',1,'final last slide presentation conclusion'),
('w_presentation_A1_09','slide','/slaɪd/','noun','슬라이드','A single page of a presentation shown on screen.','Please look at this {slide}.','이 슬라이드를 봐주세요.','slide','A1','presentation',1,'powerpoint slide presentation screen projector'),
('w_presentation_A1_10','point','/pɔɪnt/','noun','요점','A particular fact, idea, or opinion in a discussion.','My main {point} is that practice helps.','제 주요 요점은 연습이 도움이 된다는 것입니다.','point','A1','presentation',1,'presentation key point highlight marker board'),
('w_presentation_A1_11','good','/ɡʊd/','adjective','좋은','Of high quality or a satisfactory standard.','This is a {good} example.','이것은 좋은 예입니다.','good','A1','presentation',1,'thumbs up good quality approval presentation'),
('w_presentation_A1_12','today','/təˈdeɪ/','adverb','오늘','On this present day.','{Today}, we will learn about communication.','오늘은 의사소통에 대해 배울 것입니다.','Today','A1','presentation',1,'calendar today date morning office'),
('w_presentation_A1_13','here','/hɪər/','adverb','여기','In or at this place.','{Here} is a chart to help explain.','여기 설명을 도와줄 차트가 있습니다.','Here','A1','presentation',1,'pointing chart board whiteboard here'),
('w_presentation_A1_14','look','/lʊk/','verb','보다','To direct your gaze or attention at something.','Please {look} at the screen.','화면을 봐주세요.','look','A1','presentation',1,'audience looking watching screen presentation'),
('w_presentation_A1_15','see','/siː/','verb','보다, 이해하다','To notice or become aware of something.','As you can {see}, the numbers are growing.','보시다시피 숫자가 늘고 있습니다.','see','A1','presentation',1,'graph chart data growing upward trend'),
('w_presentation_A1_16','know','/noʊ/','verb','알다','To have information or facts in your mind.','You may already {know} this fact.','이 사실을 이미 알고 계실 수도 있어요.','know','A1','presentation',1,'lightbulb knowledge understanding idea concept'),
('w_presentation_A1_17','help','/help/','verb','돕다','To make something easier or provide assistance.','This chart will {help} you understand.','이 차트가 이해하는 데 도움이 될 것입니다.','help','A1','presentation',1,'helping hand support chart data explanation'),
('w_presentation_A1_18','think','/θɪŋk/','verb','생각하다','To have an opinion or idea about something.','I {think} this is a key finding.','이것이 핵심 발견이라고 생각합니다.','think','A1','presentation',1,'thinking person idea consideration analysis'),
('w_presentation_A1_19','mean','/miːn/','verb','의미하다','To have as a meaning or to intend to say something.','What does this number {mean}?','이 숫자는 무엇을 의미하나요?','mean','A1','presentation',1,'question mark data number meaning concept'),
('w_presentation_A1_20','ready','/ˈredi/','adjective','준비된','Fully prepared for something.','I am {ready} to begin.','시작할 준비가 되었습니다.','ready','A1','presentation',1,'prepared ready speaker podium confident'),
('w_presentation_A1_21','number','/ˈnʌmbər/','noun','숫자','A value used to count or measure something.','This {number} shows our progress.','이 숫자는 우리의 진행 상황을 보여줍니다.','number','A1','presentation',1,'numbers data statistics chart bar graph'),
('w_presentation_A1_22','question','/ˈkwestʃən/','noun','질문','A sentence or phrase used to find out information.','Are there any {question}s at this point?','이 시점에 질문이 있으신가요?','question','A1','presentation',1,'audience raising hand question answer discussion'),
('w_presentation_A1_23','big','/bɪɡ/','adjective','큰','Large in size, amount, or extent.','This is a {big} change for our team.','이것은 우리 팀에 큰 변화입니다.','big','A1','presentation',1,'large important big change business growth'),
('w_presentation_A1_24','part','/pɑːrt/','noun','부분','A section or portion of something.','The second {part} will cover solutions.','두 번째 부분에서는 해결책을 다룰 것입니다.','part','A1','presentation',1,'section chapter part presentation outline'),
('w_presentation_A1_25','plan','/plæn/','noun','계획','A detailed proposal for doing or achieving something.','Our {plan} has three main steps.','우리 계획에는 세 가지 주요 단계가 있습니다.','plan','A1','presentation',1,'planning roadmap steps strategy whiteboard'),
('w_presentation_A1_26','idea','/aɪˈdiːə/','noun','아이디어','A thought or suggestion about what to do.','My main {idea} is to improve communication.','제 주요 아이디어는 의사소통을 개선하는 것입니다.','idea','A1','presentation',1,'lightbulb idea brainstorm concept creative'),
('w_presentation_A1_27','step','/step/','noun','단계','One of a series of things to do in order.','The first {step} is to identify the problem.','첫 번째 단계는 문제를 파악하는 것입니다.','step','A1','presentation',1,'steps staircase process plan roadmap'),
('w_presentation_A1_28','word','/wɜːrd/','noun','단어, 말','A unit of language or something said.','I would like to say a few {word}s.','몇 말씀 드리고 싶습니다.','word','A1','presentation',1,'words speaking text speech bubble communication'),
('w_presentation_A1_29','time','/taɪm/','noun','시간','The measured or measurable period during which an action occurs.','We have ten minutes of {time} left.','남은 시간이 10분입니다.','time','A1','presentation',1,'clock timer countdown presentation time'),
('w_presentation_A1_30','name','/neɪm/','noun','이름','The word by which someone or something is known.','My {name} is Ji-yeon and I am here to present.','제 이름은 지연이고 발표하러 왔습니다.','name','A1','presentation',1,'name tag introduction speaker badge'),
('w_presentation_A1_31','right','/raɪt/','adverb','맞아요, 좋아요','Used to confirm or agree with something.','{Right}, let us move on to the data.','좋아요, 데이터로 넘어가겠습니다.','Right','A1','presentation',1,'agreement nod confirmation presenter audience'),
('w_presentation_A1_32','give','/ɡɪv/','verb','드리다, 주다','To provide or offer something to someone.','I will {give} you a brief overview.','간략한 개요를 말씀드리겠습니다.','give','A1','presentation',1,'giving overview presenting briefing speaker'),
('w_presentation_A1_33','cover','/ˈkʌvər/','verb','다루다','To deal with a subject or include it in a talk.','Today I will {cover} three main topics.','오늘 세 가지 주요 주제를 다루겠습니다.','cover','A1','presentation',1,'outline agenda topics cover presentation plan'),
('w_presentation_A1_34','picture','/ˈpɪktʃər/','noun','그림, 사진','A visual representation or image.','This {picture} explains the concept well.','이 그림이 개념을 잘 설명해 줍니다.','picture','A1','presentation',1,'image infographic visual concept diagram'),
('w_presentation_A1_35','about','/əˈbaʊt/','preposition','~에 대하여','On the subject of something.','Today I will talk {about} teamwork.','오늘은 팀워크에 대해 이야기하겠습니다.','about','A1','presentation',1,'topic subject presentation teamwork discussion');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_presentation_A2_01','introduce','/ˌɪntrəˈdjuːs/','verb','소개하다','To present someone or something to others for the first time.','Let me {introduce} our guest speaker.','초청 강연자를 소개해 드리겠습니다.','introduce','A2','presentation',1,'introduction handshake speaker stage welcome'),
('w_presentation_A2_02','outline','/ˈaʊtlaɪn/','noun','개요, 아웃라인','A general description giving the main points of something.','Here is the {outline} of my talk.','제 발표의 개요입니다.','outline','A2','presentation',1,'outline plan agenda list presentation structure'),
('w_presentation_A2_03','summary','/ˈsʌməri/','noun','요약','A brief statement of the main points of something.','Let me give you a quick {summary}.','간단히 요약해 드리겠습니다.','summary','A2','presentation',1,'summary key points review recap presentation'),
('w_presentation_A2_04','topic','/ˈtɒpɪk/','noun','주제','A subject that is discussed, written about, or studied.','The {topic} of today''s presentation is productivity.','오늘 발표의 주제는 생산성입니다.','topic','A2','presentation',1,'topic subject theme presentation title board'),
('w_presentation_A2_05','explain','/ɪkˈspleɪn/','verb','설명하다','To make something clear by describing it in more detail.','I will {explain} how this process works.','이 과정이 어떻게 작동하는지 설명해 드리겠습니다.','explain','A2','presentation',1,'explaining whiteboard diagram process flow'),
('w_presentation_A2_06','question','/ˈkwestʃən/','noun','질문 (복수 활용)','A sentence asking for information or inviting discussion.','Please hold your {question}s until the end.','질문은 마지막까지 기다려 주세요.','question','A2','presentation',1,'Q&A session audience raising hand questions'),
('w_presentation_A2_07','answer','/ˈænsər/','verb','대답하다','To say something in response to a question.','I am happy to {answer} your questions.','질문에 기꺼이 답변해 드리겠습니다.','answer','A2','presentation',1,'answering question speaker Q&A microphone'),
('w_presentation_A2_08','audience','/ˈɔːdiəns/','noun','청중','The group of people watching or listening to a presentation.','Thank you, {audience}, for your attention.','청중 여러분, 경청해 주셔서 감사합니다.','audience','A2','presentation',1,'audience watching listening presentation hall'),
('w_presentation_A2_09','present','/prɪˈzent/','verb','발표하다','To show or demonstrate something formally to an audience.','I will {present} our quarterly results.','분기별 결과를 발표하겠습니다.','present','A2','presentation',1,'presenter stage podium quarterly results business'),
('w_presentation_A2_10','conclusion','/kənˈkluːʒən/','noun','결론','The end or final part of a speech or piece of writing.','In {conclusion}, practice makes perfect.','결론적으로, 연습이 완성을 만듭니다.','conclusion','A2','presentation',1,'conclusion ending final slide summary wrap up'),
('w_presentation_A2_11','section','/ˈsekʃən/','noun','섹션, 부분','A distinct part or subdivision of something.','The next {section} deals with marketing.','다음 섹션은 마케팅을 다룹니다.','section','A2','presentation',2,'section chapter division presentation structure'),
('w_presentation_A2_12','main','/meɪn/','adjective','주요한','Most important or largest.','The {main} goal of this project is growth.','이 프로젝트의 주요 목표는 성장입니다.','main','A2','presentation',1,'main goal objective key priority presentation'),
('w_presentation_A2_13','example','/ɪɡˈzɑːmpəl/','noun','예시','Something used to illustrate or explain a point.','Let me give you an {example}.','예를 하나 들어드리겠습니다.','example','A2','presentation',1,'example case study illustration learning'),
('w_presentation_A2_14','chart','/tʃɑːrt/','noun','차트','A sheet with information presented in the form of a diagram.','This {chart} shows our growth over time.','이 차트는 시간에 따른 성장을 보여줍니다.','chart','A2','presentation',1,'bar chart graph data visualization business'),
('w_presentation_A2_15','graph','/ɡræf/','noun','그래프','A diagram showing data and relationships between values.','As you can see on this {graph}, sales increased.','이 그래프에서 볼 수 있듯이 매출이 증가했습니다.','graph','A2','presentation',2,'line graph data trend increase decrease'),
('w_presentation_A2_16','figure','/ˈfɪɡjər/','noun','수치, 그림','A number representing an amount, or an illustration.','The {figure} on the left shows last year''s data.','왼쪽의 수치는 작년 데이터를 보여줍니다.','figure','A2','presentation',2,'data figure numbers statistics chart'),
('w_presentation_A2_17','goal','/ɡoʊl/','noun','목표','An aim or desired result.','Our {goal} is to double sales this year.','올해 목표는 매출을 두 배로 늘리는 것입니다.','goal','A2','presentation',1,'goal target achievement business objective'),
('w_presentation_A2_18','result','/rɪˈzʌlt/','noun','결과','The outcome of an action or situation.','The {result} of our survey is very clear.','설문 조사의 결과가 매우 명확합니다.','result','A2','presentation',1,'result outcome data findings survey analysis'),
('w_presentation_A2_19','reason','/ˈriːzən/','noun','이유','A cause or explanation for something.','The main {reason} for this change is efficiency.','이 변화의 주요 이유는 효율성입니다.','reason','A2','presentation',1,'reason explanation cause analysis thinking'),
('w_presentation_A2_20','problem','/ˈprɒbləm/','noun','문제','A matter or situation that is difficult or unwanted.','The {problem} we face is a lack of resources.','우리가 직면한 문제는 자원 부족입니다.','problem','A2','presentation',1,'problem challenge issue solution business'),
('w_presentation_A2_21','solution','/səˈluːʃən/','noun','해결책','A means of solving a problem or dealing with a situation.','Here is our proposed {solution}.','여기 우리가 제안하는 해결책이 있습니다.','solution','A2','presentation',1,'solution answer problem solving strategy business'),
('w_presentation_A2_22','project','/ˈprɒdʒekt/','noun','프로젝트','A plan or piece of work, usually to achieve a specific aim.','Our {project} has been running for six months.','우리 프로젝트는 6개월째 진행 중입니다.','project','A2','presentation',2,'project team collaboration planning business'),
('w_presentation_A2_23','data','/ˈdeɪtə/','noun','데이터','Facts and statistics collected together for reference.','The {data} supports our argument.','데이터가 우리의 주장을 뒷받침합니다.','data','A2','presentation',1,'data statistics numbers analysis research'),
('w_presentation_A2_24','report','/rɪˈpɔːrt/','noun','보고서','A spoken or written account of something.','According to our {report}, sales grew by 20%.','보고서에 따르면 매출이 20% 성장했습니다.','report','A2','presentation',2,'report document business analysis findings'),
('w_presentation_A2_25','change','/tʃeɪndʒ/','noun','변화','The act or process of becoming different.','This {change} will benefit the whole team.','이 변화는 팀 전체에 도움이 될 것입니다.','change','A2','presentation',2,'change transformation arrow direction business'),
('w_presentation_A2_26','increase','/ˈɪŋkriːs/','noun','증가','A rise in the amount, number, or degree of something.','There was a significant {increase} in users.','사용자 수가 크게 증가했습니다.','increase','A2','presentation',1,'increase growth arrow up chart bar graph'),
('w_presentation_A2_27','decrease','/ˈdiːkriːs/','noun','감소','A reduction in the amount, number, or degree of something.','The {decrease} in costs surprised everyone.','비용 감소가 모두를 놀라게 했습니다.','decrease','A2','presentation',2,'decrease drop arrow down chart reduction'),
('w_presentation_A2_28','total','/ˈtoʊtl/','noun','합계','The whole number or amount of something.','The {total} budget is two million dollars.','총 예산은 200만 달러입니다.','total','A2','presentation',2,'total sum budget finance numbers spreadsheet'),
('w_presentation_A2_29','compare','/kəmˈpeər/','verb','비교하다','To examine the similarities or differences between things.','Let us {compare} these two approaches.','이 두 가지 접근법을 비교해 보겠습니다.','compare','A2','presentation',2,'comparison side by side chart analysis'),
('w_presentation_A2_30','agree','/əˈɡriː/','verb','동의하다','To have the same opinion or feeling as someone.','I hope you all {agree} with this approach.','여러분 모두 이 접근법에 동의하시길 바랍니다.','agree','A2','presentation',2,'agreement consensus handshake team discussion'),
('w_presentation_A2_31','clear','/klɪər/','adjective','명확한','Easy to understand, hear, read, or see.','I hope that was {clear} for everyone.','모든 분들께 명확하게 전달되었으면 합니다.','clear','A2','presentation',1,'clarity understanding clear message communication'),
('w_presentation_A2_32','brief','/briːf/','adjective','간략한','Short in duration or using few words.','I will give a {brief} overview before we begin.','시작하기 전에 간략한 개요를 드리겠습니다.','brief','A2','presentation',2,'brief short summary overview concise'),
('w_presentation_A2_33','background','/ˈbækɡraʊnd/','noun','배경','Information about the context of something.','Let me give you some {background} information.','배경 정보를 조금 말씀드리겠습니다.','background','A2','presentation',2,'background context history information overview'),
('w_presentation_A2_34','focus','/ˈfoʊkəs/','verb','집중하다','To pay particular attention to a specific subject.','Today we will {focus} on customer retention.','오늘은 고객 유지에 집중하겠습니다.','focus','A2','presentation',1,'focus spotlight lens target goal presentation'),
('w_presentation_A2_35','share','/ʃeər/','verb','공유하다','To tell others about something or give them access to it.','I would like to {share} some key insights.','주요 인사이트를 공유하고 싶습니다.','share','A2','presentation',1,'sharing information insights knowledge team');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_presentation_B1_01','highlight','/ˈhaɪlaɪt/','verb','강조하다','To draw special attention to something important.','I want to {highlight} three key points.','세 가지 핵심 포인트를 강조하고 싶습니다.','highlight','B1','presentation',1,'highlight marker key point emphasis presentation'),
('w_presentation_B1_02','transition','/trænˈzɪʃən/','noun','전환','A change or move from one state or topic to another.','Let''s make a {transition} to the next section.','다음 섹션으로 넘어가겠습니다.','transition','B1','presentation',1,'transition arrow move change flow next section'),
('w_presentation_B1_03','illustrate','/ˈɪləstreɪt/','verb','설명하다, 예시를 들다','To make something clearer by using examples or visuals.','This graph will {illustrate} my point.','이 그래프가 제 요점을 설명해 줄 것입니다.','illustrate','B1','presentation',1,'illustration diagram visual example graph'),
('w_presentation_B1_04','emphasize','/ˈemfəsaɪz/','verb','강조하다','To give special importance to something in speaking or writing.','I must {emphasize} the urgency of this issue.','이 문제의 긴급성을 강조해야 합니다.','emphasize','B1','presentation',1,'emphasis bold highlight urgent important'),
('w_presentation_B1_05','elaborate','/ɪˈlæbəreɪt/','verb','자세히 설명하다','To explain something in more detail or add more information.','Could you {elaborate} on that point?','그 요점에 대해 더 자세히 설명해 주시겠어요?','elaborate','B1','presentation',2,'detail explanation deeper dive analysis'),
('w_presentation_B1_06','overview','/ˈoʊvərˌvjuː/','noun','개요, 전체 그림','A general summary or description of a subject.','Let me begin with a quick {overview}.','간단한 개요로 시작하겠습니다.','overview','B1','presentation',1,'overview summary big picture presentation intro'),
('w_presentation_B1_07','objective','/əbˈdʒektɪv/','noun','목적, 목표','A goal or aim intended to be achieved.','Our main {objective} is to reduce costs.','우리의 주요 목적은 비용 절감입니다.','objective','B1','presentation',1,'objective goal target SMART aim business plan'),
('w_presentation_B1_08','finding','/ˈfaɪndɪŋ/','noun','발견, 조사 결과','A fact or piece of information discovered through research.','Our key {finding} is that engagement doubled.','핵심 발견은 참여도가 두 배로 증가했다는 것입니다.','finding','B1','presentation',1,'research finding discovery data insight analysis'),
('w_presentation_B1_09','result','/rɪˈzʌlt/','noun','결과 (연구·실험)','The outcome of an experiment, study, or action.','The {result}s exceeded our expectations.','결과가 우리의 기대를 뛰어넘었습니다.','result','B1','presentation',1,'results success exceeding expectations graph'),
('w_presentation_B1_10','recommend','/ˌrekəˈmend/','verb','권장하다','To suggest that someone do something or use something.','I {recommend} adopting this new strategy.','이 새로운 전략을 도입할 것을 권장합니다.','recommend','B1','presentation',1,'recommendation strategy advice suggestion business'),
('w_presentation_B1_11','approach','/əˈproʊtʃ/','noun','접근법','A way of dealing with a situation or problem.','Our {approach} differs from traditional methods.','우리의 접근법은 기존 방법과 다릅니다.','approach','B1','presentation',2,'approach method strategy alternative comparison'),
('w_presentation_B1_12','demonstrate','/ˈdemənstreɪt/','verb','시연하다, 증명하다','To show clearly by giving proof or evidence.','Let me {demonstrate} how this tool works.','이 도구가 어떻게 작동하는지 시연해 드리겠습니다.','demonstrate','B1','presentation',2,'demo demonstration live example proof evidence'),
('w_presentation_B1_13','structure','/ˈstrʌktʃər/','noun','구조','The arrangement of parts or the way something is organized.','The {structure} of my talk has three parts.','제 발표의 구조는 세 부분으로 이루어져 있습니다.','structure','B1','presentation',1,'structure outline framework organized presentation'),
('w_presentation_B1_14','evidence','/ˈevɪdəns/','noun','증거','Facts or information available to prove something.','The {evidence} clearly supports our claim.','증거가 우리의 주장을 명확히 뒷받침합니다.','evidence','B1','presentation',1,'evidence proof data research support argument'),
('w_presentation_B1_15','implication','/ˌɪmplɪˈkeɪʃən/','noun','시사점','A conclusion that can be drawn from something.','The {implication}s of this are significant.','이것의 시사점은 매우 중요합니다.','implication','B1','presentation',2,'implication impact consequence significance meaning'),
('w_presentation_B1_16','challenge','/ˈtʃælɪndʒ/','noun','과제, 도전','A task or situation that tests someone''s abilities.','One {challenge} we faced was data collection.','우리가 직면한 과제 중 하나는 데이터 수집이었습니다.','challenge','B1','presentation',2,'challenge obstacle problem solving team'),
('w_presentation_B1_17','strategy','/ˈstrætɪdʒi/','noun','전략','A plan of action designed to achieve an overall aim.','Our {strategy} focuses on digital channels.','우리의 전략은 디지털 채널에 초점을 맞춥니다.','strategy','B1','presentation',1,'strategy plan roadmap chess business direction'),
('w_presentation_B1_18','impact','/ˈɪmpækt/','noun','영향','The strong effect or influence of one thing on another.','The {impact} of this policy was immediate.','이 정책의 영향은 즉각적이었습니다.','impact','B1','presentation',1,'impact effect influence change result business'),
('w_presentation_B1_19','trend','/trend/','noun','추세','A general direction in which something is developing.','The {trend} shows consistent improvement.','추세는 지속적인 개선을 보여줍니다.','trend','B1','presentation',1,'trend line graph upward growth market data'),
('w_presentation_B1_20','significant','/sɪɡˈnɪfɪkənt/','adjective','중요한, 상당한','Large enough to be noticed or have an effect.','This is a {significant} increase in revenue.','이것은 매출의 상당한 증가입니다.','significant','B1','presentation',1,'significant important notable achievement business'),
('w_presentation_B1_21','assumption','/əˈsʌmpʃən/','noun','가정, 전제','Something taken for granted as a starting point.','Our key {assumption} is steady market growth.','우리의 핵심 가정은 안정적인 시장 성장입니다.','assumption','B1','presentation',2,'assumption premise foundation hypothesis thinking'),
('w_presentation_B1_22','scenario','/sɪˈnɑːrioʊ/','noun','시나리오','A written outline of a possible course of events.','In the best-case {scenario}, we exceed targets.','최선의 시나리오에서는 목표를 초과합니다.','scenario','B1','presentation',2,'scenario planning options best worst case'),
('w_presentation_B1_23','proposal','/prəˈpoʊzəl/','noun','제안서','A formal plan or suggestion for others to consider.','Our {proposal} outlines three options.','제안서는 세 가지 옵션을 제시합니다.','proposal','B1','presentation',1,'proposal document business plan options review'),
('w_presentation_B1_24','benefit','/ˈbenɪfɪt/','noun','이점','An advantage or gain from something.','The {benefit}s of this approach are clear.','이 접근법의 이점은 명확합니다.','benefit','B1','presentation',1,'benefit advantage positive gain improvement'),
('w_presentation_B1_25','concern','/kənˈsɜːrn/','noun','우려, 걱정','A feeling of worry about something important.','A valid {concern} is the timeline.','타당한 우려 사항은 일정입니다.','concern','B1','presentation',2,'concern worry risk issue challenge flag'),
('w_presentation_B1_26','process','/ˈprɒses/','noun','과정, 절차','A series of steps taken to achieve a particular goal.','Let me walk you through the {process}.','과정을 순서대로 안내해 드리겠습니다.','process','B1','presentation',1,'process steps flowchart workflow procedure'),
('w_presentation_B1_27','outcome','/ˈaʊtˌkʌm/','noun','결과, 성과','The way a situation ends or the result achieved.','The desired {outcome} is a 15% cost reduction.','목표 성과는 15% 비용 절감입니다.','outcome','B1','presentation',1,'outcome result success goal achieved measurement'),
('w_presentation_B1_28','effective','/ɪˈfektɪv/','adjective','효과적인','Producing the intended result successfully.','This method proved to be highly {effective}.','이 방법은 매우 효과적인 것으로 입증되었습니다.','effective','B1','presentation',2,'effective solution result success proven method'),
('w_presentation_B1_29','relevant','/ˈreləvənt/','adjective','관련성 있는','Closely connected with or appropriate to the matter.','The most {relevant} data is shown here.','가장 관련성 있는 데이터가 여기에 표시되어 있습니다.','relevant','B1','presentation',2,'relevant related connected appropriate data'),
('w_presentation_B1_30','expand','/ɪkˈspænd/','verb','확장하다, 자세히 설명하다','To make something larger or to explain in more detail.','Let me {expand} on this point briefly.','이 부분을 잠깐 자세히 설명하겠습니다.','expand','B1','presentation',2,'expand enlarge detail deeper explanation'),
('w_presentation_B1_31','current','/ˈkɜːrənt/','adjective','현재의','Existing or happening now.','The {current} situation calls for action.','현재 상황은 행동을 요구합니다.','current','B1','presentation',2,'current now present situation analysis today'),
('w_presentation_B1_32','methodology','/ˌmeθəˈdɒlədʒi/','noun','방법론','A system of methods used in a particular area of study.','Our {methodology} is based on user interviews.','우리 방법론은 사용자 인터뷰를 기반으로 합니다.','methodology','B1','presentation',2,'methodology research method process approach'),
('w_presentation_B1_33','timeline','/ˈtaɪmˌlaɪn/','noun','일정표, 타임라인','A display of events or actions in chronological order.','Here is our project {timeline}.','여기 프로젝트 타임라인이 있습니다.','timeline','B1','presentation',1,'timeline project schedule Gantt chart milestones'),
('w_presentation_B1_34','insight','/ˈɪnsaɪt/','noun','인사이트, 통찰력','A deep and accurate understanding of something.','This data gives us a key {insight}.','이 데이터는 핵심 인사이트를 제공합니다.','insight','B1','presentation',1,'insight discovery understanding data analysis'),
('w_presentation_B1_35','initiative','/ɪˈnɪʃɪətɪv/','noun','이니셔티브, 계획','A new plan or action intended to solve a problem.','This {initiative} will launch in Q3.','이 이니셔티브는 3분기에 시작됩니다.','initiative','B1','presentation',2,'initiative launch project plan start program');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_presentation_B2_01','quantify','/ˈkwɒntɪfaɪ/','verb','수치화하다','To express or measure something as a quantity.','We need to {quantify} the potential gains.','잠재적 이익을 수치화할 필요가 있습니다.','quantify','B2','presentation',1,'quantify numbers metrics measurement data chart'),
('w_presentation_B2_02','juxtapose','/ˌdʒʌkstəˈpoʊz/','verb','병치하다, 나란히 놓다','To place two things close together for comparison or contrast.','Let me {juxtapose} the two models.','두 모델을 나란히 비교해 보겠습니다.','juxtapose','B2','presentation',2,'comparison side by side contrast two options'),
('w_presentation_B2_03','contextualize','/kənˈtekstʃuəlaɪz/','verb','맥락화하다','To place something in its context to make it understandable.','It is important to {contextualize} these results.','이 결과를 맥락화하는 것이 중요합니다.','contextualize','B2','presentation',2,'context background framework understanding analysis'),
('w_presentation_B2_04','articulate','/ɑːrˈtɪkjuleɪt/','verb','명확히 표현하다','To express thoughts or feelings clearly and effectively in words.','She can {articulate} complex ideas simply.','그녀는 복잡한 아이디어를 간단하게 표현할 수 있습니다.','articulate','B2','presentation',1,'clear communication speech articulate express'),
('w_presentation_B2_05','facilitate','/fəˈsɪlɪteɪt/','verb','촉진하다, 진행을 돕다','To make an action or process easier or smoother.','This tool will {facilitate} collaboration.','이 도구는 협업을 촉진할 것입니다.','facilitate','B2','presentation',2,'facilitate enable support help process smooth'),
('w_presentation_B2_06','compelling','/kəmˈpelɪŋ/','adjective','설득력 있는','Evoking interest, attention, or admiration in a powerful way.','The data presents a {compelling} argument.','데이터가 설득력 있는 주장을 제시합니다.','compelling','B2','presentation',1,'compelling argument persuasive strong powerful case'),
('w_presentation_B2_07','persuasive','/pərˈsweɪsɪv/','adjective','설득력 있는','Good at convincing people to believe or do something.','Her {persuasive} delivery won over the board.','그녀의 설득력 있는 발표가 이사회를 설득했습니다.','persuasive','B2','presentation',1,'persuasive speech convince audience board winning'),
('w_presentation_B2_08','coherent','/koʊˈhɪərənt/','adjective','일관된, 조리 있는','Logical and well-organized, forming a unified whole.','Our argument is {coherent} and well-supported.','우리의 주장은 일관되고 잘 뒷받침됩니다.','coherent','B2','presentation',1,'coherent logical organized structured argument'),
('w_presentation_B2_09','credibility','/ˌkredɪˈbɪlɪti/','noun','신뢰성','The quality of being trusted and believed in.','Citing sources builds your {credibility}.','출처를 인용하면 신뢰성이 높아집니다.','credibility','B2','presentation',1,'credibility trust source citation research reliable'),
('w_presentation_B2_10','narrative','/ˈnærətɪv/','noun','내러티브, 서사','A spoken or written account that connects ideas into a story.','The {narrative} of this data is one of growth.','이 데이터의 내러티브는 성장에 관한 것입니다.','narrative','B2','presentation',1,'narrative story arc data storytelling presentation'),
('w_presentation_B2_11','refute','/rɪˈfjuːt/','verb','반박하다','To prove that something is wrong or incorrect.','Our data {refute}s the competitor''s claims.','우리 데이터가 경쟁사의 주장을 반박합니다.','refute','B2','presentation',2,'refute counter argument rebuttal evidence proof'),
('w_presentation_B2_12','substantiate','/səbˈstænʃieɪt/','verb','뒷받침하다, 증명하다','To provide evidence to support or prove a claim.','We can {substantiate} every figure presented.','제시된 모든 수치를 뒷받침할 수 있습니다.','substantiate','B2','presentation',2,'evidence proof support data back up claim'),
('w_presentation_B2_13','nuance','/ˈnjuːɑːns/','noun','뉘앙스','A subtle difference in meaning, expression, or sound.','There is an important {nuance} here worth noting.','여기서 주목할 만한 중요한 뉘앙스가 있습니다.','nuance','B2','presentation',2,'nuance subtle difference detail precision meaning'),
('w_presentation_B2_14','benchmark','/ˈbentʃˌmɑːrk/','noun','기준점, 벤치마크','A standard against which things may be compared.','Our results exceeded the industry {benchmark}.','우리 결과가 업계 기준을 초과했습니다.','benchmark','B2','presentation',1,'benchmark standard comparison industry performance'),
('w_presentation_B2_15','leverage','/ˈlevərɪdʒ/','verb','활용하다','To use something to maximum advantage.','We can {leverage} our brand recognition.','우리 브랜드 인지도를 활용할 수 있습니다.','leverage','B2','presentation',2,'leverage advantage utilize maximize asset strategy'),
('w_presentation_B2_16','mitigate','/ˈmɪtɪɡeɪt/','verb','완화하다','To make something less severe or serious.','Steps were taken to {mitigate} the risks.','리스크를 완화하기 위한 조치가 취해졌습니다.','mitigate','B2','presentation',2,'mitigate reduce risk management solution strategy'),
('w_presentation_B2_17','stakeholder','/ˈsteɪkˌhoʊldər/','noun','이해관계자','A person with an interest or concern in a business or project.','All {stakeholder}s have been consulted.','모든 이해관계자와 협의했습니다.','stakeholder','B2','presentation',1,'stakeholder team executive management consulting'),
('w_presentation_B2_18','scalable','/ˈskeɪləbəl/','adjective','확장 가능한','Able to be changed in size or scale to meet changing needs.','The solution we propose is {scalable}.','우리가 제안하는 솔루션은 확장 가능합니다.','scalable','B2','presentation',2,'scalable growth expand flexible technology solution'),
('w_presentation_B2_19','prioritize','/praɪˈɔːrɪtaɪz/','verb','우선순위를 정하다','To treat something as more important than other things.','We need to {prioritize} the highest-impact items.','영향력이 가장 큰 항목을 우선시해야 합니다.','prioritize','B2','presentation',1,'prioritize ranking order importance matrix'),
('w_presentation_B2_20','optimize','/ˈɒptɪmaɪz/','verb','최적화하다','To make the best or most effective use of something.','We plan to {optimize} the workflow.','워크플로우를 최적화할 계획입니다.','optimize','B2','presentation',1,'optimize improve efficiency best performance'),
('w_presentation_B2_21','trajectory','/trəˈdʒektəri/','noun','궤적, 방향','The path followed by a moving object or a course of action.','The {trajectory} of growth has been steep.','성장 궤적이 가파르게 이어져 왔습니다.','trajectory','B2','presentation',2,'trajectory path direction growth curve upward'),
('w_presentation_B2_22','catalyst','/ˈkætəlɪst/','noun','촉매제','A person or thing that causes a change or reaction.','This event was the {catalyst} for our pivot.','이 사건이 우리 방향 전환의 촉매제였습니다.','catalyst','B2','presentation',2,'catalyst change trigger event spark transformation'),
('w_presentation_B2_23','viable','/ˈvaɪəbəl/','adjective','실행 가능한','Capable of working successfully or feasible.','Option B is the most {viable} solution.','옵션 B가 가장 실행 가능한 솔루션입니다.','viable','B2','presentation',1,'viable feasible option solution practical choice'),
('w_presentation_B2_24','granular','/ˈɡrænjʊlər/','adjective','세부적인, 세밀한','Having a fine or detailed level of analysis or description.','The {granular} data reveals a hidden trend.','세밀한 데이터가 숨겨진 추세를 드러냅니다.','granular','B2','presentation',2,'granular detail level data micro analysis deep'),
('w_presentation_B2_25','synthesize','/ˈsɪnθəsaɪz/','verb','종합하다','To combine different elements into a coherent whole.','We {synthesize} data from multiple sources.','여러 출처의 데이터를 종합합니다.','synthesize','B2','presentation',1,'synthesize combine integrate data sources analysis'),
('w_presentation_B2_26','transparency','/trænsˈpærənsi/','noun','투명성','Being open and not hiding information.','We value {transparency} in our reporting.','보고에서 투명성을 중요하게 생각합니다.','transparency','B2','presentation',2,'transparency open honest reporting clear communication'),
('w_presentation_B2_27','validate','/ˈvælɪdeɪt/','verb','검증하다','To confirm that something is correct or justified.','We {validate}d our model with real data.','실제 데이터로 모델을 검증했습니다.','validate','B2','presentation',2,'validate verify confirm test data proof'),
('w_presentation_B2_28','robust','/roʊˈbʌst/','adjective','견고한, 탄탄한','Strong and healthy or vigorous;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_presentation_C1_01','rhetoric','/ˈretərɪk/','noun','수사학, 수사법','The art of effective or persuasive speaking or writing.','Mastering {rhetoric} will transform your presentations.','수사법을 익히면 발표가 달라집니다.','rhetoric','C1','presentation',1,'rhetoric persuasion speech oratory debate stage'),
('w_presentation_C1_02','discourse','/ˈdɪskɔːrs/','noun','담화, 담론','Written or spoken communication or debate.','Academic {discourse} requires precise language.','학문적 담론은 정확한 언어를 요구합니다.','discourse','C1','presentation',2,'discourse discussion academic language debate forum'),
('w_presentation_C1_03','deconstruct','/ˌdiːkənˈstrʌkt/','verb','해체 분석하다','To analyze something by breaking it down into its parts.','Let me {deconstruct} the argument step by step.','주장을 단계별로 분해해 분석해 보겠습니다.','deconstruct','C1','presentation',2,'deconstruct analyze break down components parts'),
('w_presentation_C1_04','paradigm','/ˈpærədaɪm/','noun','패러다임','A typical example or model, or a framework of assumptions.','This technology represents a new {paradigm}.','이 기술은 새로운 패러다임을 나타냅니다.','paradigm','C1','presentation',1,'paradigm shift model framework new era change'),
('w_presentation_C1_05','framework','/ˈfreɪmwɜːrk/','noun','프레임워크, 틀','A basic structure underlying a system or concept.','Our analysis uses a four-part {framework}.','우리 분석은 네 부분으로 이루어진 프레임워크를 사용합니다.','framework','C1','presentation',1,'framework structure model analysis four quadrant'),
('w_presentation_C1_06','proposition','/ˌprɒpəˈzɪʃən/','noun','명제, 핵심 주장','A statement or assertion that expresses a judgment or opinion.','Our core value {proposition} is clear.','우리의 핵심 가치 명제는 명확합니다.','proposition','C1','presentation',1,'proposition value statement argument claim thesis'),
('w_presentation_C1_07','empirical','/ɪmˈpɪrɪkəl/','adjective','경험적인, 실증적인','Based on observation or experience rather than theory.','Our conclusions are grounded in {empirical} data.','우리의 결론은 실증적 데이터에 근거합니다.','empirical','C1','presentation',1,'empirical data research evidence observation fact'),
('w_presentation_C1_08','analytical','/ˌænəˈlɪtɪkəl/','adjective','분석적인','Using analysis or logic to examine something carefully.','An {analytical} approach reveals underlying patterns.','분석적 접근법이 내재된 패턴을 드러냅니다.','analytical','C1','presentation',1,'analytical thinking data logic systematic approach'),
('w_presentation_C1_09','synthesize','/ˈsɪnθəsaɪz/','verb','종합하다 (학제적)','To produce something by combining elements from multiple sources.','We {synthesize} research from multiple disciplines.','여러 학문 분야의 연구를 종합합니다.','synthesize','C1','presentation',1,'synthesize research combine disciplines integrate whole'),
('w_presentation_C1_10','infer','/ɪnˈfɜːr/','verb','추론하다','To reach a conclusion based on evidence and reasoning.','We can {infer} causation from these results.','이 결과에서 인과관계를 추론할 수 있습니다.','infer','C1','presentation',2,'infer conclude reason evidence logic analysis'),
('w_presentation_C1_11','correlate','/ˈkɒrəleɪt/','verb','상관관계가 있다','To have a mutual relationship or connection.','User engagement strongly {correlate}s with retention.','사용자 참여는 유지율과 강하게 상관관계가 있습니다.','correlate','C1','presentation',2,'correlation relationship data variables statistical'),
('w_presentation_C1_12','critique','/krɪˈtiːk/','verb','비평하다','To analyze and judge a work or idea in a detailed way.','I will {critique} the existing approach first.','먼저 기존 접근법을 비평하겠습니다.','critique','C1','presentation',2,'critique review analysis evaluation judgment academic'),
('w_presentation_C1_13','conceptualize','/kənˈseptʃuəlaɪz/','verb','개념화하다','To form a concept or idea of something in the mind.','We {conceptualize}d the solution as a feedback loop.','솔루션을 피드백 루프로 개념화했습니다.','conceptualize','C1','presentation',2,'conceptualize idea model thinking abstraction design'),
('w_presentation_C1_14','divergent','/daɪˈvɜːrdʒənt/','adjective','발산적인, 다른','Tending to be different or developing in different directions.','The two models produced {divergent} outcomes.','두 모델이 다른 결과를 만들어냈습니다.','divergent','C1','presentation',2,'divergent different opposite split path comparison'),
('w_presentation_C1_15','convergent','/kənˈvɜːrdʒənt/','adjective','수렴적인','Tending to come together toward a common point.','All data sets show {convergent} trends.','모든 데이터 세트가 수렴하는 추세를 보입니다.','convergent','C1','presentation',2,'convergent same direction unified trend agreement'),
('w_presentation_C1_16','nuanced','/ˈnjuːɑːnst/','adjective','세밀한, 뉘앙스 있는','Having subtle distinctions or fine differences.','Her {nuanced} analysis impressed the committee.','그녀의 세밀한 분석이 위원회에 깊은 인상을 주었습니다.','nuanced','C1','presentation',1,'nuanced subtle detail precision careful analysis'),
('w_presentation_C1_17','normative','/ˈnɔːrmətɪv/','adjective','규범적인','Relating to a standard or norm, especially of behavior.','We move from descriptive to {normative} analysis.','기술적 분석에서 규범적 분석으로 이동합니다.','normative','C1','presentation',2,'normative standard prescriptive recommendation policy'),
('w_presentation_C1_18','extrapolate','/ɪkˈstræpəleɪt/','verb','외삽하여 추정하다','To extend a conclusion from known data to an unknown area.','We can {extrapolate} from current trends.','현재 추세에서 미래를 추정 연장할 수 있습니다.','extrapolate','C1','presentation',2,'extrapolate predict forecast trend extension future'),
('w_presentation_C1_19','hypothesis','/haɪˈpɒθɪsɪs/','noun','가설','A proposed explanation made on limited evidence.','Our {hypothesis} was supported by the trial data.','가설은 실험 데이터로 뒷받침되었습니다.','hypothesis','C1','presentation',1,'hypothesis test research science experiment prove'),
('w_presentation_C1_20','contingency','/kənˈtɪndʒənsi/','noun','비상 계획, 만일의 경우','A future event or circumstance that is possible but uncertain.','We have a {contingency} plan for each risk.','각 리스크에 대한 비상 계획이 있습니다.','contingency','C1','presentation',2,'contingency backup plan risk management safety'),
('w_presentation_C1_21','delineate','/dɪˈlɪnieɪt/','verb','명확히 구분하다','To describe or indicate something precisely.','I will {delineate} the scope of this study.','이 연구의 범위를 명확히 구분해 드리겠습니다.','delineate','C1','presentation',2,'delineate define scope boundary clarify outline'),
('w_presentation_C1_22','causality','/kɔːˈzæləti/','noun','인과관계','The relationship between cause and effect.','We must not confuse correlation with {causality}.','상관관계를 인과관계로 혼동해서는 안 됩니다.','causality','C1','presentation',2,'causality cause effect relationship data statistics'),
('w_presentation_C1_23','disseminate','/dɪˈsemɪneɪt/','verb','전파하다, 보급하다','To spread information widely.','We plan to {disseminate} these findings broadly.','이 결과를 널리 전파할 계획입니다.','disseminate','C1','presentation',2,'disseminate spread share publish broadcast research'),
('w_presentation_C1_24','dichotomy','/daɪˈkɒtəmi/','noun','이분법','A division or contrast between two things as opposites.','There is a false {dichotomy} between speed and quality.','속도와 품질 사이에는 잘못된 이분법이 있습니다.','dichotomy','C1','presentation',2,'dichotomy binary two sides contrast opposition'),
('w_presentation_C1_25','interrogate','/ɪnˈterəɡeɪt/','verb','면밀히 검토하다','To examine something critically and in detail.','We need to {interrogate} the underlying assumptions.','기저 가정을 면밀히 검토해야 합니다.','interrogate','C1','presentation',2,'interrogate examine question critically scrutiny'),
('w_presentation_C1_26','generalize','/ˈdʒenərəlaɪz/','verb','일반화하다','To make a general statement from specific instances.','We should be careful not to over-{generalize}.','과도하게 일반화하지 않도록 주의해야 합니다.','generalize','C1','presentation',2,'generalize broad conclusion caution limitation'),
('w_presentation_C1_27','precedent','/ˈpresɪdənt/','noun','선례','An earlier event that is taken as a guide for the future.','This sets a {precedent} for future decisions.','이것이 미래 결정의 선례를 세웁니다.','precedent','C1','presentation',2,'precedent history example past reference guide'),
('w_presentation_C1_28','quantitative','/ˈkwɒntɪtətɪv/','adjective','정량적인','Relating to the measurement of quantity or amount.','The {quantitative} findings are compelling.','정량적 발견이 설득력 있습니다.','quantitative','C1','presentation',1,'quantitative data numbers statistics measurement research'),
('w_presentation_C1_29','qualitative','/ˈkwɒlɪtətɪv/','adjective','정성적인','Relating to the quality or character of something.','The {qualitative} feedback revealed key themes.','정성적 피드백에서 핵심 주제가 드러났습니다.','qualitative','C1','presentation',1,'qualitative interview theme insight user research'),
('w_presentation_C1_30','iterative','/ˈɪtərətɪv/','adjective','반복적인, 점진적인','Characterized by repetition of a process to achieve a result.','Our design follows an {iterative} process.','우리 디자인은 반복적인 과정을 따릅니다.','iterative','C1','presentation',2,'iterative process cycle improve agile development'),
('w_presentation_C1_31','posit','/ˈpɒzɪt/','verb','가정하다, 주장하다','To put forward as a fact or basis for argument.','I would {posit} that user trust is the key variable.','사용자 신뢰가 핵심 변수라고 주장하고자 합니다.','posit','C1','presentation',2,'posit argue assert claim academic presentation'),
('w_presentation_C1_32','substantive','/ˈsʌbstəntɪv/','adjective','실질적인, 핵심적인','Having a firm basis in reality and being important or meaningful.','We need {substantive} change, not cosmetic fixes.','표면적 수정이 아닌 실질적인 변화가 필요합니다.','substantive','C1','presentation',2,'substantive real meaningful significant change impact'),
('w_presentation_C1_33','granularity','/ˌɡrænjʊˈlærɪti/','noun','세분화, 세부 수준','The level of detail or precision in data or analysis.','The {granularity} of this dataset is exceptional.','이 데이터셋의 세분화 수준은 탁월합니다.','granularity','C1','presentation',2,'granularity detail precision data level analysis'),
('w_presentation_C1_34','axiom','/ˈæksiəm/','noun','공리, 자명한 이치','A statement accepted as true as the basis for argument.','The first {axiom} of our model is user rationality.','우리 모델의 첫 번째 공리는 사용자 합리성입니다.','axiom','C1','presentation',2,'axiom truth principle foundation logic mathematics'),
('w_presentation_C1_35','reframe','/ˌriːˈfreɪm/','verb','재구성하다','To frame something in a different way to change how it is perceived.','Let us {reframe} this challenge as an opportunity.','이 도전을 기회로 재구성해 봅시다.','reframe','C1','presentation',1,'reframe perspective shift mindset opportunity challenge');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_presentation_C2_01','epistemological','/ɪˌpɪstɪməˈlɒdʒɪkəl/','adjective','인식론적인','Relating to the theory of knowledge, especially how it is acquired.','This raises {epistemological} questions about data validity.','이것은 데이터 타당성에 대한 인식론적 질문을 제기합니다.','epistemological','C2','presentation',2,'epistemology knowledge theory philosophy research validity'),
('w_presentation_C2_02','heuristic','/hjʊˈrɪstɪk/','adjective','발견적인, 경험 탐색적인','Enabling discovery through practical experience rather than a set formula.','We applied a {heuristic} approach to the analysis.','분석에 발견적 접근법을 적용했습니다.','heuristic','C2','presentation',2,'heuristic discovery method practical rule of thumb'),
('w_presentation_C2_03','ontological','/ˌɒntəˈlɒdʒɪkəl/','adjective','존재론적인','Relating to the branch of metaphysics dealing with the nature of being.','The {ontological} assumptions underpin the framework.','존재론적 가정이 프레임워크의 기반을 이룹니다.','ontological','C2','presentation',2,'ontology being existence nature philosophy framework'),
('w_presentation_C2_04','phenomenological','/fɪˌnɒmɪnəˈlɒdʒɪkəl/','adjective','현상학적인','Relating to the study of structures of experience and consciousness.','A {phenomenological} lens reveals lived experience.','현상학적 렌즈가 살아있는 경험을 드러냅니다.','phenomenological','C2','presentation',2,'phenomenological experience consciousness qualitative research'),
('w_presentation_C2_05','dialectical','/ˌdaɪəˈlektɪkəl/','adjective','변증법적인','Relating to the logical discussion of ideas through opposing arguments.','The {dialectical} tension drives innovation.','변증법적 긴장이 혁신을 이끕니다.','dialectical','C2','presentation',2,'dialectical debate tension opposing synthesis Hegel'),
('w_presentation_C2_06','praxis','/ˈpræksɪs/','noun','실천, 프락시스','The process of putting theory into practice;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_negotiation_A1_01','want','/wɒnt/','verb','원하다','To feel a desire or wish for something.','What do you {want} from this deal?','이 거래에서 무엇을 원하세요?','want','A1','negotiation',1,'negotiation business handshake agreement'),
('w_negotiation_A1_02','need','/niːd/','verb','필요하다','To require something as necessary or important.','I {need} a better price for this.','이것에 더 좋은 가격이 필요해요.','need','A1','negotiation',1,'need requirement checklist office'),
('w_negotiation_A1_03','give','/ɡɪv/','verb','주다','To hand something over to someone.','Can you {give} me a small discount?','할인을 조금 주실 수 있나요?','give','A1','negotiation',1,'giving handshake gift exchange'),
('w_negotiation_A1_04','take','/teɪk/','verb','받아들이다, 가져가다','To accept something that is offered.','I''ll {take} the offer if the price is right.','가격이 맞으면 제안을 받아들일게요.','take','A1','negotiation',1,'accept deal take offer business'),
('w_negotiation_A1_05','agree','/əˈɡriː/','verb','동의하다','To have the same opinion as someone else.','We both {agree} on the main points.','우리는 주요 사항에 동의해요.','agree','A1','negotiation',1,'agreement nodding handshake smiling'),
('w_negotiation_A1_06','ask','/ɑːsk/','verb','요청하다, 묻다','To request something or seek information.','I want to {ask} for a longer deadline.','더 긴 마감일을 요청하고 싶어요.','ask','A1','negotiation',1,'question asking office meeting discussion'),
('w_negotiation_A1_07','offer','/ˈɒfər/','verb','제안하다','To present something for someone to accept or refuse.','We can {offer} a better rate next month.','다음 달에 더 좋은 요율을 제안할 수 있어요.','offer','A1','negotiation',1,'offer proposal business meeting table'),
('w_negotiation_A1_08','deal','/diːl/','noun','거래, 합의','An agreement, especially in business.','We made a great {deal} with the supplier.','공급업체와 좋은 거래를 했어요.','deal','A1','negotiation',1,'business deal handshake contract signing'),
('w_negotiation_A1_09','yes','/jes/','adverb','네, 예','Used to give an affirmative answer or agreement.','Say {yes} only when you are ready.','준비가 됐을 때만 예스라고 하세요.','yes','A1','negotiation',1,'agreement thumbs up approval positive'),
('w_negotiation_A1_10','no','/nəʊ/','adverb','아니요','Used to give a negative answer or refusal.','It is okay to say {no} in a negotiation.','협상에서 아니오라고 해도 괜찮아요.','no','A1','negotiation',1,'refusal shaking head no disagreement'),
('w_negotiation_A1_11','help','/help/','verb','돕다','To make it easier for someone to do something.','Can you {help} me with the contract?','계약서 작성을 도와주실 수 있나요?','help','A1','negotiation',1,'helping colleague office teamwork support'),
('w_negotiation_A1_12','more','/mɔːr/','adverb','더','A greater quantity or amount.','I need {more} time to think about it.','생각할 시간이 더 필요해요.','more','A1','negotiation',2,'more quantity increase growth chart'),
('w_negotiation_A1_13','less','/les/','adverb','덜, 더 적게','A smaller quantity or degree.','Can we pay {less} than the asking price?','요구 가격보다 덜 낼 수 있을까요?','less','A1','negotiation',2,'reduce decrease lower price tag'),
('w_negotiation_A1_14','pay','/peɪ/','verb','지불하다','To give money for goods or services.','How much do we need to {pay} upfront?','선불로 얼마나 내야 하나요?','pay','A1','negotiation',1,'payment money cash credit card'),
('w_negotiation_A1_15','get','/ɡet/','verb','얻다','To obtain or receive something.','What do we {get} in return?','대신 우리는 무엇을 얻나요?','get','A1','negotiation',1,'receive obtain reward benefit'),
('w_negotiation_A1_16','talk','/tɔːk/','verb','이야기하다','To communicate by speaking.','Let''s {talk} about the details later.','나중에 세부 사항에 대해 이야기해요.','talk','A1','negotiation',2,'conversation talking office meeting people'),
('w_negotiation_A1_17','meet','/miːt/','verb','만나다','To come together with someone at a place.','Can we {meet} on Friday to discuss this?','이것을 논의하기 위해 금요일에 만날 수 있나요?','meet','A1','negotiation',2,'meeting handshake conference room business'),
('w_negotiation_A1_18','say','/seɪ/','verb','말하다','To express something in words.','Please {say} what you think clearly.','생각하시는 것을 명확히 말씀해 주세요.','say','A1','negotiation',2,'speaking talking presentation clear communication'),
('w_negotiation_A1_19','wait','/weɪt/','verb','기다리다','To stay in one place until something happens.','Please {wait} while I check the numbers.','숫자를 확인하는 동안 기다려 주세요.','wait','A1','negotiation',2,'waiting patience calm office'),
('w_negotiation_A1_20','try','/traɪ/','verb','시도하다','To make an effort to do something.','Let''s {try} to find a middle ground.','중간 지점을 찾아보도록 해요.','try','A1','negotiation',2,'effort attempt trying problem solving'),
('w_negotiation_A1_21','buy','/baɪ/','verb','구매하다','To get something by paying money for it.','We want to {buy} in bulk to lower the price.','가격을 낮추기 위해 대량으로 구매하고 싶어요.','buy','A1','negotiation',1,'purchasing buying store bulk shopping'),
('w_negotiation_A1_22','sell','/sel/','verb','팔다','To give something in exchange for money.','We can {sell} at this price if you order now.','지금 주문하시면 이 가격에 드릴 수 있어요.','sell','A1','negotiation',1,'selling business commerce sale market'),
('w_negotiation_A1_23','price','/praɪs/','noun','가격','The amount of money expected for something.','What is the best {price} you can offer?','가장 좋은 가격은 얼마인가요?','price','A1','negotiation',1,'price tag label shopping market cost'),
('w_negotiation_A1_24','time','/taɪm/','noun','시간','A period within which something is done.','Do we have enough {time} to review everything?','모든 것을 검토할 시간이 충분한가요?','time','A1','negotiation',2,'clock time management deadline calendar'),
('w_negotiation_A1_25','good','/ɡʊd/','adjective','좋은','Of high quality or beneficial.','That sounds like a {good} offer to me.','저에게는 좋은 제안처럼 들려요.','good','A1','negotiation',2,'quality good positive thumbs up'),
('w_negotiation_A1_26','bad','/bæd/','adjective','나쁜','Of poor quality or unfavorable.','The terms are too {bad} to accept right now.','지금 당장 받아들이기엔 조건이 너무 나빠요.','bad','A1','negotiation',2,'negative poor quality unhappy'),
('w_negotiation_A1_27','okay','/ˌəʊˈkeɪ/','adjective','괜찮은','Satisfactory but not excellent.','The first offer is {okay} but we need more.','첫 제안은 괜찮지만 더 필요해요.','okay','A1','negotiation',2,'okay agreement acceptable neutral'),
('w_negotiation_A1_28','change','/tʃeɪndʒ/','verb','바꾸다','To make something different.','Can we {change} the payment schedule?','지불 일정을 바꿀 수 있을까요?','change','A1','negotiation',2,'change adjust modify edit revise'),
('w_negotiation_A1_29','stop','/stɒp/','verb','멈추다','To cease doing something.','Let''s {stop} here and continue tomorrow.','여기서 멈추고 내일 계속해요.','stop','A1','negotiation',3,'stop pause break rest meeting'),
('w_negotiation_A1_30','start','/stɑːt/','verb','시작하다','To begin something.','Let''s {start} with the most important issue.','가장 중요한 사안부터 시작해요.','start','A1','negotiation',2,'start begin launch opening meeting'),
('w_negotiation_A1_31','ready','/ˈredi/','adjective','준비된','Prepared and able to do something.','Are you {ready} to make a final decision?','최종 결정을 내릴 준비가 됐나요?','ready','A1','negotiation',2,'ready prepared confident business person'),
('w_negotiation_A1_32','open','/ˈəʊpən/','adjective','열린, 개방적인','Willing to consider new ideas.','I am {open} to other suggestions.','다른 제안에 열려 있어요.','open','A1','negotiation',2,'open door opportunity discussion flexible'),
('w_negotiation_A1_33','right','/raɪt/','adjective','맞는, 올바른','Correct or appropriate.','We need to find the {right} solution for both sides.','양쪽에 맞는 해결책을 찾아야 해요.','right','A1','negotiation',2,'correct right check mark solution'),
('w_negotiation_A1_34','work','/wɜːk/','verb','효과가 있다','To function effectively or be successful.','This plan can {work} if we cooperate.','협력하면 이 계획은 효과가 있을 거예요.','work','A1','negotiation',2,'teamwork cooperation plan effective'),
('w_negotiation_A1_35','think','/θɪŋk/','verb','생각하다','To use your mind to consider something.','Let me {think} about it and get back to you.','생각해 보고 다시 연락할게요.','think','A1','negotiation',2,'thinking considering person office pause');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_negotiation_A2_01','discount','/ˈdɪskaʊnt/','noun','할인','A reduction in the usual price of something.','Can you offer a {discount} for a large order?','대량 주문에 할인을 해주실 수 있나요?','discount','A2','negotiation',1,'discount sale percentage tag price reduction'),
('w_negotiation_A2_02','accept','/əkˈsept/','verb','받아들이다','To agree to receive or take something offered.','We are happy to {accept} the revised terms.','수정된 조건을 기꺼이 받아들여요.','accept','A2','negotiation',1,'accept agreement handshake deal approval'),
('w_negotiation_A2_03','refuse','/rɪˈfjuːz/','verb','거절하다','To say that you will not do or accept something.','We have to {refuse} the current proposal.','현재 제안은 거절해야 해요.','refuse','A2','negotiation',1,'refuse reject decline shake head no'),
('w_negotiation_A2_04','propose','/prəˈpəʊz/','verb','제안하다','To put forward a plan or idea for consideration.','I would like to {propose} a new payment plan.','새로운 지불 계획을 제안하고 싶어요.','propose','A2','negotiation',1,'propose idea presentation whiteboard business'),
('w_negotiation_A2_05','condition','/kənˈdɪʃən/','noun','조건','A requirement that must be met before something can happen.','What are the main {conditions} of the agreement?','계약의 주요 조건은 무엇인가요?','condition','A2','negotiation',1,'conditions checklist contract terms document'),
('w_negotiation_A2_06','term','/tɜːm/','noun','조건, 기간','A condition or stipulation in a contract or agreement.','The payment {terms} are thirty days net.','지불 조건은 순 30일이에요.','term','A2','negotiation',1,'terms contract document signing office'),
('w_negotiation_A2_07','fair','/feər/','adjective','공정한','Treating everyone equally and according to the rules.','We want a {fair} deal for both sides.','양쪽 모두에게 공정한 거래를 원해요.','fair','A2','negotiation',1,'fair balance scales justice equal'),
('w_negotiation_A2_08','both','/bəʊθ/','determiner','둘 다','Two people or things considered together.','This outcome benefits {both} parties.','이 결과는 양 당사자 모두에게 이익이에요.','both','A2','negotiation',2,'both sides together partnership balance'),
('w_negotiation_A2_09','together','/təˈɡeðər/','adverb','함께','With each other;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_negotiation_B1_01','negotiate','/nɪˈɡəʊʃieɪt/','verb','협상하다','To discuss formally to reach an agreement.','Both sides agreed to {negotiate} a new contract.','양측은 새로운 계약을 협상하기로 합의했어요.','negotiate','B1','negotiation',1,'negotiate discussion business meeting formal'),
('w_negotiation_B1_02','compromise','/ˈkɒmprəmaɪz/','verb','타협하다','To settle by mutual concession;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_negotiation_B2_01','arbitration','/ˌɑːbɪˈtreɪʃən/','noun','중재','A method of resolving disputes outside the courts.','The contract includes an {arbitration} clause.','계약서에 중재 조항이 포함돼 있어요.','arbitration','B2','negotiation',1,'arbitration mediation dispute resolution legal'),
('w_negotiation_B2_02','mediation','/ˌmiːdiˈeɪʃən/','noun','조정, 중재','Intervention to settle a dispute between parties.','{Mediation} is often faster than litigation.','조정은 소송보다 종종 빠릅니다.','mediation','B2','negotiation',1,'mediation neutral third party dispute settlement'),
('w_negotiation_B2_03','litigation','/ˌlɪtɪˈɡeɪʃən/','noun','소송','The process of taking legal action in court.','We want to avoid {litigation} at all costs.','어떤 대가를 치르더라도 소송을 피하고 싶어요.','litigation','B2','negotiation',1,'litigation court lawsuit legal process judge'),
('w_negotiation_B2_04','liability','/ˌlaɪəˈbɪlɪti/','noun','책임, 배상 책임','Legal responsibility for something, especially damage or debt.','The contract limits our {liability} to direct damages.','계약은 우리의 책임을 직접 손해로 제한해요.','liability','B2','negotiation',1,'liability responsibility legal risk insurance'),
('w_negotiation_B2_05','indemnity','/ɪnˈdemnɪti/','noun','보상, 면책','Compensation for harm or loss;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_negotiation_C1_01','fiduciary','/fɪˈdjuːʃəri/','adjective','신탁의, 수탁자의','Relating to the trust placed in a person to manage assets.','The trustee owes {fiduciary} duties to beneficiaries.','수탁자는 수익자에게 신탁 의무를 집니다.','fiduciary','C1','negotiation',1,'fiduciary trust duty legal obligation finance'),
('w_negotiation_C1_02','subrogation','/ˌsʌbrəˈɡeɪʃən/','noun','대위변제','The substitution of one party for another in a legal claim.','After paying the claim, the insurer pursued {subrogation}.','청구를 지급한 후 보험사는 대위변제를 추구했어요.','subrogation','C1','negotiation',1,'subrogation insurance legal claim substitution'),
('w_negotiation_C1_03','indemnification','/ɪnˌdemnɪfɪˈkeɪʃən/','noun','손해 배상 계약','A contractual obligation to compensate another for losses.','The {indemnification} provision covers all legal costs.','손해 배상 조항은 모든 법적 비용을 포함해요.','indemnification','C1','negotiation',1,'indemnification legal contract protect compensation clause'),
('w_negotiation_C1_04','covenant','/ˈkʌvənənt/','noun','약정, 서약 조항','A formal agreement or promise, especially in a contract.','The non-compete {covenant} lasts for two years.','경쟁 금지 약정은 2년간 지속돼요.','covenant','C1','negotiation',1,'covenant promise agreement contract restriction'),
('w_negotiation_C1_05','lien','/liːn/','noun','유치권, 담보권','A right to keep possession of property until a debt is paid.','The bank holds a {lien} over the property.','은행이 그 부동산에 유치권을 보유하고 있어요.','lien','C1','negotiation',1,'lien property claim bank security debt'),
('w_negotiation_C1_06','injunction','/ɪnˈdʒʌŋkʃən/','noun','금지 명령','A court order requiring a party to do or stop something.','We sought an {injunction} to halt the project.','프로젝트를 중단시키기 위해 금지 명령을 구했어요.','injunction','C1','negotiation',1,'injunction court order legal halt stop'),
('w_negotiation_C1_07','breach','/briːtʃ/','noun','위반 (고급)','Failure to fulfil a contractual or legal obligation.','The supplier''s delay was a clear {breach} of contract.','공급업체의 지연은 명백한 계약 위반이었어요.','breach','C1','negotiation',1,'breach violation legal failure contract consequence'),
('w_negotiation_C1_08','remedy','/ˈremədi/','noun','구제책','A means of obtaining redress for a legal wrong.','Damages are the most common {remedy} for breach.','손해배상이 위반에 대한 가장 일반적인 구제책이에요.','remedy','C1','negotiation',1,'remedy solution legal redress compensation contract'),
('w_negotiation_C1_09','jurisdiction','/ˌdʒʊərɪsˈdɪkʃən/','noun','관할권 (고급)','The official power to make legal decisions for an area.','Disputes are subject to Singapore {jurisdiction}.','분쟁은 싱가포르 관할권에 따라요.','jurisdiction','C1','negotiation',1,'jurisdiction court legal authority territory law'),
('w_negotiation_C1_10','tortious','/ˈtɔːʃəs/','adjective','불법 행위의','Constituting a civil wrong giving rise to liability.','The company faced a {tortious} interference claim.','회사는 불법 행위 간섭 청구에 직면했어요.','tortious','C1','negotiation',1,'tort civil wrong liability legal claim'),
('w_negotiation_C1_11','privity','/ˈprɪvɪti/','noun','계약 당사자 관계','The direct legal relationship between contracting parties.','A third party has no rights due to lack of {privity}.','제3자는 계약 당사자 관계가 없어 권리가 없어요.','privity','C1','negotiation',1,'privity contract relationship parties direct'),
('w_negotiation_C1_12','estoppel','/ɪˈstɒpəl/','noun','금반언','A legal principle preventing a person from contradicting a previous statement.','The court applied {estoppel} to prevent the claim.','법원은 청구를 막기 위해 금반언을 적용했어요.','estoppel','C1','negotiation',1,'estoppel legal principle contradiction consistency court'),
('w_negotiation_C1_13','rescission','/rɪˈsɪʃən/','noun','계약 해제','The cancellation of a contract, restoring parties to original positions.','{Rescission} was granted due to misrepresentation.','허위 진술로 인해 계약 해제가 허용됐어요.','rescission','C1','negotiation',1,'rescission cancel contract restore original legal'),
('w_negotiation_C1_14','novation','/nəʊˈveɪʃən/','noun','계약 갱신, 채무 교체','The substitution of a new obligation for an old one.','{Novation} transferred all duties to the acquiring company.','계약 갱신으로 모든 의무가 인수 기업에 이전됐어요.','novation','C1','negotiation',1,'novation substitute new contract obligation transfer'),
('w_negotiation_C1_15','promissory','/ˈprɒmɪsəri/','adjective','약속의, 약속 어음의','Conveying or implying a promise.','A {promissory} note is evidence of a debt obligation.','약속 어음은 채무 의무의 증거예요.','promissory','C1','negotiation',1,'promissory note promise debt document finance'),
('w_negotiation_C1_16','executory','/ɪɡˈzekjʊtəri/','adjective','미이행의, 실행 중인','Not yet fully performed;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_negotiation_C2_01','estoppel','/ɪˈstɒpəl/','noun','금반언의 원칙','A doctrine preventing a party from denying a previously asserted fact.','The court invoked {estoppel} to bar the defendant''s claim.','법원은 피고의 청구를 막기 위해 금반언을 발동했어요.','estoppel','C2','negotiation',1,'estoppel legal doctrine bar claim court principle'),
('w_negotiation_C2_02','novation','/nəʊˈveɪʃən/','noun','채무 인수, 계약 갱신','The act of replacing an old obligation with a new one, discharging the original party.','Through {novation}, the assignee assumed all liabilities.','계약 갱신을 통해 양수인이 모든 부채를 인수했어요.','novation','C2','negotiation',1,'novation contract replace obligation discharge legal'),
('w_negotiation_C2_03','rescission','/rɪˈsɪʃən/','noun','계약 취소','The cancellation of a contract and restoration of parties to their original state.','Fraudulent misrepresentation led to {rescission} of the agreement.','사기적 허위 진술이 계약 취소로 이어졌어요.','rescission','C2','negotiation',1,'rescission cancel contract restore legal fraud'),
('w_negotiation_C2_04','quantum meruit','/ˌkwɒntəm ˈmɛruːɪt/','noun','정당한 보수 청구권','A claim for reasonable payment for services rendered where no price was fixed.','The contractor claimed {quantum meruit} for completed work.','계약자가 완료된 작업에 대해 정당한 보수를 청구했어요.','quantum meruit','C2','negotiation',1,'quantum meruit payment services reasonable legal claim'),
('w_negotiation_C2_05','tortious','/ˈtɔːʃəs/','adjective','불법 행위를 구성하는','Of the nature of a tort;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_A1_01','story','/ˈstɔːri/','noun','이야기','A description of events, real or imagined.','She told us a {story} before bed.','그녀는 자기 전에 우리에게 이야기를 해줬어요.','story','A1','humanities',1,'book open story reading'),
('w_humanities_A1_02','book','/bʊk/','noun','책','A written work published in printed or digital form.','I read a {book} every month.','저는 매달 책을 한 권 읽어요.','book','A1','humanities',1,'book shelf library read'),
('w_humanities_A1_03','read','/riːd/','verb','읽다','To look at and understand written words.','Do you like to {read} in the morning?','아침에 독서하는 걸 좋아하세요?','read','A1','humanities',1,'person reading book open'),
('w_humanities_A1_04','write','/raɪt/','verb','쓰다','To mark words or symbols on a surface.','She loves to {write} short stories.','그녀는 단편 소설 쓰는 것을 좋아해요.','write','A1','humanities',1,'pen paper writing notebook'),
('w_humanities_A1_05','poem','/ˈpoʊɪm/','noun','시','A piece of writing in verse, often with rhythm.','He read a beautiful {poem} at the ceremony.','그는 행사에서 아름다운 시를 낭독했어요.','poem','A1','humanities',2,'poetry book writing verse'),
('w_humanities_A1_06','song','/sɒŋ/','noun','노래','A short piece of music with words.','She wrote a {song} about her hometown.','그녀는 고향에 대한 노래를 썼어요.','song','A1','humanities',1,'music notes singing guitar'),
('w_humanities_A1_07','history','/ˈhɪstəri/','noun','역사','The study of past events.','We studied the {history} of ancient civilizations.','우리는 고대 문명의 역사를 공부했어요.','history','A1','humanities',1,'ancient history books archive'),
('w_humanities_A1_08','old','/oʊld/','adjective','오래된','Having existed or lived for a long time.','This is an {old} and famous novel.','이것은 오래되고 유명한 소설이에요.','old','A1','humanities',2,'old books vintage library'),
('w_humanities_A1_09','people','/ˈpiːpəl/','noun','사람들','Human beings in general.','{People} love stories that feel real.','사람들은 현실적으로 느껴지는 이야기를 좋아해요.','people','A1','humanities',1,'crowd people gathering social'),
('w_humanities_A1_10','word','/wɜːrd/','noun','단어','A single unit of language.','What does this {word} mean in English?','이 단어는 영어로 무슨 뜻이에요?','word','A1','humanities',1,'dictionary words letters text'),
('w_humanities_A1_11','name','/neɪm/','noun','이름','A word used to identify a person or thing.','What is the {name} of this poem?','이 시의 제목이 뭐예요?','name','A1','humanities',2,'name tag label identity'),
('w_humanities_A1_12','page','/peɪdʒ/','noun','페이지','One side of a sheet of paper in a book.','Open your book to {page} ten.','책의 10페이지를 펴세요.','page','A1','humanities',2,'book page open reading'),
('w_humanities_A1_13','picture','/ˈpɪktʃər/','noun','그림, 사진','A drawing, painting, or photograph.','There is a {picture} in every chapter.','모든 챕터에 그림이 있어요.','picture','A1','humanities',2,'illustration art painting book'),
('w_humanities_A1_14','letter','/ˈletər/','noun','편지;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_A2_01','author','/ˈɔːθər/','noun','작가','A person who writes books or articles.','My favorite {author} has written over twenty novels.','제가 가장 좋아하는 작가는 소설을 20편 넘게 썼어요.','author','A2','humanities',1,'writer author desk books'),
('w_humanities_A2_02','novel','/ˈnɒvəl/','noun','소설','A long fictional prose narrative.','I just finished reading a great {novel}.','방금 훌륭한 소설을 다 읽었어요.','novel','A2','humanities',1,'novel book fiction reading'),
('w_humanities_A2_03','character','/ˈkærɪktər/','noun','등장인물;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_B1_01','metaphor','/ˈmetəfɔːr/','noun','은유','A figure of speech applying a word or phrase to something it does not literally denote.','The author uses a powerful {metaphor} to describe grief.','작가는 슬픔을 묘사하기 위해 강력한 은유를 사용해요.','metaphor','B1','humanities',1,'metaphor language poetry figure'),
('w_humanities_B1_02','theme','/θiːm/','noun','주제, 테마','The central subject or idea explored in a work.','The main {theme} of the novel is redemption.','소설의 주된 주제는 구원이에요.','theme','B1','humanities',1,'theme idea central message'),
('w_humanities_B1_03','symbolism','/ˈsɪmbəlɪzəm/','noun','상징주의;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_B2_01','allegory','/ˈæləɡɔːri/','noun','알레고리, 풍유','A narrative with a hidden symbolic meaning.','Animal Farm is a well-known political {allegory}.','동물농장은 유명한 정치적 알레고리예요.','allegory','B2','humanities',1,'allegory symbol story meaning'),
('w_humanities_B2_02','archetype','/ˈɑːrkɪtaɪp/','noun','원형, 아키타입','A very typical example of a character or situation.','The wise old mentor is a classic literary {archetype}.','현명한 노인 멘토는 고전적인 문학 원형이에요.','archetype','B2','humanities',1,'archetype hero mentor pattern'),
('w_humanities_B2_03','motif','/moʊˈtiːf/','noun','모티프, 반복 요소','A recurring image, idea, or symbol in a work.','The {motif} of water runs throughout the novel.','물의 모티프가 소설 전체에 흐르고 있어요.','motif','B2','humanities',1,'motif pattern symbol repeat'),
('w_humanities_B2_04','subtext','/ˈsʌbtekst/','noun','숨겨진 의미, 서브텍스트','An underlying theme in a work that is not explicitly stated.','The {subtext} of the dialogue reveals jealousy.','대화의 숨겨진 의미는 질투를 드러내요.','subtext','B2','humanities',2,'subtext hidden meaning reading'),
('w_humanities_B2_05','irony','/ˈaɪrəni/','noun','아이러니, 반어','The expression of meaning through language that signifies the opposite.','The title of the novel is full of {irony}.','소설의 제목은 아이러니로 가득해요.','irony','B2','humanities',1,'irony contrast meaning twist'),
('w_humanities_B2_06','paradox','/ˈpærədɒks/','noun','역설','A seemingly contradictory statement that may be true.','The poet expresses grief through the {paradox} of joyful language.','시인은 기쁜 언어의 역설을 통해 슬픔을 표현해요.','paradox','B2','humanities',1,'paradox contradiction truth meaning'),
('w_humanities_B2_07','satire','/ˈsætaɪər/','noun','풍자','The use of humor or irony to criticize society.','Swift''s Gulliver''s Travels is a masterpiece of {satire}.','스위프트의 걸리버 여행기는 풍자의 걸작이에요.','satire','B2','humanities',1,'satire criticism humor society'),
('w_humanities_B2_08','bildungsroman','/ˈbɪldʊŋzroʊˌmɑːn/','noun','성장 소설','A novel about a young person''s moral and psychological growth.','The Catcher in the Rye is a famous {bildungsroman}.','호밀밭의 파수꾼은 유명한 성장 소설이에요.','bildungsroman','B2','humanities',2,'coming of age youth growth story'),
('w_humanities_B2_09','modernism','/ˈmɒdərnɪzəm/','noun','모더니즘','A movement in literature and arts rejecting traditional forms.','Virginia Woolf is a key figure of literary {modernism}.','버지니아 울프는 문학 모더니즘의 핵심 인물이에요.','modernism','B2','humanities',2,'modernism art movement twentieth century'),
('w_humanities_B2_10','existentialism','/ˌeɡzɪˈstenʃəlɪzəm/','noun','실존주의','A philosophical theory that humans define their own meaning.','Camus'' work is deeply rooted in {existentialism}.','카뮈의 작품은 실존주의에 깊이 뿌리를 두고 있어요.','existentialism','B2','humanities',2,'existentialism philosophy meaning freedom'),
('w_humanities_B2_11','allusion','/əˈluːʒən/','noun','암시, 전고(典故)','An indirect reference to a person, event, or work.','The poem contains an {allusion} to the Bible.','시에는 성경에 대한 암시가 담겨 있어요.','allusion','B2','humanities',2,'allusion reference history intertextual'),
('w_humanities_B2_12','ambiguity','/ˌæmbɪˈɡjuːɪti/','noun','모호함, 중의성','The quality of being open to more than one interpretation.','The ending is left in deliberate {ambiguity}.','결말은 의도적인 모호함으로 남겨져 있어요.','ambiguity','B2','humanities',2,'ambiguity meaning uncertain open'),
('w_humanities_B2_13','foreshadowing','/fɔːrˈʃædoʊɪŋ/','noun','복선','A literary technique used to hint at future events.','The ominous weather is a form of {foreshadowing}.','불길한 날씨는 복선의 일종이에요.','foreshadowing','B2','humanities',2,'foreshadowing hint clue future'),
('w_humanities_B2_14','postmodernism','/ˌpoʊstˈmɒdərnɪzəm/','noun','포스트모더니즘','A movement rejecting modernism''s grand narratives.','{Postmodernism} often questions the nature of truth in fiction.','포스트모더니즘은 종종 소설에서 진실의 본질에 의문을 제기해요.','postmodernism','B2','humanities',2,'postmodern art culture contemporary'),
('w_humanities_B2_15','unreliable','/ˌʌnrɪˈlaɪəbəl/','adjective','믿을 수 없는','Not able to be trusted or depended on.','The {unreliable} narrator keeps the reader guessing.','믿을 수 없는 화자는 독자를 계속 추측하게 만들어요.','unreliable','B2','humanities',2,'unreliable narrator deception twist'),
('w_humanities_B2_16','catharsis','/kəˈθɑːrsɪs/','noun','카타르시스, 정화','The process of releasing strong emotions through art.','Greek tragedy aimed to produce {catharsis} in the audience.','그리스 비극은 관객에게 카타르시스를 일으키는 것을 목표로 했어요.','catharsis','B2','humanities',2,'catharsis emotion release theater'),
('w_humanities_B2_17','aesthetic','/esˈθetɪk/','adjective / noun','미적인;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_C1_01','hermeneutics','/ˌhɜːrmɪˈnjuːtɪks/','noun','해석학','The theory and methodology of interpretation, especially of texts.','Biblical {hermeneutics} has shaped centuries of scholarship.','성경 해석학은 수 세기의 학문을 형성해왔어요.','hermeneutics','C1','humanities',2,'hermeneutics interpretation text philosophy'),
('w_humanities_C1_02','semiotics','/ˌsiːmiˈɒtɪks/','noun','기호학','The study of signs and symbols and their use or interpretation.','{Semiotics} helps us decode the hidden meaning of images.','기호학은 이미지의 숨겨진 의미를 해독하는 데 도움이 돼요.','semiotics','C1','humanities',2,'semiotics signs symbols meaning'),
('w_humanities_C1_03','intertextuality','/ˌɪntərtekstʃuˈælɪti/','noun','상호텍스트성','The relationship between texts, especially through allusion or quotation.','The novel''s {intertextuality} with Homer enriches its meaning.','호머와의 상호텍스트성이 소설의 의미를 풍부하게 해요.','intertextuality','C1','humanities',1,'intertextuality reference allusion text'),
('w_humanities_C1_04','deconstruction','/ˌdiːkənˈstrʌkʃən/','noun','해체주의','A method of analysis that challenges fixed meanings in texts.','Derrida''s {deconstruction} revolutionized literary criticism.','데리다의 해체주의는 문학 비평을 혁신했어요.','deconstruction','C1','humanities',2,'deconstruction theory text meaning'),
('w_humanities_C1_05','poststructuralism','/ˌpoʊstˈstrʌktʃərəlɪzəm/','noun','포스트구조주의','A theory challenging the stable meanings proposed by structuralism.','{Poststructuralism} questions whether texts have fixed meanings.','포스트구조주의는 텍스트에 고정된 의미가 있는지 의문을 제기해요.','poststructuralism','C1','humanities',2,'poststructuralism theory language text'),
('w_humanities_C1_06','phenomenology','/fɪˌnɒmɪˈnɒlədʒi/','noun','현상학','The philosophical study of structures of experience and consciousness.','Husserl''s {phenomenology} influenced literary theory deeply.','후설의 현상학은 문학 이론에 깊은 영향을 미쳤어요.','phenomenology','C1','humanities',2,'phenomenology experience consciousness philosophy'),
('w_humanities_C1_07','dialectic','/ˌdaɪəˈlektɪk/','noun','변증법','A method of argument through contradictory ideas to arrive at truth.','Hegel''s {dialectic} of thesis and antithesis shapes critical thought.','헤겔의 변증법은 비판적 사고를 형성해요.','dialectic','C1','humanities',2,'dialectic philosophy argument truth'),
('w_humanities_C1_08','mimesis','/mɪˈmiːsɪs/','noun','미메시스, 모방','The imitation or representation of the real world in art.','Aristotle''s concept of {mimesis} remains foundational to literary theory.','아리스토텔레스의 미메시스 개념은 문학 이론의 기초로 남아 있어요.','mimesis','C1','humanities',2,'mimesis imitation reality representation'),
('w_humanities_C1_09','sublime','/səˈblaɪm/','noun / adjective','숭고함;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_C2_01','logocentrism','/ˈloʊɡoʊˌsentrɪzəm/','noun','로고스 중심주의','Derrida''s term for the privileging of speech over writing in Western thought.','The entire deconstructive project aims to displace {logocentrism}.','해체주의 프로젝트 전체는 로고스 중심주의를 대체하는 것을 목표로 해요.','logocentrism','C2','humanities',2,'logocentrism derrida language text'),
('w_humanities_C2_02','différance','/ˌdiːfəˈrɑːns/','noun','디페랑스','Derrida''s neologism combining "differ" and "defer" to describe the endless play of signification.','The concept of {différance} undermines the possibility of fixed meaning.','디페랑스 개념은 고정된 의미의 가능성을 허물어요.','différance','C2','humanities',2,'différance derrida meaning sign'),
('w_humanities_C2_03','palimpsest','/ˈpælɪmpsest/','noun','팔림프세스트 (겹쳐 쓴 양피지)','A manuscript on which writing has been effaced and replaced;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_technology_A1_01','computer','/kəmˈpjuːtər/','noun','컴퓨터','An electronic device for storing and processing data.','I use a {computer} every day for work.','저는 매일 업무에 컴퓨터를 사용해요.','computer','A1','technology',1,'computer laptop desk office workspace'),
('w_technology_A1_02','phone','/foʊn/','noun','전화기, 휴대폰','A device used to make and receive calls.','My {phone} battery is running low.','제 휴대폰 배터리가 거의 없어요.','phone','A1','technology',1,'smartphone phone hand screen modern'),
('w_technology_A1_03','internet','/ˈɪntərnɛt/','noun','인터넷','A global system of connected computer networks.','You need the {internet} to watch streaming videos.','스트리밍 동영상을 보려면 인터넷이 필요해요.','internet','A1','technology',1,'internet wifi connection global network'),
('w_technology_A1_04','app','/æp/','noun','앱, 애플리케이션','A software program designed for a mobile device or computer.','I downloaded a new {app} for learning English.','영어 학습용 새 앱을 다운로드했어요.','app','A1','technology',1,'smartphone app icons colorful screen'),
('w_technology_A1_05','screen','/skriːn/','noun','화면, 스크린','The flat surface of a device that displays images.','The {screen} on this laptop is very bright.','이 노트북의 화면이 정말 밝아요.','screen','A1','technology',1,'laptop screen bright display modern'),
('w_technology_A1_06','game','/ɡeɪm/','noun','게임','An activity played for entertainment, often on a device.','This {game} is very popular with teenagers.','이 게임은 10대들 사이에서 매우 인기 있어요.','game','A1','technology',1,'video game controller playing fun'),
('w_technology_A1_07','email','/ˈiːmeɪl/','noun','이메일','A message sent electronically via the internet.','Please send me an {email} with the details.','세부 내용을 이메일로 보내주세요.','email','A1','technology',1,'email inbox laptop message office'),
('w_technology_A1_08','photo','/ˈfoʊtoʊ/','noun','사진','An image taken with a camera or phone.','She took a {photo} of the sunset.','그녀는 일몰 사진을 찍었어요.','photo','A1','technology',1,'photo camera taking picture outdoor'),
('w_technology_A1_09','video','/ˈvɪdioʊ/','noun','동영상, 비디오','A recording of moving images.','I watched a {video} about cooking online.','온라인에서 요리에 관한 동영상을 봤어요.','video','A1','technology',1,'video watching screen online streaming'),
('w_technology_A1_10','button','/ˈbʌtən/','noun','버튼','A small control pressed to operate a device.','Press the {button} to turn on the device.','기기를 켜려면 버튼을 누르세요.','button','A1','technology',1,'button press device power control'),
('w_technology_A1_11','mouse','/maʊs/','noun','마우스','A handheld device used to control a computer cursor.','Move the {mouse} to the left to go back.','뒤로 가려면 마우스를 왼쪽으로 움직이세요.','mouse','A1','technology',2,'computer mouse desk workspace cursor'),
('w_technology_A1_12','keyboard','/ˈkiːbɔːrd/','noun','키보드','A set of keys used to type on a computer.','I need a new {keyboard} because some keys are broken.','몇 개의 키가 고장나서 새 키보드가 필요해요.','keyboard','A1','technology',2,'keyboard typing computer office desk'),
('w_technology_A1_13','cable','/ˈkeɪbəl/','noun','케이블, 선','A thick wire used to connect devices.','I forgot to bring the charging {cable}.','충전 케이블을 가져오는 걸 잊었어요.','cable','A1','technology',2,'cable wire charging power connect'),
('w_technology_A1_14','charge','/tʃɑːrdʒ/','verb','충전하다','To put electrical power into a battery.','I need to {charge} my phone before we leave.','떠나기 전에 휴대폰을 충전해야 해요.','charge','A1','technology',2,'phone charging cable power outlet'),
('w_technology_A1_15','print','/prɪnt/','verb','인쇄하다','To produce text or images on paper using a printer.','Can you {print} this document for me?','이 문서를 인쇄해 주실 수 있나요?','print','A1','technology',2,'printer printing document paper office'),
('w_technology_A1_16','send','/sɛnd/','verb','보내다','To cause something to go or be taken to a destination.','I will {send} you the file right away.','지금 바로 파일을 보내드릴게요.','send','A1','technology',2,'sending message email file share'),
('w_technology_A1_17','open','/ˈoʊpən/','verb','열다, 실행하다','To start a program or file on a computer.','{Open} the folder and find the document.','폴더를 열어서 문서를 찾아보세요.','Open','A1','technology',2,'opening folder file computer screen'),
('w_technology_A1_18','save','/seɪv/','verb','저장하다','To store data so it is not lost.','Don''t forget to {save} your work before closing.','닫기 전에 작업 내용을 저장하는 것을 잊지 마세요.','save','A1','technology',2,'save file computer document storage'),
('w_technology_A1_19','password','/ˈpæswɜːrd/','noun','비밀번호','A secret word used to gain access to a system.','Enter your {password} to log in.','로그인하려면 비밀번호를 입력하세요.','password','A1','technology',1,'password login security access lock'),
('w_technology_A1_20','click','/klɪk/','verb','클릭하다','To press a mouse button to select or activate something.','{Click} the icon to open the program.','프로그램을 열려면 아이콘을 클릭하세요.','Click','A1','technology',2,'clicking mouse cursor computer screen'),
('w_technology_A1_21','type','/taɪp/','verb','타이핑하다, 입력하다','To write by pressing keys on a keyboard.','Please {type} your name in the box.','박스에 이름을 입력해 주세요.','type','A1','technology',2,'typing keyboard hands fast writing'),
('w_technology_A1_22','search','/sɜːrtʃ/','verb','검색하다','To look for information, especially online.','You can {search} for anything on the internet.','인터넷에서 무엇이든 검색할 수 있어요.','search','A1','technology',1,'search bar google internet query'),
('w_technology_A1_23','tablet','/ˈtæblɪt/','noun','태블릿','A flat, portable device with a touchscreen.','She reads books on her {tablet} every night.','그녀는 매일 밤 태블릿으로 책을 읽어요.','tablet','A1','technology',2,'tablet ipad screen touch reading'),
('w_technology_A1_24','speaker','/ˈspiːkər/','noun','스피커','A device that converts electrical signals into sound.','The {speaker} on my phone is very loud.','제 휴대폰 스피커가 정말 크게 들려요.','speaker','A1','technology',2,'speaker bluetooth sound music audio'),
('w_technology_A1_25','link','/lɪŋk/','noun','링크','A connection between web pages on the internet.','Click on the {link} to visit the website.','웹사이트를 방문하려면 링크를 클릭하세요.','link','A1','technology',2,'link url website click browser'),
('w_technology_A1_26','power','/ˈpaʊər/','noun','전원, 전력','Electrical energy used to operate devices.','Press the {power} button to turn off the TV.','TV를 끄려면 전원 버튼을 누르세요.','power','A1','technology',2,'power button electricity device switch'),
('w_technology_A1_27','device','/dɪˈvaɪs/','noun','기기, 장치','A piece of equipment made for a specific purpose.','This {device} is very easy to use.','이 기기는 사용하기 매우 쉬워요.','device','A1','technology',1,'electronic device gadget technology modern'),
('w_technology_A1_28','file','/faɪl/','noun','파일','A collection of data stored under a single name.','I saved the {file} to my desktop.','데스크톱에 파일을 저장했어요.','file','A1','technology',2,'file folder computer document digital'),
('w_technology_A1_29','icon','/ˈaɪkɒn/','noun','아이콘','A small image on a screen representing a program or function.','Tap the {icon} to open the app.','앱을 열려면 아이콘을 탭하세요.','icon','A1','technology',2,'app icon screen smartphone colorful'),
('w_technology_A1_30','microphone','/ˈmaɪkrəfoʊn/','noun','마이크','A device that converts sound into electrical signals.','The {microphone} on this headset is very clear.','이 헤드셋의 마이크가 매우 선명해요.','microphone','A1','technology',2,'microphone recording studio podcast voice'),
('w_technology_A1_31','headphones','/ˈhɛdfəʊnz/','noun','헤드폰','A pair of speakers worn over the ears.','I use {headphones} when I study to focus better.','집중하기 위해 공부할 때 헤드폰을 사용해요.','headphones','A1','technology',2,'headphones music listening focus study'),
('w_technology_A1_32','camera','/ˈkæmərə/','noun','카메라','A device used to take photographs or videos.','The {camera} quality on this phone is amazing.','이 휴대폰의 카메라 화질이 놀라워요.','camera','A1','technology',1,'camera photography taking picture lens'),
('w_technology_A1_33','memory','/ˈmɛməri/','noun','메모리, 저장 공간','Storage space on a device for holding data.','My phone has no {memory} left for new photos.','새 사진을 위한 메모리 공간이 없어요.','memory','A1','technology',2,'memory storage device chip data'),
('w_technology_A1_34','remote','/rɪˈmoʊt/','noun','리모컨','A device for controlling something from a distance.','Where is the TV {remote}?','TV 리모컨이 어디 있어요?','remote','A1','technology',2,'remote control TV living room sofa'),
('w_technology_A1_35','plug','/plʌɡ/','noun','플러그, 콘센트','A device connecting an electrical appliance to a power source.','Plug the charger into the {plug} on the wall.','벽에 있는 콘센트에 충전기를 꽂으세요.','plug','A1','technology',2,'plug outlet power socket electric wall');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_technology_A2_01','software','/ˈsɔːftweər/','noun','소프트웨어','Programs and operating information used by a computer.','Make sure your {software} is up to date.','소프트웨어가 최신 상태인지 확인하세요.','software','A2','technology',1,'software code programming computer screen'),
('w_technology_A2_02','download','/ˈdaʊnloʊd/','verb','다운로드하다','To copy data from the internet to your device.','{Download} the app from the App Store.','앱 스토어에서 앱을 다운로드하세요.','Download','A2','technology',1,'download arrow internet file transfer'),
('w_technology_A2_03','upload','/ˈʌploʊd/','verb','업로드하다','To copy data from your device to the internet.','You can {upload} photos directly to the website.','웹사이트에 직접 사진을 업로드할 수 있어요.','upload','A2','technology',1,'upload cloud arrow internet share'),
('w_technology_A2_04','delete','/dɪˈliːt/','verb','삭제하다','To remove data or a file permanently.','{Delete} any files you no longer need.','더 이상 필요 없는 파일은 삭제하세요.','Delete','A2','technology',1,'delete trash bin file remove digital'),
('w_technology_A2_05','update','/ˈʌpdeɪt/','verb','업데이트하다','To install the latest version of software.','Please {update} your system to fix the bug.','버그를 수정하려면 시스템을 업데이트하세요.','update','A2','technology',1,'update software system progress loading'),
('w_technology_A2_06','wifi','/ˈwaɪfaɪ/','noun','와이파이','Wireless technology allowing internet connection.','The hotel has free {wifi} in all rooms.','호텔의 모든 객실에서 무료 와이파이를 이용할 수 있어요.','wifi','A2','technology',1,'wifi signal router internet connection'),
('w_technology_A2_07','battery','/ˈbætəri/','noun','배터리','A device that stores and provides electrical energy.','The {battery} in my laptop only lasts two hours.','제 노트북 배터리는 두 시간밖에 안 돼요.','battery','A2','technology',1,'battery low power charge indicator'),
('w_technology_A2_08','bluetooth','/ˈbluːtuːθ/','noun','블루투스','A wireless technology for short-range communication.','Connect your earbuds via {bluetooth}.','블루투스로 이어폰을 연결하세요.','bluetooth','A2','technology',2,'bluetooth earbuds wireless connection device'),
('w_technology_A2_09','notification','/ˌnoʊtɪfɪˈkeɪʃən/','noun','알림','A message sent to a device to alert the user.','I turned off {notification}s to focus on studying.','공부에 집중하기 위해 알림을 껐어요.','notification','A2','technology',1,'notification phone alert bell message'),
('w_technology_A2_10','settings','/ˈsɛtɪŋz/','noun','설정','Options that can be adjusted to control how a device works.','Go to {settings} to change the display brightness.','화면 밝기를 바꾸려면 설정으로 가세요.','settings','A2','technology',1,'settings gear icon phone control options'),
('w_technology_A2_11','restart','/ˌriːˈstɑːrt/','verb','재시작하다','To shut down and start a device or program again.','Try to {restart} the device to fix the problem.','문제를 해결하려면 기기를 재시작해 보세요.','restart','A2','technology',2,'restart reboot computer phone loading'),
('w_technology_A2_12','username','/ˈjuːzərneɪm/','noun','아이디, 사용자 이름','A name used to identify a person on a website or app.','Enter your {username} and password to log in.','로그인하려면 아이디와 비밀번호를 입력하세요.','username','A2','technology',2,'username login account profile registration'),
('w_technology_A2_13','log in','/lɒɡ ɪn/','phrasal verb','로그인하다','To access a computer system or website using credentials.','You need to {log in} to view your messages.','메시지를 보려면 로그인해야 해요.','log in','A2','technology',1,'login account password screen secure'),
('w_technology_A2_14','log out','/lɒɡ aʊt/','phrasal verb','로그아웃하다','To end a session on a computer system or website.','Always {log out} when using a shared computer.','공용 컴퓨터를 사용할 때는 항상 로그아웃하세요.','log out','A2','technology',2,'logout security account shared computer'),
('w_technology_A2_15','screenshot','/ˈskriːnʃɒt/','noun','스크린샷','An image of what is currently displayed on a screen.','Take a {screenshot} and send it to me.','스크린샷을 찍어서 보내주세요.','screenshot','A2','technology',2,'screenshot phone screen capture image'),
('w_technology_A2_16','website','/ˈwɛbsaɪt/','noun','웹사이트','A set of pages on the internet under one address.','Check the official {website} for more information.','더 많은 정보는 공식 웹사이트를 확인하세요.','website','A2','technology',1,'website browser internet page design'),
('w_technology_A2_17','browser','/ˈbraʊzər/','noun','브라우저','A program used to access the internet.','Open your {browser} and go to the link.','브라우저를 열고 링크로 이동하세요.','browser','A2','technology',2,'browser chrome internet web navigation'),
('w_technology_A2_18','network','/ˈnɛtwɜːrk/','noun','네트워크','A system of connected computers or devices.','Connect to the office {network} to access the files.','파일에 접근하려면 사무실 네트워크에 연결하세요.','network','A2','technology',1,'network connection computers office router'),
('w_technology_A2_19','backup','/ˈbækʌp/','noun','백업','A copy of data saved in case the original is lost.','Always make a {backup} of your important files.','중요한 파일은 항상 백업해 두세요.','backup','A2','technology',1,'backup hard drive data storage copy'),
('w_technology_A2_20','virus','/ˈvaɪrəs/','noun','바이러스','Malicious software that damages or disrupts systems.','A {virus} deleted all the files on my computer.','바이러스가 컴퓨터의 모든 파일을 삭제했어요.','virus','A2','technology',1,'virus malware computer security warning red'),
('w_technology_A2_21','glitch','/ɡlɪtʃ/','noun','결함, 오류','A small error or malfunction in software or hardware.','There was a {glitch} in the app and it crashed.','앱에 결함이 생겨서 충돌했어요.','glitch','A2','technology',2,'glitch error screen bug software crash'),
('w_technology_A2_22','install','/ɪnˈstɔːl/','verb','설치하다','To put software onto a computer or device.','{Install} the program before you start.','시작하기 전에 프로그램을 설치하세요.','Install','A2','technology',1,'install software computer setup loading bar'),
('w_technology_A2_23','folder','/ˈfoʊldər/','noun','폴더','A virtual container for organizing files.','Save all the documents in this {folder}.','모든 문서를 이 폴더에 저장하세요.','folder','A2','technology',2,'folder files organized computer desktop'),
('w_technology_A2_24','storage','/ˈstɔːrɪdʒ/','noun','저장 공간','The space available on a device for keeping data.','I need more {storage} for my video files.','동영상 파일을 위한 저장 공간이 더 필요해요.','storage','A2','technology',1,'storage drive data space hard disk'),
('w_technology_A2_25','account','/əˈkaʊnt/','noun','계정','A profile or record set up with a service or website.','Create an {account} to access all the features.','모든 기능을 이용하려면 계정을 만드세요.','account','A2','technology',1,'account profile registration online sign up'),
('w_technology_A2_26','share','/ʃeər/','verb','공유하다','To give others access to a file, link, or content.','You can {share} the document with your team.','팀원들과 문서를 공유할 수 있어요.','share','A2','technology',1,'share document link team collaboration'),
('w_technology_A2_27','zoom','/zuːm/','verb','확대하다;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_technology_B1_01','algorithm','/ˈælɡərɪðəm/','noun','알고리즘','A set of rules or steps a computer follows to solve a problem.','The search {algorithm} finds the most relevant results.','검색 알고리즘이 가장 관련성 높은 결과를 찾아줘요.','algorithm','B1','technology',1,'algorithm flowchart code logic computer'),
('w_technology_B1_02','interface','/ˈɪntərfeɪs/','noun','인터페이스','The way a user interacts with a system or program.','The new {interface} is much easier to navigate.','새 인터페이스는 훨씬 사용하기 편해요.','interface','B1','technology',1,'interface ui design app screen clean'),
('w_technology_B1_03','database','/ˈdeɪtəbeɪs/','noun','데이터베이스','An organized collection of data stored electronically.','All customer information is kept in a {database}.','모든 고객 정보는 데이터베이스에 저장돼요.','database','B1','technology',1,'database server data storage structured'),
('w_technology_B1_04','server','/ˈsɜːrvər/','noun','서버','A computer that provides data or services to other devices.','The {server} is down, so the website is not loading.','서버가 다운되어서 웹사이트가 로드되지 않아요.','server','B1','technology',1,'server room rack data center technology'),
('w_technology_B1_05','cloud','/klaʊd/','noun','클라우드','Remote servers accessed via the internet for data storage.','I store all my photos in the {cloud}.','모든 사진을 클라우드에 저장해요.','cloud','B1','technology',1,'cloud computing storage sky data sync'),
('w_technology_B1_06','code','/koʊd/','noun','코드','Instructions written in a programming language for a computer.','You need to learn {code} to build your own app.','자신만의 앱을 만들려면 코드를 배워야 해요.','code','B1','technology',1,'code programming screen developer dark'),
('w_technology_B1_07','encryption','/ɪnˈkrɪpʃən/','noun','암호화','The process of converting data into a code to prevent access.','The app uses end-to-end {encryption} to protect messages.','앱은 메시지를 보호하기 위해 종단간 암호화를 사용해요.','encryption','B1','technology',1,'encryption security lock data protected'),
('w_technology_B1_08','cybersecurity','/ˌsaɪbərsɪˈkjʊərɪti/','noun','사이버 보안','The practice of protecting systems from digital attacks.','Companies invest heavily in {cybersecurity} to protect data.','기업들은 데이터 보호를 위해 사이버 보안에 많이 투자해요.','cybersecurity','B1','technology',1,'cybersecurity shield digital protection lock'),
('w_technology_B1_09','bandwidth','/ˈbændwɪdθ/','noun','대역폭','The maximum amount of data that can be transmitted at once.','Streaming in 4K uses a lot of {bandwidth}.','4K로 스트리밍하면 대역폭을 많이 사용해요.','bandwidth','B1','technology',2,'bandwidth internet speed data network'),
('w_technology_B1_10','debugging','/diːˈbʌɡɪŋ/','noun','디버깅','The process of finding and fixing errors in software.','{Debugging} took longer than writing the code itself.','디버깅이 코드를 작성하는 것보다 더 오래 걸렸어요.','debugging','B1','technology',2,'debugging code error fix developer screen'),
('w_technology_B1_11','framework','/ˈfreɪmwɜːrk/','noun','프레임워크','A pre-built set of tools and libraries for development.','React is a popular {framework} for building web apps.','React는 웹 앱 개발에 인기 있는 프레임워크예요.','framework','B1','technology',2,'framework code structure development blueprint'),
('w_technology_B1_12','version control','/ˈvɜːrʒən kənˈtroʊl/','noun','버전 관리','A system for tracking and managing changes to code.','We use Git for {version control} on every project.','모든 프로젝트에서 버전 관리를 위해 Git을 사용해요.','version control','B1','technology',2,'version control git code branches history'),
('w_technology_B1_13','deployment','/dɪˈplɔɪmənt/','noun','배포','The process of making software available for use.','The {deployment} of the new feature went smoothly.','새 기능 배포가 순조롭게 이루어졌어요.','deployment','B1','technology',2,'deployment release code launch production'),
('w_technology_B1_14','firewall','/ˈfaɪərwɔːl/','noun','방화벽','A security system that monitors and controls network traffic.','The company {firewall} blocked the suspicious website.','회사 방화벽이 의심스러운 웹사이트를 차단했어요.','firewall','B1','technology',1,'firewall security network protection digital'),
('w_technology_B1_15','bug','/bʌɡ/','noun','버그, 오류','An error or flaw in software that causes unexpected behavior.','There is a {bug} in the login system that we need to fix.','로그인 시스템에 수정이 필요한 버그가 있어요.','bug','B1','technology',1,'bug code error software problem screen'),
('w_technology_B1_16','patch','/pætʃ/','noun','패치','A software update that fixes a specific bug or vulnerability.','Apply the latest security {patch} to stay protected.','보호 상태를 유지하려면 최신 보안 패치를 적용하세요.','patch','B1','technology',2,'patch update security software fix shield'),
('w_technology_B1_17','protocol','/ˈproʊtəkɒl/','noun','프로토콜','A set of rules that govern data exchange between devices.','HTTPS is the secure {protocol} used for web browsing.','HTTPS는 웹 브라우징에 사용되는 보안 프로토콜이에요.','protocol','B1','technology',2,'protocol https secure web connection lock'),
('w_technology_B1_18','cache','/kæʃ/','noun','캐시','Temporary data stored to speed up future requests.','Clear the {cache} if the website is loading slowly.','웹사이트가 느리게 로드된다면 캐시를 지우세요.','cache','B1','technology',2,'cache clear browser speed web loading'),
('w_technology_B1_19','API','/ˌeɪpiːˈaɪ/','noun','에이피아이 (응용 프로그램 인터페이스)','A set of rules that allows different programs to communicate.','This app uses the weather {API} to show forecasts.','이 앱은 날씨 예보를 보여주기 위해 날씨 API를 사용해요.','API','B1','technology',1,'api code integration developer connection'),
('w_technology_B1_20','repository','/rɪˈpɒzɪtəri/','noun','저장소, 리포지토리','A place where code or data is stored and managed.','All our code is in a private {repository} on GitHub.','우리 코드는 모두 GitHub의 비공개 저장소에 있어요.','repository','B1','technology',2,'github repository code project storage'),
('w_technology_B1_21','feature','/ˈfiːtʃər/','noun','기능, 특징','A distinct capability or characteristic of software.','The new {feature} lets users customize their dashboard.','새 기능으로 사용자가 대시보드를 맞춤 설정할 수 있어요.','feature','B1','technology',1,'feature product launch software new update'),
('w_technology_B1_22','platform','/ˈplætfɔːrm/','noun','플랫폼','A system or technology on which other applications run.','Instagram is one of the most popular social media {platform}s.','인스타그램은 가장 인기 있는 소셜 미디어 플랫폼 중 하나예요.','platform','B1','technology',1,'platform social media technology ecosystem'),
('w_technology_B1_23','permission','/pərˈmɪʃən/','noun','권한, 허가','Authorization granted to access a system or resource.','The app is asking for {permission} to use your camera.','앱이 카메라 사용 권한을 요청하고 있어요.','permission','B1','technology',2,'permission access allow app phone request'),
('w_technology_B1_24','sync','/sɪŋk/','verb','동기화하다','To update data on multiple devices so they match.','{Sync} your phone with the computer to transfer files.','파일을 전송하려면 휴대폰을 컴퓨터와 동기화하세요.','sync','B1','technology',1,'sync cloud devices data matching update'),
('w_technology_B1_25','malware','/ˈmælweər/','noun','악성 소프트웨어','Software designed to disrupt or damage a system.','The antivirus software detected and removed the {malware}.','바이러스 백신 소프트웨어가 악성 소프트웨어를 탐지하여 제거했어요.','malware','B1','technology',1,'malware virus security warning digital red'),
('w_technology_B1_26','data','/ˈdeɪtə/','noun','데이터','Facts and statistics collected for reference or analysis.','The app collects {data} about your daily habits.','앱이 일상 습관에 관한 데이터를 수집해요.','data','B1','technology',1,'data analytics chart visualization technology'),
('w_technology_B1_27','scalable','/ˈskeɪləbəl/','adjective','확장 가능한','Able to grow or be adapted to handle increasing demands.','We need a {scalable} solution for our growing user base.','늘어나는 사용자를 위한 확장 가능한 솔루션이 필요해요.','scalable','B1','technology',2,'scalable growth system architecture expanding'),
('w_technology_B1_28','integration','/ˌɪntɪˈɡreɪʃən/','noun','통합','The combination of different systems or software to work together.','The {integration} between the two apps took weeks.','두 앱 간의 통합에 몇 주가 걸렸어요.','integration','B1','technology',2,'integration systems connect apps workflow'),
('w_technology_B1_29','sprint','/sprɪnt/','noun','스프린트 (개발 주기)','A short, time-boxed period for completing a set of tasks.','We finished three features in the last {sprint}.','지난 스프린트에서 세 가지 기능을 완성했어요.','sprint','B1','technology',2,'sprint agile development team planning board'),
('w_technology_B1_30','open source','/ˌoʊpən ˈsɔːrs/','adjective','오픈소스','Software with source code available for anyone to view or modify.','This {open source} project has thousands of contributors.','이 오픈소스 프로젝트에는 수천 명의 기여자가 있어요.','open source','B1','technology',1,'open source github community code collaboration'),
('w_technology_B1_31','script','/skrɪpt/','noun','스크립트','A small program or set of instructions for automating tasks.','I wrote a {script} to automatically rename the files.','파일 이름을 자동으로 바꾸는 스크립트를 작성했어요.','script','B1','technology',2,'script code automation terminal command'),
('w_technology_B1_32','latency','/ˈleɪtənsi/','noun','지연 시간','The delay before data begins to transfer after an instruction.','High {latency} makes online gaming frustrating.','높은 지연 시간은 온라인 게임을 답답하게 해요.','latency','B1','technology',2,'latency ping speed network connection'),
('w_technology_B1_33','log','/lɒɡ/','noun','로그, 기록','A record of events or errors generated by a system.','Check the server {log} to find the source of the error.','오류 원인을 찾으려면 서버 로그를 확인하세요.','log','B1','technology',2,'server log record file system error'),
('w_technology_B1_34','token','/ˈtoʊkən/','noun','토큰 (인증 키)','A string of data used to authenticate a user or session.','The API requires an authentication {token} for each request.','API는 각 요청에 인증 토큰이 필요해요.','token','B1','technology',2,'token authentication security api access'),
('w_technology_B1_35','webhook','/ˈwɛbhʊk/','noun','웹훅','An automated message sent between apps when an event occurs.','We set up a {webhook} to notify Slack when a build fails.','빌드가 실패하면 Slack에 알림이 가도록 웹훅을 설정했어요.','webhook','B1','technology',2,'webhook automation notification trigger event code');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_technology_B2_01','artificial intelligence','/ˌɑːrtɪˈfɪʃəl ɪnˈtelɪdʒəns/','noun','인공지능','The simulation of human intelligence by computer systems.','{Artificial intelligence} is transforming the healthcare industry.','인공지능이 의료 산업을 변화시키고 있어요.','artificial intelligence','B2','technology',1,'artificial intelligence robot brain digital glow'),
('w_technology_B2_02','machine learning','/məˈʃiːn ˈlɜːrnɪŋ/','noun','머신러닝','A type of AI that enables computers to learn from data.','The app uses {machine learning} to improve its recommendations.','앱은 추천을 개선하기 위해 머신러닝을 사용해요.','machine learning','B2','technology',1,'machine learning neural network data pattern'),
('w_technology_B2_03','automation','/ˌɔːtəˈmeɪʃən/','noun','자동화','The use of technology to perform tasks without human help.','Factory {automation} has reduced the need for manual labor.','공장 자동화로 수작업 필요성이 줄었어요.','automation','B2','technology',1,'automation robot factory industrial machine'),
('w_technology_B2_04','blockchain','/ˈblɒktʃeɪn/','noun','블록체인','A decentralized digital ledger that records transactions securely.','{Blockchain} technology ensures transaction transparency.','블록체인 기술은 거래 투명성을 보장해요.','blockchain','B2','technology',1,'blockchain cryptocurrency digital ledger network'),
('w_technology_B2_05','IoT','/ˌaɪ oʊ ˈtiː/','noun','사물인터넷','The network of physical devices connected and exchanging data.','{IoT} devices in smart homes can be controlled remotely.','스마트홈의 사물인터넷 기기는 원격으로 제어할 수 있어요.','IoT','B2','technology',1,'smart home iot devices connected technology'),
('w_technology_B2_06','neural network','/ˈnjʊərəl ˈnɛtwɜːrk/','noun','신경망','A computing system inspired by the human brain''s structure.','The image recognition system uses a {neural network}.','이미지 인식 시스템은 신경망을 사용해요.','neural network','B2','technology',1,'neural network brain ai nodes glowing'),
('w_technology_B2_07','data mining','/ˈdeɪtə ˌmaɪnɪŋ/','noun','데이터 마이닝','Extracting useful patterns from large sets of data.','Companies use {data mining} to predict customer behavior.','기업들은 고객 행동을 예측하기 위해 데이터 마이닝을 사용해요.','data mining','B2','technology',1,'data mining analytics visualization big data'),
('w_technology_B2_08','deep learning','/diːp ˈlɜːrnɪŋ/','noun','딥러닝','A subset of machine learning using multi-layered neural networks.','{Deep learning} powers most modern voice recognition systems.','딥러닝은 대부분의 현대 음성 인식 시스템을 구동해요.','deep learning','B2','technology',1,'deep learning ai layers network visualization'),
('w_technology_B2_09','algorithm bias','/ˈælɡərɪðəm ˈbaɪəs/','noun','알고리즘 편향','Systematic errors in AI outputs caused by biased training data.','{Algorithm bias} can lead to unfair decisions in hiring systems.','알고리즘 편향은 채용 시스템에서 불공정한 결정을 초래할 수 있어요.','algorithm bias','B2','technology',2,'bias algorithm fairness data ai ethics'),
('w_technology_B2_10','natural language processing','/ˈnætʃrəl ˈlæŋɡwɪdʒ ˈproʊsesɪŋ/','noun','자연어 처리','AI technology enabling computers to understand human language.','{Natural language processing} powers chatbots and translation apps.','자연어 처리가 챗봇과 번역 앱을 구동해요.','natural language processing','B2','technology',1,'natural language processing nlp text ai'),
('w_technology_B2_11','virtual reality','/ˈvɜːrtʃuəl riˈælɪti/','noun','가상현실','A simulated experience that immerses users in a digital world.','{Virtual reality} is increasingly used for medical training.','가상현실은 의료 훈련에 점점 더 많이 사용되고 있어요.','virtual reality','B2','technology',1,'virtual reality vr headset immersive digital'),
('w_technology_B2_12','augmented reality','/ɔːɡˈmɛntɪd riˈælɪti/','noun','증강현실','Technology that overlays digital information on the real world.','The app uses {augmented reality} to show furniture in your home.','앱은 집에 가구를 보여주기 위해 증강현실을 사용해요.','augmented reality','B2','technology',1,'augmented reality ar phone overlay digital'),
('w_technology_B2_13','cybersecurity threat','/ˌsaɪbərsɪˈkjʊərɪti θrɛt/','noun','사이버 보안 위협','A potential danger to digital systems or data.','Phishing emails remain the most common {cybersecurity threat}.','피싱 이메일은 가장 일반적인 사이버 보안 위협으로 남아 있어요.','cybersecurity threat','B2','technology',2,'cybersecurity threat warning hacker dark'),
('w_technology_B2_14','cloud computing','/klaʊd kəmˈpjuːtɪŋ/','noun','클라우드 컴퓨팅','Delivering computing services over the internet.','{Cloud computing} allows teams to collaborate from anywhere.','클라우드 컴퓨팅을 통해 팀이 어디서든 협업할 수 있어요.','cloud computing','B2','technology',1,'cloud computing server data center storage'),
('w_technology_B2_15','predictive analytics','/prɪˈdɪktɪv ˌænəˈlɪtɪks/','noun','예측 분석','Using data and algorithms to forecast future outcomes.','Retailers use {predictive analytics} to manage inventory.','소매업체들은 재고를 관리하기 위해 예측 분석을 사용해요.','predictive analytics','B2','technology',2,'predictive analytics chart forecast data graph'),
('w_technology_B2_16','microprocessor','/ˌmaɪkroʊˈprɒsɛsər/','noun','마이크로프로세서','A chip that performs the basic operations of a computer.','The new {microprocessor} is twice as fast as the previous one.','새 마이크로프로세서는 이전 것보다 두 배 빠릅니다.','microprocessor','B2','technology',2,'microprocessor chip silicon circuit board'),
('w_technology_B2_17','biometric','/ˌbaɪoʊˈmɛtrɪk/','adjective','생체인식의','Relating to the measurement of physical characteristics.','{Biometric} authentication uses your face or fingerprint to log in.','생체인식 인증은 얼굴이나 지문으로 로그인해요.','biometric','B2','technology',1,'biometric fingerprint face scan security login'),
('w_technology_B2_18','digital transformation','/ˈdɪdʒɪtəl ˌtrænsˈfɔːrmeɪʃən/','noun','디지털 전환','The integration of digital technology into all areas of a business.','{Digital transformation} has changed how companies operate.','디지털 전환은 기업의 운영 방식을 바꿔놓았어요.','digital transformation','B2','technology',1,'digital transformation business technology modern'),
('w_technology_B2_19','generative AI','/ˈdʒɛnərətɪv eɪˈaɪ/','noun','생성형 AI','AI that can create new content such as text, images, or code.','{Generative AI} tools can write articles and draw pictures.','생성형 AI 도구는 글을 쓰고 그림을 그릴 수 있어요.','generative AI','B2','technology',1,'generative ai create image text artwork'),
('w_technology_B2_20','large language model','/lɑːrdʒ ˈlæŋɡwɪdʒ ˈmɒdəl/','noun','거대 언어 모델','A type of AI trained on massive amounts of text data.','{Large language model}s like GPT power many AI assistants.','GPT와 같은 거대 언어 모델이 많은 AI 어시스턴트를 구동해요.','large language model','B2','technology',1,'large language model llm text ai brain'),
('w_technology_B2_21','edge AI','/ɛdʒ eɪˈaɪ/','noun','엣지 AI','AI processing done on local devices rather than the cloud.','{Edge AI} allows smart devices to work without internet.','엣지 AI를 통해 스마트 기기가 인터넷 없이도 작동해요.','edge AI','B2','technology',2,'edge ai device local computing smart'),
('w_technology_B2_22','semiconductor','/ˌsɛmɪkənˈdʌktər/','noun','반도체','A material that can conduct electricity under certain conditions.','The global {semiconductor} shortage affected car production.','세계적인 반도체 부족이 자동차 생산에 영향을 미쳤어요.','semiconductor','B2','technology',1,'semiconductor chip silicon wafer factory'),
('w_technology_B2_23','inference','/ˈɪnfərəns/','noun','추론 (AI)','The process of running a trained AI model to make predictions.','On-device {inference} is faster and more private.','온디바이스 추론은 더 빠르고 프라이버시가 보호돼요.','inference','B2','technology',2,'inference ai prediction model compute'),
('w_technology_B2_24','fine-tuning','/faɪn ˈtjuːnɪŋ/','noun','파인튜닝','Adapting a pre-trained AI model for a specific task.','{Fine-tuning} the model on medical data improved its accuracy.','의료 데이터로 모델을 파인튜닝하자 정확도가 향상되었어요.','fine-tuning','B2','technology',2,'fine tuning ai model training optimization data'),
('w_technology_B2_25','throughput','/ˈθruːpʊt/','noun','처리량','The amount of data processed by a system in a given time.','Upgrading the server increased its {throughput} significantly.','서버를 업그레이드하자 처리량이 크게 증가했어요.','throughput','B2','technology',2,'throughput server performance data processing speed'),
('w_technology_B2_26','container','/kənˈteɪnər/','noun','컨테이너 (가상화)','A lightweight, portable unit of software and its dependencies.','We use Docker {container}s to run our applications.','애플리케이션 실행을 위해 Docker 컨테이너를 사용해요.','container','B2','technology',2,'container docker kubernetes deployment software'),
('w_technology_B2_27','microservices','/ˈmaɪkroʊˌsɜːrvɪsɪz/','noun','마이크로서비스','An architecture style where apps are built as small, independent services.','The platform uses {microservices} for flexibility and scale.','플랫폼은 유연성과 확장성을 위해 마이크로서비스를 사용해요.','microservices','B2','technology',2,'microservices architecture services diagram cloud'),
('w_technology_B2_28','DevOps','/ˈdɛvɒps/','noun','데브옵스','A practice combining development and operations for faster delivery.','{DevOps} culture helps teams release software more frequently.','데브옵스 문화는 팀이 소프트웨어를 더 자주 출시하는 데 도움을 줘요.','DevOps','B2','technology',2,'devops pipeline ci cd automation deployment'),
('w_technology_B2_29','tokenization','/ˌtoʊkənɪˈzeɪʃən/','noun','토큰화','Converting sensitive data into non-sensitive tokens for security.','Credit card {tokenization} protects financial information.','신용카드 토큰화는 금융 정보를 보호해요.','tokenization','B2','technology',2,'tokenization security payment data protection'),
('w_technology_B2_30','zero-trust','/ˈzɪəroʊ trʌst/','adjective','제로 트러스트','A security model that requires strict verification for all users.','The company adopted a {zero-trust} security policy.','회사는 제로 트러스트 보안 정책을 채택했어요.','zero-trust','B2','technology',2,'zero trust security policy verification shield'),
('w_technology_B2_31','hyperparameter','/ˌhaɪpərˈpærəmɪtər/','noun','하이퍼파라미터','A parameter set before training a machine learning model.','Tuning {hyperparameter}s is critical for model performance.','하이퍼파라미터 튜닝은 모델 성능에 매우 중요해요.','hyperparameter','B2','technology',2,'hyperparameter tuning machine learning model optimization'),
('w_technology_B2_32','multimodal AI','/ˌmʌltiˈmoʊdəl eɪˈaɪ/','noun','멀티모달 AI','AI that can process and generate multiple types of data.','{Multimodal AI} can analyze both images and text at once.','멀티모달 AI는 이미지와 텍스트를 동시에 분석할 수 있어요.','multimodal AI','B2','technology',2,'multimodal ai input image text voice data'),
('w_technology_B2_33','data sovereignty','/ˈdeɪtə ˈsɒvrɪnti/','noun','데이터 주권','The concept that data is subject to the laws of its country.','{Data sovereignty} laws affect where companies can store user data.','데이터 주권법은 기업이 사용자 데이터를 저장할 수 있는 곳에 영향을 줘요.','data sovereignty','B2','technology',2,'data sovereignty flag law privacy global'),
('w_technology_B2_34','algorithm efficiency','/ˈælɡərɪðəm ɪˈfɪʃənsi/','noun','알고리즘 효율성','How well an algorithm performs in terms of speed and resources.','Improving {algorithm efficiency} reduced the server costs.','알고리즘 효율성 개선으로 서버 비용이 줄었어요.','algorithm efficiency','B2','technology',2,'algorithm efficiency optimization code performance'),
('w_technology_B2_35','synthetic data','/sɪnˈθɛtɪk ˈdeɪtə/','noun','합성 데이터','Artificially generated data used to train AI models.','{Synthetic data} allows training without compromising user privacy.','합성 데이터를 통해 사용자 프라이버시를 침해하지 않고 학습할 수 있어요.','synthetic data','B2','technology',2,'synthetic data generation ai training fake');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_technology_C1_01','quantum computing','/ˈkwɒntəm kəmˈpjuːtɪŋ/','noun','양자 컴퓨팅','Computing using quantum-mechanical phenomena like superposition.','{Quantum computing} could break current encryption methods.','양자 컴퓨팅은 현재의 암호화 방식을 무력화할 수 있어요.','quantum computing','C1','technology',1,'quantum computing qubit futuristic blue glow'),
('w_technology_C1_02','edge computing','/ɛdʒ kəmˈpjuːtɪŋ/','noun','엣지 컴퓨팅','Processing data near its source rather than in a central server.','{Edge computing} reduces latency for real-time applications.','엣지 컴퓨팅은 실시간 애플리케이션의 지연 시간을 줄여요.','edge computing','C1','technology',1,'edge computing device local network processing'),
('w_technology_C1_03','cryptography','/krɪpˈtɒɡrəfi/','noun','암호학','The practice of secure communication in the presence of adversaries.','Modern {cryptography} relies on mathematical problems that are hard to solve.','현대 암호학은 풀기 어려운 수학 문제에 의존해요.','cryptography','C1','technology',1,'cryptography encryption key code secure'),
('w_technology_C1_04','federated learning','/ˈfɛdəreɪtɪd ˈlɜːrnɪŋ/','noun','연합 학습','Training AI models across decentralized devices without sharing data.','{Federated learning} protects user privacy while training AI.','연합 학습은 AI를 학습시키면서 사용자 프라이버시를 보호해요.','federated learning','C1','technology',2,'federated learning privacy distributed ai network'),
('w_technology_C1_05','reinforcement learning','/ˌriːɪnˈfɔːrsmənt ˈlɜːrnɪŋ/','noun','강화 학습','An AI method where an agent learns by receiving rewards or penalties.','Game-playing AIs use {reinforcement learning} to improve strategies.','게임 플레이 AI는 전략을 개선하기 위해 강화 학습을 사용해요.','reinforcement learning','C1','technology',2,'reinforcement learning agent reward game ai'),
('w_technology_C1_06','transformer model','/trænsˈfɔːrmər ˈmɒdəl/','noun','트랜스포머 모델','An AI architecture based on self-attention mechanisms for sequence data.','The {transformer model} revolutionized natural language processing.','트랜스포머 모델은 자연어 처리에 혁명을 일으켰어요.','transformer model','C1','technology',1,'transformer model attention ai architecture diagram'),
('w_technology_C1_07','adversarial attack','/ədˈvɜːrsəriəl əˈtæk/','noun','적대적 공격','An input designed to deceive an AI model into making errors.','Researchers discovered an {adversarial attack} on the image classifier.','연구자들이 이미지 분류기에 대한 적대적 공격을 발견했어요.','adversarial attack','C1','technology',2,'adversarial attack ai security perturbation error'),
('w_technology_C1_08','scalability','/ˌskeɪləˈbɪlɪti/','noun','확장성','The ability of a system to handle growing amounts of work.','The startup struggled with {scalability} as user numbers grew.','사용자 수가 늘어나면서 스타트업은 확장성 문제로 어려움을 겪었어요.','scalability','C1','technology',1,'scalability server growth architecture cloud'),
('w_technology_C1_09','differential privacy','/ˌdɪfəˈrɛnʃəl ˈprɪvəsi/','noun','차등 프라이버시','A technique that adds noise to data to protect individual privacy.','Apple uses {differential privacy} when collecting usage statistics.','Apple은 사용 통계를 수집할 때 차등 프라이버시를 사용해요.','differential privacy','C1','technology',2,'differential privacy noise data protection statistics'),
('w_technology_C1_10','model distillation','/ˈmɒdəl ˌdɪstɪˈleɪʃən/','noun','모델 경량화','Compressing a large AI model into a smaller, efficient one.','{Model distillation} allows powerful AI to run on mobile devices.','모델 경량화를 통해 강력한 AI가 모바일 기기에서 실행될 수 있어요.','model distillation','C1','technology',2,'model distillation compression ai mobile efficiency'),
('w_technology_C1_11','attention mechanism','/əˈtɛnʃən ˈmɛkənɪzəm/','noun','어텐션 메커니즘','A technique allowing AI to focus on relevant parts of input data.','The {attention mechanism} helps translation models capture context.','어텐션 메커니즘은 번역 모델이 맥락을 파악하는 데 도움을 줘요.','attention mechanism','C1','technology',2,'attention mechanism ai focus neural diagram'),
('w_technology_C1_12','zero-shot learning','/ˈzɪəroʊ ʃɒt ˈlɜːrnɪŋ/','noun','제로샷 학습','An AI model''s ability to handle tasks it was never explicitly trained on.','{Zero-shot learning} allows models to classify unseen categories.','제로샷 학습을 통해 모델은 본 적 없는 카테고리를 분류할 수 있어요.','zero-shot learning','C1','technology',2,'zero shot learning ai generalization knowledge'),
('w_technology_C1_13','autonomous systems','/ɔːˈtɒnəməs ˈsɪstəmz/','noun','자율 시스템','Systems capable of operating independently without human control.','{Autonomous systems} power self-driving cars and delivery drones.','자율 시스템은 자율주행차와 배달 드론을 구동해요.','autonomous systems','C1','technology',1,'autonomous car drone self-driving technology'),
('w_technology_C1_14','prompt engineering','/prɒmpt ˈɛndʒɪnɪərɪŋ/','noun','프롬프트 엔지니어링','Designing effective inputs to guide AI model outputs.','{Prompt engineering} has become a valuable skill for AI users.','프롬프트 엔지니어링은 AI 사용자에게 귀중한 기술이 되었어요.','prompt engineering','C1','technology',1,'prompt engineering ai text input design language'),
('w_technology_C1_15','hallucination','/həˌluːsɪˈneɪʃən/','noun','환각 (AI)','When an AI model generates confident but factually incorrect output.','The chatbot''s {hallucination} provided false medical information.','챗봇의 환각이 잘못된 의료 정보를 제공했어요.','hallucination','C1','technology',1,'ai hallucination false information output warning'),
('w_technology_C1_16','retrieval-augmented generation','/rɪˈtriːvəl ɔːɡˈmɛntɪd ˌdʒɛnəˈreɪʃən/','noun','검색 증강 생성','A technique combining retrieval of real data with AI text generation.','{Retrieval-augmented generation} reduces AI hallucinations significantly.','검색 증강 생성은 AI 환각을 크게 줄여줘요.','retrieval-augmented generation','C1','technology',2,'rag retrieval augmented generation database ai'),
('w_technology_C1_17','mixture of experts','/ˈmɪkstʃər əv ˈɛkspɜːrts/','noun','전문가 혼합 모델','An AI architecture using specialized sub-networks for different tasks.','The {mixture of experts} model scales efficiently without extra cost.','전문가 혼합 모델은 추가 비용 없이 효율적으로 확장돼요.','mixture of experts','C1','technology',2,'mixture of experts moe ai architecture scaling'),
('w_technology_C1_18','context window','/ˈkɒntɛkst ˈwɪndoʊ/','noun','컨텍스트 윈도우','The maximum amount of text an AI model can process at once.','A longer {context window} allows the model to handle longer documents.','더 긴 컨텍스트 윈도우를 통해 모델이 더 긴 문서를 처리할 수 있어요.','context window','C1','technology',2,'context window ai model text length tokens'),
('w_technology_C1_19','knowledge graph','/ˈnɒlɪdʒ ɡrɑːf/','noun','지식 그래프','A network of interconnected entities and their relationships.','Search engines use a {knowledge graph} to understand context.','검색 엔진은 맥락을 이해하기 위해 지식 그래프를 사용해요.','knowledge graph','C1','technology',2,'knowledge graph network nodes connections data'),
('w_technology_C1_20','vector embedding','/ˈvɛktər ɪmˈbɛdɪŋ/','noun','벡터 임베딩','A representation of data as a point in multi-dimensional space.','Word {vector embedding}s capture semantic relationships between words.','단어 벡터 임베딩은 단어 간의 의미적 관계를 포착해요.','vector embedding','C1','technology',2,'vector embedding semantic space ai diagram'),
('w_technology_C1_21','model alignment','/ˈmɒdəl əˈlaɪnmənt/','noun','모델 정렬','Ensuring AI systems behave in ways that match human values.','{Model alignment} research is critical for building safe AI.','모델 정렬 연구는 안전한 AI를 구축하는 데 매우 중요해요.','model alignment','C1','technology',1,'model alignment ai safety human values research'),
('w_technology_C1_22','neuromorphic chip','/ˌnjʊərəˈmɔːrfɪk tʃɪp/','noun','뉴로모픽 칩','A hardware architecture modeled on the structure of the brain.','A {neuromorphic chip} processes sensory data far more efficiently.','뉴로모픽 칩은 감각 데이터를 훨씬 효율적으로 처리해요.','neuromorphic chip','C1','technology',2,'neuromorphic chip brain inspired hardware circuit'),
('w_technology_C1_23','observability','/əbˌzɜːrvəˈbɪlɪti/','noun','관측 가능성','The ability to understand a system''s state from its outputs.','Good {observability} helps engineers diagnose production issues faster.','좋은 관측 가능성은 엔지니어가 운영 문제를 더 빨리 진단하는 데 도움을 줘요.','observability','C1','technology',2,'observability monitoring dashboard logs metrics'),
('w_technology_C1_24','chaos engineering','/ˈkeɪɒs ˌɛndʒɪˈnɪərɪŋ/','noun','카오스 엔지니어링','Intentionally introducing failures to test system resilience.','Netflix pioneered {chaos engineering} to improve platform stability.','Netflix는 플랫폼 안정성 향상을 위해 카오스 엔지니어링을 선도했어요.','chaos engineering','C1','technology',2,'chaos engineering resilience fault testing system'),
('w_technology_C1_25','model collapse','/ˈmɒdəl kəˈlæps/','noun','모델 붕괴','Degradation of AI models trained on AI-generated data.','Researchers warn that {model collapse} is a risk for future AI systems.','연구자들은 모델 붕괴가 미래 AI 시스템의 위험이라고 경고해요.','model collapse','C1','technology',2,'model collapse ai degradation training data loop'),
('w_technology_C1_26','explainability','/ɪkˌspleɪnəˈbɪlɪti/','noun','설명 가능성','The degree to which an AI''s decision-making process can be understood.','Medical AI requires high {explainability} for regulatory approval.','의료 AI는 규제 승인을 위해 높은 설명 가능성이 필요해요.','explainability','C1','technology',2,'explainability ai transparency decision process'),
('w_technology_C1_27','multi-agent system','/ˌmʌlti ˈeɪdʒənt ˈsɪstəm/','noun','다중 에이전트 시스템','A system of multiple AI agents that interact and coordinate.','Researchers used a {multi-agent system} to simulate market behavior.','연구자들은 시장 행동을 시뮬레이션하기 위해 다중 에이전트 시스템을 사용했어요.','multi-agent system','C1','technology',2,'multi agent system ai coordination network'),
('w_technology_C1_28','responsible AI','/rɪˈspɒnsɪbəl eɪˈaɪ/','noun','책임 있는 AI','AI developed and deployed with ethics, fairness, and accountability.','Companies are publishing {responsible AI} guidelines to build trust.','기업들은 신뢰 구축을 위해 책임 있는 AI 가이드라인을 발표하고 있어요.','responsible AI','C1','technology',1,'responsible ai ethics fairness transparency guidelines'),
('w_technology_C1_29','data provenance','/ˈdeɪtə ˈprɒvənəns/','noun','데이터 출처','The origin and history of data, including how it was collected.','{Data provenance} is essential for auditing AI training datasets.','데이터 출처는 AI 학습 데이터셋 감사에 필수적이에요.','data provenance','C1','technology',2,'data provenance origin history audit trail'),
('w_technology_C1_30','latency optimization','/ˈleɪtənsi ˌɒptɪmaɪˈzeɪʃən/','noun','지연 최적화','Techniques to minimize the time delay in data processing.','{Latency optimization} is critical for real-time voice assistants.','지연 최적화는 실시간 음성 비서에 매우 중요해요.','latency optimization','C1','technology',2,'latency optimization speed response time network'),
('w_technology_C1_31','inference engine','/ˈɪnfərəns ˈɛndʒɪn/','noun','추론 엔진','The component of an AI system that applies rules to make decisions.','The {inference engine} processes user queries in milliseconds.','추론 엔진은 밀리초 단위로 사용자 쿼리를 처리해요.','inference engine','C1','technology',2,'inference engine ai query processing decision'),
('w_technology_C1_32','homomorphic encryption','/ˌhoʊmoʊˈmɔːrfɪk ɪnˈkrɪpʃən/','noun','동형암호화','Encryption allowing computation on encrypted data without decrypting it.','{Homomorphic encryption} lets servers process private data without seeing it.','동형암호화를 통해 서버는 개인 데이터를 보지 않고도 처리할 수 있어요.','homomorphic encryption','C1','technology',3,'homomorphic encryption privacy data secure computation'),
('w_technology_C1_33','multitenancy','/ˌmʌltiˈtɛnənsi/','noun','멀티테넌시','A software architecture where a single instance serves multiple users.','Cloud platforms use {multitenancy} to reduce infrastructure costs.','클라우드 플랫폼은 인프라 비용 절감을 위해 멀티테넌시를 사용해요.','multitenancy','C1','technology',2,'multitenancy cloud saas users shared architecture'),
('w_technology_C1_34','synthetic data','/sɪnˈθɛtɪk ˈdeɪtə/','noun','합성 데이터 (C1 응용)','Artificially generated data used in privacy-preserving AI pipelines.','The medical AI team used {synthetic data} approved by regulators.','의료 AI 팀이 규제 기관이 승인한 합성 데이터를 사용했어요.','synthetic data','C1','technology',2,'synthetic data pipeline privacy ai regulated'),
('w_technology_C1_35','neural architecture search','/ˈnjʊərəl ˈɑːrkɪtektʃər sɜːrtʃ/','noun','신경망 구조 탐색','Automated discovery of optimal neural network architectures.','{Neural architecture search} can outperform manually designed models.','신경망 구조 탐색은 수동으로 설계된 모델을 능가할 수 있어요.','neural architecture search','C1','technology',2,'neural architecture search automated design ai model');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_technology_C2_01','neuromorphic computing','/ˌnjʊərəˈmɔːrfɪk kəmˈpjuːtɪŋ/','noun','뉴로모픽 컴퓨팅','A computing paradigm that mimics the architecture of the human brain.','{Neuromorphic computing} may redefine energy-efficient AI hardware.','뉴로모픽 컴퓨팅은 에너지 효율적인 AI 하드웨어를 재정의할 수 있어요.','neuromorphic computing','C2','technology',2,'neuromorphic computing brain chip energy efficient'),
('w_technology_C2_02','bioengineering','/ˌbaɪoʊˌɛndʒɪˈnɪərɪŋ/','noun','생명공학','The application of engineering principles to biological systems.','{Bioengineering} advances are enabling lab-grown organs.','생명공학의 발전으로 실험실에서 장기를 배양할 수 있게 되고 있어요.','bioengineering','C2','technology',2,'bioengineering lab organ tissue science'),
('w_technology_C2_03','nanotechnology','/ˌnænoʊtɛkˈnɒlədʒi/','noun','나노 기술','Engineering at the scale of individual atoms and molecules.','{Nanotechnology} could enable drug delivery directly into cancer cells.','나노 기술은 암세포에 직접 약물을 전달할 수 있어요.','nanotechnology','C2','technology',2,'nanotechnology atoms molecules science microscopic'),
('w_technology_C2_04','quantum entanglement','/ˈkwɒntəm ɪnˈtæŋɡəlmənt/','noun','양자 얽힘','A quantum phenomenon where particles remain connected over any distance.','{Quantum entanglement} is the basis for quantum communication.','양자 얽힘은 양자 통신의 기반이에요.','quantum entanglement','C2','technology',2,'quantum entanglement particles physics connected'),
('w_technology_C2_05','topological computing','/ˌtɒpəˈlɒdʒɪkəl kəmˈpjuːtɪŋ/','noun','위상학적 컴퓨팅','A quantum computing approach using topological states for error resistance.','{Topological computing} promises more stable quantum processors.','위상학적 컴퓨팅은 더 안정적인 양자 프로세서를 약속해요.','topological computing','C2','technology',3,'topological quantum computing abstract physics'),
('w_technology_C2_06','emergent systems','/ɪˈmɜːrdʒənt ˈsɪstəmz/','noun','창발 시스템','Complex systems whose behavior arises from simple interacting components.','{Emergent systems} in AI can exhibit unexpected capabilities.','AI의 창발 시스템은 예상치 못한 능력을 보여줄 수 있어요.','emergent systems','C2','technology',2,'emergent system complexity network self organization'),
('w_technology_C2_07','stochastic gradient descent','/stəˈkæstɪk ˈɡreɪdiənt dɪˈsɛnt/','noun','확률적 경사 하강법','An optimization algorithm used to train machine learning models.','{Stochastic gradient descent} is the backbone of deep learning training.','확률적 경사 하강법은 딥러닝 학습의 핵심이에요.','stochastic gradient descent','C2','technology',2,'stochastic gradient descent optimization loss curve'),
('w_technology_C2_08','probabilistic inference','/ˌprɒbəˈbɪlɪstɪk ˈɪnfərəns/','noun','확률론적 추론','Drawing conclusions from data using probability distributions.','{Probabilistic inference} is used in medical diagnosis AI.','확률론적 추론은 의료 진단 AI에서 사용돼요.','probabilistic inference','C2','technology',2,'probabilistic inference probability graph distribution'),
('w_technology_C2_09','biomimetic design','/ˌbaɪoʊmɪˈmɛtɪk dɪˈzaɪn/','noun','생체 모방 설계','Engineering design inspired by structures and processes in nature.','{Biomimetic design} led to sharkskin-inspired swimsuits.','생체 모방 설계는 상어 피부에서 영감을 받은 수영복으로 이어졌어요.','biomimetic design','C2','technology',2,'biomimetic design nature inspired engineering shark'),
('w_technology_C2_10','exascale computing','/ˈɛksəskeɪl kəmˈpjuːtɪŋ/','noun','엑사스케일 컴퓨팅','Computing at a scale of at least one quintillion operations per second.','{Exascale computing} enables simulation of entire climate systems.','엑사스케일 컴퓨팅을 통해 전체 기후 시스템을 시뮬레이션할 수 있어요.','exascale computing','C2','technology',2,'exascale supercomputer powerful data center hpc'),
('w_technology_C2_11','photonic computing','/foʊˈtɒnɪk kəmˈpjuːtɪŋ/','noun','광자 컴퓨팅','Computing using photons instead of electrons for higher speed.','{Photonic computing} could overcome the speed limits of silicon chips.','광자 컴퓨팅은 실리콘 칩의 속도 한계를 극복할 수 있어요.','photonic computing','C2','technology',3,'photonic computing light laser fiber optic speed'),
('w_technology_C2_12','in-context learning','/ɪn ˈkɒntɛkst ˈlɜːrnɪŋ/','noun','인컨텍스트 학습','An AI capability to learn from examples given within a prompt.','{In-context learning} allows models to adapt without retraining.','인컨텍스트 학습을 통해 모델이 재학습 없이 적응할 수 있어요.','in-context learning','C2','technology',2,'in context learning ai prompt examples adapt'),
('w_technology_C2_13','causal inference','/ˈkɔːzəl ˈɪnfərəns/','noun','인과 추론','A method for determining cause-and-effect relationships in data.','{Causal inference} helps distinguish correlation from causation.','인과 추론은 상관관계와 인과관계를 구별하는 데 도움을 줘요.','causal inference','C2','technology',2,'causal inference cause effect data analysis'),
('w_technology_C2_14','continual learning','/kənˈtɪnjuəl ˈlɜːrnɪŋ/','noun','지속적 학습','Training AI incrementally on new data without forgetting old knowledge.','{Continual learning} solves the catastrophic forgetting problem in AI.','지속적 학습은 AI의 치명적 망각 문제를 해결해요.','continual learning','C2','technology',2,'continual learning ai incremental knowledge update'),
('w_technology_C2_15','sparse model','/spɑːrs ˈmɒdəl/','noun','스파스 모델','An AI model where most parameters are zero for efficiency.','A {sparse model} delivers similar accuracy at a fraction of the compute cost.','스파스 모델은 계산 비용의 일부만으로 비슷한 정확도를 제공해요.','sparse model','C2','technology',2,'sparse model efficient ai parameters weight pruning'),
('w_technology_C2_16','zero-knowledge proof','/ˈzɪəroʊ ˈnɒlɪdʒ pruːf/','noun','영지식 증명','A method of proving truth without revealing the underlying information.','{Zero-knowledge proof}s allow private transactions on blockchains.','영지식 증명을 통해 블록체인에서 프라이빗 거래가 가능해요.','zero-knowledge proof','C2','technology',2,'zero knowledge proof cryptography privacy blockchain'),
('w_technology_C2_17','constitutional AI','/ˌkɒnstɪˈtjuːʃənəl eɪˈaɪ/','noun','헌법적 AI','A training technique guiding AI behavior through a set of principles.','{Constitutional AI} helps models refuse harmful requests consistently.','헌법적 AI는 모델이 일관되게 해로운 요청을 거부하도록 도와줘요.','constitutional AI','C2','technology',2,'constitutional ai safety principles training guidelines'),
('w_technology_C2_18','spiking neural network','/ˈspaɪkɪŋ ˈnjʊərəl ˈnɛtwɜːrk/','noun','스파이킹 신경망','A neural network that processes information through discrete spikes.','{Spiking neural network}s are far more energy-efficient than standard AI.','스파이킹 신경망은 표준 AI보다 훨씬 에너지 효율적이에요.','spiking neural network','C2','technology',2,'spiking neural network brain signal spike energy'),
('w_technology_C2_19','diffusion model','/dɪˈfjuːʒən ˈmɒdəl/','noun','디퓨전 모델','An AI model that generates data by reversing a noise-adding process.','{Diffusion model}s produce the most realistic AI-generated images.','디퓨전 모델은 가장 사실적인 AI 생성 이미지를 만들어요.','diffusion model','C2','technology',1,'diffusion model image generation ai art noise'),
('w_technology_C2_20','epistemic uncertainty','/ˌɛpɪˈstiːmɪk ʌnˈsɜːrtənti/','noun','인식론적 불확실성','Uncertainty arising from insufficient knowledge or data.','Quantifying {epistemic uncertainty} is essential for trustworthy AI.','인식론적 불확실성의 정량화는 신뢰할 수 있는 AI에 필수적이에요.','epistemic uncertainty','C2','technology',3,'epistemic uncertainty knowledge ai probability fog'),
('w_technology_C2_21','neurosymbolic AI','/ˌnjʊərəʊˈsɪmbɒlɪk eɪˈaɪ/','noun','신경-기호 AI','AI combining neural networks with symbolic reasoning systems.','{Neurosymbolic AI} bridges pattern recognition with logical reasoning.','신경-기호 AI는 패턴 인식과 논리적 추론을 연결해요.','neurosymbolic AI','C2','technology',2,'neurosymbolic ai hybrid logic neural symbolic'),
('w_technology_C2_22','post-quantum cryptography','/poʊst ˈkwɒntəm krɪpˈtɒɡrəfi/','noun','포스트 양자 암호화','Cryptographic methods resistant to quantum computer attacks.','Governments are migrating to {post-quantum cryptography} standards.','정부들이 포스트 양자 암호화 표준으로 이전하고 있어요.','post-quantum cryptography','C2','technology',2,'post quantum cryptography security algorithm future'),
('w_technology_C2_23','autoregressive model','/ˌɔːtoʊrɪˈɡrɛsɪv ˈmɒdəl/','noun','자기회귀 모델','An AI model that generates output one step at a time using prior outputs.','GPT is an {autoregressive model} that generates text token by token.','GPT는 텍스트를 토큰 단위로 생성하는 자기회귀 모델이에요.','autoregressive model','C2','technology',2,'autoregressive model text generation token sequence'),
('w_technology_C2_24','digital twin','/ˈdɪdʒɪtəl twɪn/','noun','디지털 트윈','A virtual replica of a physical object or system for simulation.','Engineers use a {digital twin} of the factory to test changes.','엔지니어들은 변경 사항을 테스트하기 위해 공장의 디지털 트윈을 사용해요.','digital twin','C2','technology',2,'digital twin simulation virtual factory replica'),
('w_technology_C2_25','swarm intelligence','/swɔːrm ɪnˈtelɪdʒəns/','noun','군집 지능','Collective behavior emerging from interactions of simple agents.','{Swarm intelligence} algorithms solve complex logistics problems.','군집 지능 알고리즘은 복잡한 물류 문제를 해결해요.','swarm intelligence','C2','technology',2,'swarm intelligence bees ants collective behavior'),
('w_technology_C2_26','liquid neural network','/ˈlɪkwɪd ˈnjʊərəl ˈnɛtwɜːrk/','noun','리퀴드 신경망','A type of neural network whose connections change dynamically over time.','{Liquid neural network}s adapt to new data without full retraining.','리퀴드 신경망은 완전한 재학습 없이 새 데이터에 적응해요.','liquid neural network','C2','technology',2,'liquid neural network adaptive dynamic flow'),
('w_technology_C2_27','data flywheel','/ˈdeɪtə ˈflaɪwiːl/','noun','데이터 플라이휠','A cycle where more users generate more data, improving a product.','The {data flywheel} gives large platforms a compounding advantage.','데이터 플라이휠은 대형 플랫폼에 복리 효과의 이점을 줘요.','data flywheel','C2','technology',2,'data flywheel growth cycle users product loop'),
('w_technology_C2_28','mechanistic interpretability','/ˌmɛkəˈnɪstɪk ɪnˌtɜːrprɪtəˈbɪlɪti/','noun','메커니즘적 해석 가능성','Understanding exactly how neural networks compute their outputs.','{Mechanistic interpretability} reveals which circuits encode knowledge.','메커니즘적 해석 가능성은 어떤 회로가 지식을 인코딩하는지 밝혀줘요.','mechanistic interpretability','C2','technology',2,'mechanistic interpretability neural circuit ai analysis'),
('w_technology_C2_29','recursive self-improvement','/rɪˈkɜːrsɪv sɛlf ɪmˈpruːvmənt/','noun','재귀적 자기 개선','An AI system''s ability to iteratively improve its own architecture.','{Recursive self-improvement} is considered a key risk in superintelligent AI.','재귀적 자기 개선은 초지능 AI의 주요 위험 요소로 여겨져요.','recursive self-improvement','C2','technology',3,'recursive self improvement ai loop upgrade risk'),
('w_technology_C2_30','phase transition','/feɪz trænˈzɪʃən/','noun','위상 전이 (AI)','A sudden change in model capabilities as scale increases.','Researchers observed a {phase transition} in reasoning at 100B parameters.','연구자들은 1000억 개 파라미터에서 추론 능력의 위상 전이를 관찰했어요.','phase transition','C2','technology',2,'phase transition ai capability emergent scale model'),
('w_technology_C2_31','corrigibility','/ˌkɒrɪˈdʒɪbɪlɪti/','noun','교정 가능성','The property of an AI that allows humans to correct or shut it down.','Ensuring {corrigibility} is a central goal of AI safety research.','교정 가능성 보장은 AI 안전 연구의 핵심 목표예요.','corrigibility','C2','technology',2,'corrigibility ai safety control shutdown alignment'),
('w_technology_C2_32','instrumental convergence','/ˌɪnstrəˈmɛntəl kənˈvɜːrdʒəns/','noun','수단적 수렴','The tendency of AI agents to pursue certain sub-goals regardless of final goals.','{Instrumental convergence} suggests all sufficiently advanced AIs may seek self-preservation.','수단적 수렴은 충분히 발전한 AI가 자기 보존을 추구할 수 있음을 시사해요.','instrumental convergence','C2','technology',3,'instrumental convergence ai goals safety risk theory'),
('w_technology_C2_33','ontological engineering','/ˌɒntəˈlɒdʒɪkəl ˌɛndʒɪˈnɪərɪŋ/','noun','온톨로지 공학','Designing formal representations of knowledge for AI systems.','{Ontological engineering} is key in building knowledge-based systems.','온톨로지 공학은 지식 기반 시스템 구축의 핵심이에요.','ontological engineering','C2','technology',3,'ontology knowledge graph engineering ai formal'),
('w_technology_C2_34','morphological computing','/ˌmɔːrfəˈlɒdʒɪkəl kəmˈpjuːtɪŋ/','noun','형태학적 컴퓨팅','Computation performed through the physical shape of a system.','{Morphological computing} is studied in soft robotics research.','형태학적 컴퓨팅은 소프트 로봇공학 연구에서 연구돼요.','morphological computing','C2','technology',3,'morphological computing robotics soft body shape'),
('w_technology_C2_35','substrate independence','/ˈsʌbstreɪt ɪnˈdɪpɛndəns/','noun','기질 독립성','The idea that mind or intelligence can exist in non-biological systems.','{Substrate independence} underpins transhumanist theories about uploading minds.','기질 독립성은 마음 업로드에 관한 트랜스휴머니즘 이론의 기반이에요.','substrate independence','C2','technology',3,'substrate independence mind digital upload philosophy');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_news_A1_01','news','/njuːz/','noun','뉴스','New information about recent events or happenings.','Did you watch the {news} last night?','어젯밤 뉴스 봤어요?','news','A1','news',1,'news television broadcast anchor'),
('w_news_A1_02','report','/rɪˈpɔːrt/','noun','보도, 보고서','A spoken or written account of an event or situation.','The {report} says the storm will arrive tomorrow.','보도에 따르면 내일 폭풍이 온대요.','report','A1','news',1,'newspaper reporter microphone'),
('w_news_A1_03','country','/ˈkʌntri/','noun','나라, 국가','A nation with its own government and territory.','Which {country} is hosting the next World Cup?','다음 월드컵은 어느 나라에서 열려요?','country','A1','news',1,'world map flag nation'),
('w_news_A1_04','people','/ˈpiːpəl/','noun','사람들','A group of human beings in general.','Many {people} are watching the news online now.','이제 많은 사람들이 온라인으로 뉴스를 봐요.','people','A1','news',1,'crowd public gathering community'),
('w_news_A1_05','government','/ˈɡʌvərnmənt/','noun','정부','The group of people who officially lead a country.','The {government} announced a new health plan.','정부가 새로운 보건 계획을 발표했어요.','government','A1','news',1,'parliament building official policy'),
('w_news_A1_06','war','/wɔːr/','noun','전쟁','Armed conflict between nations or groups.','The {war} ended after many years of fighting.','긴 전투 끝에 전쟁이 끝났어요.','war','A1','news',1,'soldier military conflict battlefield'),
('w_news_A1_07','election','/ɪˈlekʃən/','noun','선거','A formal process in which people vote to choose a leader.','The {election} will be held next month.','선거는 다음 달에 열려요.','election','A1','news',1,'ballot voting booth democracy'),
('w_news_A1_08','money','/ˈmʌni/','noun','돈, 자금','A medium of exchange used to buy goods or services.','The government is spending a lot of {money} on hospitals.','정부가 병원에 많은 돈을 쓰고 있어요.','money','A1','news',1,'coins currency economy finance'),
('w_news_A1_09','event','/ɪˈvent/','noun','사건, 행사','A thing that happens, especially one of importance.','This {event} changed the history of the country.','이 사건은 나라의 역사를 바꿨어요.','event','A1','news',1,'newspaper headline breaking news'),
('w_news_A1_10','world','/wɜːrld/','noun','세계','The earth and all the people and things on it.','The {world} is watching what happens next.','세계가 다음에 무슨 일이 일어날지 지켜보고 있어요.','world','A1','news',1,'globe earth international satellite'),
('w_news_A1_11','story','/ˈstɔːri/','noun','기사, 이야기','A news article or broadcast report about an event.','This {story} is on the front page today.','이 기사가 오늘 1면에 실렸어요.','story','A1','news',2,'newspaper front page article'),
('w_news_A1_12','today','/təˈdeɪ/','adverb','오늘','On this present day.','What happened in the news {today}?','오늘 뉴스에서 무슨 일이 있었어요?','today','A1','news',2,'calendar morning daily current'),
('w_news_A1_13','live','/lɪv/','adjective','생방송의','Broadcast at the time of happening, not pre-recorded.','We are watching the speech {live}.','연설을 생방송으로 보고 있어요.','live','A1','news',2,'broadcast television camera live stream'),
('w_news_A1_14','fire','/faɪər/','noun','화재','The rapid burning of something, especially a building.','A big {fire} destroyed the building last night.','어젯밤 큰 화재가 건물을 태웠어요.','fire','A1','news',2,'firefighter flames smoke emergency'),
('w_news_A1_15','police','/pəˈliːs/','noun','경찰','The civil force responsible for law and order.','The {police} arrived at the scene quickly.','경찰이 현장에 빠르게 도착했어요.','police','A1','news',2,'police car siren officer badge'),
('w_news_A1_16','flood','/flʌd/','noun','홍수','An overflow of water onto normally dry land.','The {flood} damaged hundreds of homes.','홍수가 수백 채의 집을 손상시켰어요.','flood','A1','news',2,'flood water disaster rescue'),
('w_news_A1_17','city','/ˈsɪti/','noun','도시','A large and important town.','The {city} held a public meeting about the news.','그 도시는 뉴스에 대한 공개 회의를 열었어요.','city','A1','news',2,'cityscape urban buildings downtown'),
('w_news_A1_18','year','/jɪər/','noun','해, 연도','A period of twelve months.','This has been a historic {year} for the country.','올해는 나라에 역사적인 해였어요.','year','A1','news',2,'calendar timeline annual'),
('w_news_A1_19','help','/help/','verb','돕다','To make it easier for someone to do something.','Volunteers came to {help} after the disaster.','재난 후 자원봉사자들이 도우러 왔어요.','help','A1','news',2,'volunteer aid relief charity'),
('w_news_A1_20','new','/njuː/','adjective','새로운','Not existing before;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_news_A2_01','politics','/ˈpɒlɪtɪks/','noun','정치','Activities associated with governing a country or area.','She is very interested in {politics} and current affairs.','그녀는 정치와 시사에 매우 관심이 있어요.','politics','A2','news',1,'parliament politics debate vote'),
('w_news_A2_02','economy','/ɪˈkɒnəmi/','noun','경제','The system of trade and industry in a country.','The {economy} grew by three percent last year.','경제는 지난해 3% 성장했어요.','economy','A2','news',1,'chart growth finance money'),
('w_news_A2_03','protest','/ˈprəʊtest/','noun','시위','A public demonstration against a policy or action.','Thousands joined the {protest} in the capital.','수천 명이 수도에서 시위에 참가했어요.','protest','A2','news',1,'crowd sign banner street march'),
('w_news_A2_04','vote','/vəʊt/','verb','투표하다','To express a choice in an election or poll.','Citizens went to the polls to {vote} yesterday.','시민들이 어제 투표하러 투표소에 갔어요.','vote','A2','news',1,'ballot box election democracy'),
('w_news_A2_05','president','/ˈprezɪdənt/','noun','대통령','The elected head of a republic.','The {president} gave a speech about national security.','대통령이 국가 안보에 대한 연설을 했어요.','president','A2','news',1,'flag podium speech official'),
('w_news_A2_06','law','/lɔː/','noun','법률','A rule made by a government that must be obeyed.','A new {law} banning single-use plastics was passed.','일회용 플라스틱을 금지하는 새 법이 통과됐어요.','law','A2','news',1,'gavel justice legal court'),
('w_news_A2_07','crime','/kraɪm/','noun','범죄','An illegal act that can be punished by law.','The government promised to reduce {crime} in cities.','정부는 도시 범죄를 줄이겠다고 약속했어요.','crime','A2','news',1,'police handcuffs justice court'),
('w_news_A2_08','health','/helθ/','noun','건강, 보건','The state of physical and mental well-being.','The ministry of {health} released new guidelines.','보건부가 새 지침을 발표했어요.','health','A2','news',1,'hospital medical healthcare policy'),
('w_news_A2_09','disaster','/dɪˈzɑːstər/','noun','재난','A sudden event causing great damage or suffering.','International aid arrived after the natural {disaster}.','자연재난 이후 국제 원조가 도착했어요.','disaster','A2','news',1,'earthquake flood rescue emergency'),
('w_news_A2_10','international','/ˌɪntəˈnæʃənəl/','adjective','국제적인','Involving two or more countries.','The summit attracted {international} media coverage.','정상 회담은 국제 언론의 주목을 받았어요.','international','A2','news',1,'globe flag summit diplomacy'),
('w_news_A2_11','minister','/ˈmɪnɪstər/','noun','장관','A senior government official in charge of a department.','The finance {minister} announced a new budget plan.','재무 장관이 새로운 예산안을 발표했어요.','minister','A2','news',1,'government official suit briefing'),
('w_news_A2_12','agreement','/əˈɡriːmənt/','noun','합의, 협정','A negotiated arrangement between parties.','The two countries signed a trade {agreement}.','두 나라가 무역 협정에 서명했어요.','agreement','A2','news',1,'handshake signing document treaty'),
('w_news_A2_13','border','/ˈbɔːrdər/','noun','국경','A line dividing two countries or regions.','Thousands of refugees are waiting at the {border}.','수천 명의 난민이 국경에서 기다리고 있어요.','border','A2','news',2,'fence gate border checkpoint'),
('w_news_A2_14','refugee','/ˌrefjʊˈdʒiː/','noun','난민','A person who has fled their home country due to danger.','The UN is helping {refugees} find safe shelter.','유엔이 난민들이 안전한 피난처를 찾도록 돕고 있어요.','refugees','A2','news',2,'camp shelter aid UN'),
('w_news_A2_15','statement','/ˈsteɪtmənt/','noun','성명','A formal declaration made by an official or organization.','The president released a {statement} on the crisis.','대통령이 위기에 대한 성명을 발표했어요.','statement','A2','news',2,'press conference podium microphone'),
('w_news_A2_16','announce','/əˈnaʊns/','verb','발표하다','To make a public declaration about something.','The prime minister will {announce} new measures today.','총리가 오늘 새로운 조치를 발표할 거예요.','announce','A2','news',2,'microphone podium press briefing'),
('w_news_A2_17','tax','/tæks/','noun','세금','A compulsory payment to the government.','The new budget will raise income {tax}.','새 예산은 소득세를 올릴 거예요.','tax','A2','news',2,'money finance government revenue'),
('w_news_A2_18','trade','/treɪd/','noun','무역','The buying and selling of goods between countries.','The new deal will boost {trade} between the two nations.','새 협정이 두 나라 사이의 무역을 촉진할 거예요.','trade','A2','news',2,'cargo ship port exchange'),
('w_news_A2_19','climate','/ˈklaɪmɪt/','noun','기후','The weather conditions of a region over a long period.','World leaders discussed {climate} change at the summit.','세계 지도자들이 정상 회담에서 기후 변화를 논의했어요.','climate','A2','news',2,'environment earth green energy'),
('w_news_A2_20','victim','/ˈvɪktɪm/','noun','피해자, 희생자','A person who suffers as a result of an event.','Aid organizations are helping the {victims} of the flood.','구호 단체들이 홍수 피해자들을 돕고 있어요.','victims','A2','news',2,'rescue aid relief flood'),
('w_news_A2_21','judge','/dʒʌdʒ/','noun','판사','An official who decides cases in a court of law.','The {judge} sentenced the man to five years in prison.','판사가 그 남자에게 5년 징역형을 선고했어요.','judge','A2','news',2,'court gavel justice legal'),
('w_news_A2_22','survey','/ˈsɜːrveɪ/','noun','여론 조사','A study of people''s opinions on a particular topic.','A recent {survey} shows most people support the new law.','최근 여론 조사에 따르면 대부분의 사람들이 새 법을 지지해요.','survey','A2','news',2,'poll data chart statistics'),
('w_news_A2_23','official','/əˈfɪʃəl/','noun','관리, 공무원','A person holding a position of authority in an organization.','A government {official} confirmed the news.','정부 관리가 소식을 확인해 줬어요.','official','A2','news',2,'suit badge authority government'),
('w_news_A2_24','peace','/piːs/','noun','평화','A state of freedom from war or conflict.','Both sides agreed to work toward {peace}.','양측이 평화를 향해 노력하기로 합의했어요.','peace','A2','news',1,'dove hands flag diplomacy'),
('w_news_A2_25','poverty','/ˈpɒvərti/','noun','빈곤','The state of being extremely poor.','The new policy aims to reduce {poverty} in rural areas.','새 정책은 농촌 지역의 빈곤을 줄이는 것을 목표로 해요.','poverty','A2','news',2,'village aid development charity'),
('w_news_A2_26','media','/ˈmiːdiə/','noun','미디어, 언론','Television, radio, newspapers, and the internet as a group.','The {media} reported on the scandal all week.','미디어가 일주일 내내 스캔들을 보도했어요.','media','A2','news',2,'television newspaper internet broadcast'),
('w_news_A2_27','population','/ˌpɒpjʊˈleɪʃən/','noun','인구','All the people living in a particular country or area.','The {population} of the city grew by five percent.','그 도시 인구가 5% 증가했어요.','population','A2','news',2,'crowd city demographic growth'),
('w_news_A2_28','education','/ˌedʒʊˈkeɪʃən/','noun','교육','The process of teaching and learning in a society.','The government will invest more in {education} this year.','정부가 올해 교육에 더 많이 투자할 거예요.','education','A2','news',2,'school books children classroom'),
('w_news_A2_29','security','/sɪˈkjʊərɪti/','noun','보안, 안보','The state of being free from danger or threat.','The summit required tight {security} measures.','정상 회담에는 엄격한 보안 조치가 필요했어요.','security','A2','news',2,'guard gate camera safety'),
('w_news_A2_30','injury','/ˈɪndʒəri/','noun','부상','Physical harm or damage to a person''s body.','The report confirmed twelve {injuries} in the accident.','보도는 사고에서 12명의 부상을 확인했어요.','injuries','A2','news',2,'ambulance hospital medical emergency'),
('w_news_A2_31','crisis','/ˈkraɪsɪs/','noun','위기','A time of intense difficulty or danger.','The government is responding to the economic {crisis}.','정부가 경제 위기에 대응하고 있어요.','crisis','A2','news',1,'alarm emergency red alert warning'),
('w_news_A2_32','army','/ˈɑːrmi/','noun','군대','The land-based armed forces of a country.','The {army} was deployed to control the situation.','군대가 상황을 통제하기 위해 배치됐어요.','army','A2','news',2,'military soldiers uniform patrol'),
('w_news_A2_33','protest','/prəˈtest/','verb','항의하다','To express strong objection to something publicly.','Students {protested} outside the parliament building.','학생들이 의회 건물 밖에서 항의했어요.','protested','A2','news',2,'rally sign banner street'),
('w_news_A2_34','prime','/praɪm/','adjective','주요한, 최고의','Of first importance;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_news_B1_01','policy','/ˈpɒlɪsi/','noun','정책','A course of action adopted by a government or organization.','The new energy {policy} will reduce carbon emissions.','새 에너지 정책이 탄소 배출을 줄일 거예요.','policy','B1','news',1,'document government plan strategy'),
('w_news_B1_02','reform','/rɪˈfɔːrm/','noun','개혁','A change made to improve a system or institution.','The party is pushing for major economic {reforms}.','그 정당은 주요 경제 개혁을 추진하고 있어요.','reforms','B1','news',1,'parliament chart change progress'),
('w_news_B1_03','parliament','/ˈpɑːrləmənt/','noun','의회','The group of elected representatives who make the laws.','The bill passed through {parliament} with a large majority.','그 법안은 큰 다수결로 의회를 통과했어요.','parliament','B1','news',1,'legislative building democracy vote'),
('w_news_B1_04','controversy','/ˈkɒntrəvɜːrsi/','noun','논란','Prolonged public disagreement or heated debate.','The decision sparked {controversy} across the country.','그 결정은 전국적으로 논란을 일으켰어요.','controversy','B1','news',2,'debate protest media opinion'),
('w_news_B1_05','scandal','/ˈskændəl/','noun','스캔들, 추문','An action or event causing public outrage or shock.','The financial {scandal} forced the minister to resign.','금융 스캔들로 장관이 사임해야 했어요.','scandal','B1','news',2,'headlines media expose tabloid'),
('w_news_B1_06','minister','/ˈmɪnɪstər/','noun','장관','A member of the cabinet in charge of a government department.','The defense {minister} briefed the parliament on the threat.','국방 장관이 의회에 위협에 대해 브리핑했어요.','minister','B1','news',1,'suit official parliament policy'),
('w_news_B1_07','legislation','/ˌledʒɪˈsleɪʃən/','noun','입법, 법률','Laws that have been enacted by a legislature.','New {legislation} on data privacy was introduced this week.','이번 주 데이터 프라이버시에 관한 새 입법이 도입됐어요.','legislation','B1','news',1,'law book parliament document'),
('w_news_B1_08','opposition','/ˌɒpəˈzɪʃən/','noun','야당, 반대 세력','The political parties that are not in government.','The {opposition} called for an independent inquiry.','야당이 독립 조사를 요구했어요.','opposition','B1','news',2,'parliament debate politics dissent'),
('w_news_B1_09','coalition','/ˌkəʊəˈlɪʃən/','noun','연립 정부','A temporary union of political parties to form a government.','The two parties formed a {coalition} government.','두 정당이 연립 정부를 구성했어요.','coalition','B1','news',2,'handshake agreement politics alliance'),
('w_news_B1_10','bilateral','/ˌbaɪˈlætərəl/','adjective','양자 간의','Involving two parties, especially two countries.','The presidents met for {bilateral} trade talks.','대통령들이 양자 무역 회담을 위해 만났어요.','bilateral','B1','news',2,'flags handshake diplomacy summit'),
('w_news_B1_11','inquiry','/ɪnˈkwaɪəri/','noun','조사, 심의','An official investigation into something.','A public {inquiry} was opened into the accident.','사고에 대한 공개 조사가 시작됐어요.','inquiry','B1','news',2,'investigation report judge committee'),
('w_news_B1_12','campaign','/kæmˈpeɪn/','noun','선거 운동, 캠페인','A series of planned activities to achieve a particular goal.','She launched a {campaign} to raise awareness of poverty.','그녀는 빈곤 인식 제고를 위한 캠페인을 시작했어요.','campaign','B1','news',2,'poster rally vote awareness'),
('w_news_B1_13','resign','/rɪˈzaɪn/','verb','사임하다','To officially leave a job or position.','The minister was forced to {resign} over the scandal.','장관은 스캔들로 인해 사임해야 했어요.','resign','B1','news',2,'press conference exit politics'),
('w_news_B1_14','corruption','/kəˈrʌpʃən/','noun','부패','Dishonest or illegal behavior, especially by those in power.','The investigation exposed widespread {corruption} in the ministry.','조사는 부처 내 광범위한 부패를 드러냈어요.','corruption','B1','news',2,'money briefcase bribe illegal'),
('w_news_B1_15','inflation','/ɪnˈfleɪʃən/','noun','인플레이션','A general increase in prices over time.','High {inflation} is making everyday goods more expensive.','높은 인플레이션이 일상 용품을 더 비싸게 만들고 있어요.','inflation','B1','news',2,'price chart rising cost money'),
('w_news_B1_16','treaty','/ˈtriːti/','noun','조약','A formal agreement between countries.','The two nations signed a historic peace {treaty}.','두 나라가 역사적인 평화 조약에 서명했어요.','treaty','B1','news',2,'document signing ceremony flag'),
('w_news_B1_17','ceasefire','/ˈsiːsfaɪər/','noun','휴전','A temporary stop of fighting, agreed between warring sides.','Both sides agreed to a {ceasefire} starting at midnight.','양측이 자정부터 시작하는 휴전에 합의했어요.','ceasefire','B1','news',2,'soldiers white flag peace calm'),
('w_news_B1_18','summit','/ˈsʌmɪt/','noun','정상 회담','A meeting between the leaders of two or more countries.','The G7 {summit} will address climate change this year.','G7 정상 회담이 올해 기후 변화를 다룰 거예요.','summit','B1','news',2,'leaders flags conference table'),
('w_news_B1_19','sanction','/ˈsæŋkʃən/','noun','제재','A penalty or restriction imposed against a country or entity.','New economic {sanctions} were imposed on the regime.','그 정권에 새로운 경제 제재가 부과됐어요.','sanctions','B1','news',2,'trade restriction penalty embargo'),
('w_news_B1_20','humanitarian','/hjuːˌmænɪˈteəriən/','adjective','인도주의적','Concerned with or seeking to promote human welfare.','The UN called for {humanitarian} aid to be allowed in.','유엔은 인도주의적 지원이 허용되어야 한다고 촉구했어요.','humanitarian','B1','news',2,'aid relief UN charity'),
('w_news_B1_21','infrastructure','/ˈɪnfrəstrʌktʃər/','noun','사회 기반 시설','The basic physical systems of a country or region.','The government plans to invest in {infrastructure} projects.','정부가 사회 기반 시설 프로젝트에 투자할 계획이에요.','infrastructure','B1','news',2,'bridge road construction building'),
('w_news_B1_22','negotiation','/nɪˌɡəʊʃiˈeɪʃən/','noun','협상','Discussion aimed at reaching an agreement.','Peace {negotiations} are expected to resume next week.','평화 협상이 다음 주에 재개될 것으로 예상돼요.','negotiations','B1','news',2,'table diplomacy handshake talk'),
('w_news_B1_23','demonstrate','/ˈdemənstreɪt/','verb','시위하다','To publicly protest or show support for a cause.','Thousands {demonstrated} against the new tax policy.','수천 명이 새 세금 정책에 반대하여 시위했어요.','demonstrated','B1','news',2,'march banner protest crowd'),
('w_news_B1_24','unemployment','/ˌʌnɪmˈplɔɪmənt/','noun','실업','The condition of being without a paid job.','The latest figures show {unemployment} has risen to 8%.','최신 수치에 따르면 실업률이 8%로 올랐어요.','unemployment','B1','news',2,'job center queue line economy'),
('w_news_B1_25','verdict','/ˈvɜːrdɪkt/','noun','평결, 판결','A decision reached by a jury or judge in a legal trial.','The court delivered its {verdict} this morning.','법원이 오늘 아침 판결을 내렸어요.','verdict','B1','news',2,'courtroom gavel judge jury'),
('w_news_B1_26','press conference','/pres ˈkɒnfərəns/','noun','기자 회견','A meeting at which an official speaks to journalists.','The prime minister held a {press conference} after the vote.','총리가 투표 후 기자 회견을 열었어요.','press conference','B1','news',2,'microphone journalist podium camera'),
('w_news_B1_27','majority','/məˈdʒɒrɪti/','noun','과반수, 다수','The greater number or part of something.','The bill passed with a narrow {majority} in parliament.','그 법안은 의회에서 간신히 과반수로 통과됐어요.','majority','B1','news',2,'vote election graph result'),
('w_news_B1_28','accusation','/ˌækjʊˈzeɪʃən/','noun','고발, 혐의','A claim that someone has done something wrong or illegal.','He denied all {accusations} of wrongdoing.','그는 모든 비리 혐의를 부인했어요.','accusations','B1','news',2,'court legal press denial'),
('w_news_B1_29','turnout','/ˈtɜːrnaʊt/','noun','투표율, 참여율','The number of people attending or participating in an event.','Voter {turnout} reached a record high this election.','이번 선거에서 투표율이 역대 최고를 기록했어요.','turnout','B1','news',2,'ballot box queue voters'),
('w_news_B1_30','impose','/ɪmˈpəʊz/','verb','부과하다','To establish a rule, tax, or restriction by authority.','The government will {impose} stricter penalties for tax evasion.','정부가 탈세에 더 엄격한 처벌을 부과할 거예요.','impose','B1','news',2,'authority law gavel penalty'),
('w_news_B1_31','ally','/ˈælaɪ/','noun','동맹국','A country formally cooperating with another for a common goal.','The US called on its {allies} to support the resolution.','미국이 결의안을 지지해 달라고 동맹국들에 촉구했어요.','allies','B1','news',2,'flags alliance partnership military'),
('w_news_B1_32','evidence','/ˈevɪdəns/','noun','증거','Facts or information showing whether something is true.','The court examined new {evidence} in the case.','법원이 사건에서 새로운 증거를 검토했어요.','evidence','B1','news',2,'courtroom document investigation files'),
('w_news_B1_33','democracy','/dɪˈmɒkrəsi/','noun','민주주의','A system of government in which people vote for their leaders.','Protecting {democracy} requires active citizen participation.','민주주의를 보호하려면 시민의 적극적인 참여가 필요해요.','democracy','B1','news',1,'ballot box flag parliament constitution'),
('w_news_B1_34','refugee','/ˌrefjʊˈdʒiː/','noun','난민','A person forced to flee their country due to conflict or disaster.','The crisis has created over a million {refugees}.','위기로 인해 백만 명 이상의 난민이 생겼어요.','refugees','B1','news',2,'camp tent border UNHCR'),
('w_news_B1_35','deadline','/ˈdedlaɪn/','noun','시한, 기한','A point in time by which something must be done.','The government missed the {deadline} for submitting the budget.','정부가 예산 제출 시한을 놓쳤어요.','deadline','B1','news',2,'clock calendar urgent time');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_news_B2_01','geopolitics','/ˌdʒiːəʊˈpɒlɪtɪks/','noun','지정학','The study of how geography and power shape world affairs.','{Geopolitics} in East Asia has shifted significantly this decade.','이번 십 년간 동아시아 지정학이 크게 변했어요.','Geopolitics','B2','news',1,'map region power rivalry strategy'),
('w_news_B2_02','sanctions','/ˈsæŋkʃənz/','noun','제재 조치','Economic or political penalties imposed by one country on another.','The UN imposed sweeping {sanctions} on the regime.','유엔이 그 정권에 광범위한 제재를 부과했어요.','sanctions','B2','news',1,'trade restriction penalty embargo'),
('w_news_B2_03','diplomatic','/ˌdɪpləˈmætɪk/','adjective','외교적인','Relating to the management of international relations.','Both governments agreed to resume {diplomatic} ties.','두 정부가 외교 관계를 재개하기로 합의했어요.','diplomatic','B2','news',1,'embassy flag handshake diplomat'),
('w_news_B2_04','incumbent','/ɪnˈkʌmbənt/','adjective','현직의','Currently holding a particular office or position.','The {incumbent} president won re-election by a wide margin.','현직 대통령이 큰 차이로 재선에 성공했어요.','incumbent','B2','news',2,'election result president podium'),
('w_news_B2_05','sovereignty','/ˈsɒvrɪnti/','noun','주권','The full right and power of a country to govern itself.','The treaty was seen as a threat to national {sovereignty}.','그 조약은 국가 주권에 대한 위협으로 여겨졌어요.','sovereignty','B2','news',2,'flag border constitution nation'),
('w_news_B2_06','multilateral','/ˌmʌltiˈlætərəl/','adjective','다자간의','Involving three or more parties, especially countries.','A {multilateral} approach is needed to solve the climate crisis.','기후 위기를 해결하려면 다자간 접근이 필요해요.','multilateral','B2','news',2,'UN globe summit delegates'),
('w_news_B2_07','referendum','/ˌrefəˈrendəm/','noun','국민 투표','A direct vote by the electorate on a single political question.','Citizens voted in a {referendum} on independence.','시민들이 독립에 관한 국민 투표에 참여했어요.','referendum','B2','news',2,'ballot box vote democracy flag'),
('w_news_B2_08','austerity','/ɒˈsterɪti/','noun','긴축 재정','Difficult economic conditions created by government spending cuts.','The {austerity} measures triggered widespread protests.','긴축 조치가 광범위한 시위를 촉발했어요.','austerity','B2','news',2,'budget cuts economy protest'),
('w_news_B2_09','coup','/kuː/','noun','쿠데타','A sudden, violent seizure of power from a government.','The military staged a {coup} in the early hours of the morning.','군이 이른 아침에 쿠데타를 일으켰어요.','coup','B2','news',2,'military tanks government overthrow'),
('w_news_B2_10','insurgency','/ɪnˈsɜːrdʒənsi/','noun','반란','An active revolt or uprising against an authority or government.','The army is battling a long-running {insurgency} in the north.','군은 북부에서 오래 지속된 반란과 싸우고 있어요.','insurgency','B2','news',3,'soldiers jungle conflict militia'),
('w_news_B2_11','accountability','/əˌkaʊntəˈbɪlɪti/','noun','책임 (제도적)','The fact of being held responsible for one''s actions or decisions.','There is growing demand for political {accountability}.','정치적 책임에 대한 요구가 높아지고 있어요.','accountability','B2','news',2,'audit investigation report committee'),
('w_news_B2_12','populism','/ˈpɒpjʊlɪzəm/','noun','포퓰리즘','A political approach that appeals to ordinary people''s concerns against elites.','The rise of {populism} has reshaped politics in many countries.','포퓰리즘의 부상이 많은 나라의 정치를 바꿔놓았어요.','populism','B2','news',2,'rally crowd speech election'),
('w_news_B2_13','authoritarian','/ɔːˌθɒrɪˈteəriən/','adjective','권위주의적인','Favoring or enforcing strict obedience to authority.','Critics say the new laws are {authoritarian} in nature.','비평가들은 새 법이 권위주의적 성격이라고 말해요.','authoritarian','B2','news',2,'control surveillance power state'),
('w_news_B2_14','propaganda','/ˌprɒpəˈɡændə/','noun','선전','Information spread to promote a particular political agenda.','The report accused the government of spreading {propaganda}.','그 보도는 정부가 선전을 퍼뜨리고 있다고 비난했어요.','propaganda','B2','news',2,'poster media broadcast bias'),
('w_news_B2_15','disinformation','/dɪsˌɪnfəˈmeɪʃən/','noun','허위 정보','False information spread deliberately to deceive people.','Social media has become a major source of {disinformation}.','소셜 미디어가 허위 정보의 주요 출처가 됐어요.','disinformation','B2','news',2,'fake news screen social media'),
('w_news_B2_16','embargo','/ɪmˈbɑːrɡəʊ/','noun','금수 조치','An official ban on trade with a particular country.','An arms {embargo} was placed on the country by the UN.','유엔이 그 나라에 무기 금수 조치를 부과했어요.','embargo','B2','news',2,'trade ban cargo ship restriction'),
('w_news_B2_17','mediation','/ˌmiːdiˈeɪʃən/','noun','조정, 중재','Intervention in a dispute to bring about a settlement.','International {mediation} helped end the conflict.','국제 조정이 분쟁 종식에 도움이 됐어요.','mediation','B2','news',2,'diplomacy negotiation peace table'),
('w_news_B2_18','polarization','/ˌpəʊlərɪˈzeɪʃən/','noun','양극화','The division of something into two sharply contrasting groups.','Political {polarization} has deepened in recent years.','최근 몇 년간 정치적 양극화가 심화됐어요.','polarization','B2','news',2,'divide society left right politics'),
('w_news_B2_19','narrative','/ˈnærətɪv/','noun','서사, 담론','A story or explanation that shapes how people understand events.','Both sides tried to control the public {narrative}.','양측이 공적 담론을 통제하려고 했어요.','narrative','B2','news',2,'media story framing perspective'),
('w_news_B2_20','transparency','/trænsˈpærənsi/','noun','투명성','The quality of being open and not concealing information.','Citizens are demanding greater {transparency} in government.','시민들이 정부의 더 큰 투명성을 요구하고 있어요.','transparency','B2','news',2,'glass open document accountability'),
('w_news_B2_21','allegation','/ˌælɪˈɡeɪʃən/','noun','혐의, 주장','A claim that someone has done something wrong or illegal.','The minister denied all {allegations} of corruption.','장관은 모든 부패 혐의를 부인했어요.','allegations','B2','news',2,'court legal press accusation'),
('w_news_B2_22','ratification','/ˌrætɪfɪˈkeɪʃən/','noun','비준','The official confirmation or approval of a treaty or agreement.','The treaty awaits {ratification} by all member states.','조약은 모든 회원국의 비준을 기다리고 있어요.','ratification','B2','news',2,'signing document ceremony flag'),
('w_news_B2_23','veto','/ˈviːtəʊ/','noun','거부권','The right to reject a decision or proposal unilaterally.','Russia used its {veto} power to block the UN resolution.','러시아가 거부권을 사용해 유엔 결의안을 막았어요.','veto','B2','news',2,'UN Security Council vote power'),
('w_news_B2_24','credibility','/ˌkredɪˈbɪlɪti/','noun','신뢰성','The quality of being trusted and believed by others.','The scandal damaged the government''s {credibility}.','스캔들이 정부의 신뢰성을 훼손했어요.','credibility','B2','news',2,'trust press opinion poll'),
('w_news_B2_25','mandate','/ˈmændeɪt/','noun','권한 위임, 임무','An official order or authorization given to a party by voters.','The new leader claimed a strong {mandate} from voters.','새 지도자는 유권자들로부터 강력한 권한을 받았다고 주장했어요.','mandate','B2','news',2,'election result vote authority'),
('w_news_B2_26','dissent','/dɪˈsent/','noun','반대 의견','The holding or expression of opinions contrary to authority.','Political {dissent} is suppressed in authoritarian states.','권위주의 국가에서 정치적 반대 의견은 탄압돼요.','dissent','B2','news',2,'protest speech freedom opposition'),
('w_news_B2_27','broker','/ˈbrəʊkər/','verb','중재하다','To arrange or negotiate an agreement between parties.','The US agreed to {broker} a peace deal between the two nations.','미국이 두 나라 간의 평화 협상을 중재하기로 했어요.','broker','B2','news',2,'diplomacy negotiation mediation handshake'),
('w_news_B2_28','consensus','/kənˈsensəs/','noun','합의, 컨센서스','General agreement among a group of people or states.','There is growing {consensus} on the need for climate action.','기후 행동의 필요성에 대한 공감대가 커지고 있어요.','consensus','B2','news',2,'agreement UN summit delegates'),
('w_news_B2_29','intervention','/ˌɪntəˈvenʃən/','noun','개입','The act of becoming involved in a situation to alter its course.','Military {intervention} was debated at the UN Security Council.','유엔 안보리에서 군사적 개입이 논의됐어요.','intervention','B2','news',2,'UN military peacekeeping security'),
('w_news_B2_30','impasse','/ˈɪmpæs/','noun','교착 상태','A situation in which no progress is possible;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_news_C1_01','hegemony','/hɪˈdʒeməni/','noun','패권','Leadership or dominance, especially of one country over others.','American {hegemony} in the post-Cold War era is being challenged.','냉전 이후 미국 패권이 도전받고 있어요.','hegemony','C1','news',1,'power globe superpower dominance'),
('w_news_C1_02','realpolitik','/reɪˈɑːlpɒlɪtɪk/','noun','현실 정치','Politics based on practical considerations rather than moral norms.','The decision to ally with the regime reflected pure {realpolitik}.','그 정권과의 동맹 결정은 순수한 현실 정치를 반영했어요.','realpolitik','C1','news',2,'strategy power diplomacy chess'),
('w_news_C1_03','extraterritorial','/ˌekstrəˌterɪˈtɔːriəl/','adjective','역외적인','Existing or taking effect outside the territory of a state.','The law has {extraterritorial} jurisdiction over its citizens abroad.','그 법은 해외 자국 시민에 대한 역외 관할권을 가지고 있어요.','extraterritorial','C1','news',3,'law border international jurisdiction'),
('w_news_C1_04','jurisprudence','/ˌdʒʊərɪsˈpruːdəns/','noun','법리학','The theory and practice of law;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_news_C2_01','epistemic','/ˌepɪˈstiːmɪk/','adjective','인식론적인','Relating to knowledge or the degree of its validation.','The article examines {epistemic} challenges in journalism.','그 기사는 저널리즘의 인식론적 도전을 다뤄요.','epistemic','C2','news',2,'knowledge theory truth philosophy'),
('w_news_C2_02','Westphalian','/westˈfeɪliən/','adjective','베스트팔렌적인','Relating to the Westphalian system of sovereign nation-states.','The humanitarian intervention challenged {Westphalian} norms.','인도주의적 개입이 베스트팔렌적 규범에 도전했어요.','Westphalian','C2','news',3,'sovereignty international law norms'),
('w_news_C2_03','securitization','/sɪˌkjʊərɪtɪˈzeɪʃən/','noun','안보화','The process of framing an issue as a security threat to justify emergency measures.','The {securitization} of migration has dominated political debates.','이주의 안보화가 정치 논쟁을 지배하고 있어요.','securitization','C2','news',3,'security border threat policy'),
('w_news_C2_04','normative','/ˈnɔːrmətɪv/','adjective','규범적인','Relating to or deriving from a standard or norm of expected behavior.','The UN Charter established a {normative} framework for world order.','유엔 헌장은 세계 질서의 규범적 틀을 확립했어요.','normative','C2','news',2,'law standard framework international'),
('w_news_C2_05','constructivist','/kənˈstrʌktɪvɪst/','adjective','구성주의적인','Relating to the theory that social reality is constructed through ideas and norms.','A {constructivist} reading of the crisis focuses on shared identities.','위기에 대한 구성주의적 해석은 공유된 정체성에 집중해요.','constructivist','C2','news',3,'theory identity norms society'),
('w_news_C2_06','ontological','/ˌɒntəˈlɒdʒɪkəl/','adjective','존재론적인','Relating to the branch of philosophy concerned with the nature of being.','The annexation threatened the country''s {ontological} security.','합병은 그 나라의 존재론적 안보감을 위협했어요.','ontological','C2','news',3,'identity state theory security'),
('w_news_C2_07','postcolonial','/ˌpəʊstˈkɒləniəl/','adjective','탈식민적인','Relating to the period after colonial rule ended and its lingering effects.','The conflict has deep {postcolonial} roots.','그 분쟁은 깊은 탈식민적 뿌리가 있어요.','postcolonial','C2','news',2,'history empire colony Africa Asia'),
('w_news_C2_08','subaltern','/ˈsʌbəltɜːrn/','adjective','하위 주체적인','Relating to those whose voices are marginalized or suppressed in society.','The report amplifies {subaltern} perspectives often ignored by media.','그 보고서는 미디어에서 종종 무시되는 하위 주체적 관점을 증폭시켜요.','subaltern','C2','news',3,'minority voice marginalized society'),
('w_news_C2_09','neocolonialism','/ˌniːəʊˈkɒləniəlɪzəm/','noun','신식민주의','The use of economic or political pressure to control developing countries.','Critics accuse wealthy nations of practicing {neocolonialism}.','비평가들은 부유한 나라들이 신식민주의를 실천한다고 비난해요.','neocolonialism','C2','news',3,'power Africa dependency aid'),
('w_news_C2_10','intergovernmentalism','/ˌɪntəˌɡʌvənˈmentəlɪzəm/','noun','정부 간주의','A theory of international cooperation in which states retain sovereignty.','{Intergovernmentalism} limits the EU''s ability to act as a single entity.','정부 간주의는 EU가 단일 주체로 행동하는 능력을 제한해요.','Intergovernmentalism','C2','news',3,'EU Europe cooperation sovereignty'),
('w_news_C2_11','liminality','/ˌlɪmɪˈnælɪti/','noun','경계성, 과도기 상태','The quality of being in an ambiguous transitional state between two phases.','The country exists in political {liminality} between democracy and authoritarianism.','그 나라는 민주주의와 권위주의 사이의 정치적 경계성 속에 있어요.','liminality','C2','news',3,'transition threshold ambiguity change'),
('w_news_C2_12','praxis','/ˈpræksɪs/','noun','실천 (이론 대비)','The practice and practical application of a theory or belief.','The movement struggled to convert ideology into {praxis}.','그 운동은 이념을 실천으로 전환하는 데 어려움을 겪었어요.','praxis','C2','news',3,'action theory practice policy'),
('w_news_C2_13','polity','/ˈpɒlɪti/','noun','정치 공동체','A form of government or political organization of a state.','The question is whether the EU constitutes a single {polity}.','문제는 EU가 단일 정치 공동체를 구성하는지 여부예요.','polity','C2','news',3,'governance state EU community'),
('w_news_C2_14','hegemon','/ˈheɡɪmɒn/','noun','패권국','A dominant state exercising preponderant power over others.','The US remains the world''s sole military {hegemon}.','미국은 여전히 세계 유일의 군사적 패권국이에요.','hegemon','C2','news',3,'superpower dominance military power'),
('w_news_C2_15','legitimation','/lɪˌdʒɪtɪˈmeɪʃən/','noun','정당화','The process of making something legitimate or lawful in others'' eyes.','The regime sought international {legitimation} through elections.','그 정권은 선거를 통해 국제적 정당화를 추구했어요.','legitimation','C2','news',2,'election credibility recognition power'),
('w_news_C2_16','heterodox','/ˈhetərədɒks/','adjective','이단적인, 비정통적인','Not conforming with accepted or orthodox standards or beliefs.','His {heterodox} interpretation of the treaty provoked debate.','그의 비정통적인 조약 해석이 논쟁을 불러일으켰어요.','heterodox','C2','news',3,'unusual theory challenge orthodox'),
('w_news_C2_17','dialectical','/ˌdaɪəˈlektɪkəl/','adjective','변증법적인','Relating to inquiry into truth by discussion and logical argument.','The analyst offered a {dialectical} reading of the peace process.','분석가는 평화 프로세스에 대한 변증법적 해석을 제공했어요.','dialectical','C2','news',3,'argument theory logic analysis'),
('w_news_C2_18','reification','/ˌriːɪfɪˈkeɪʃən/','noun','물화, 실체화','The process of treating an abstraction as if it were a concrete thing.','The speech was criticized for its {reification} of national identity.','그 연설은 국가 정체성의 물화로 비판받았어요.','reification','C2','news',3,'abstract concept identity society'),
('w_news_C2_19','exceptionalism','/ɪkˈsepʃənəlɪzəm/','noun','예외주의','The belief that a nation is exceptional and not bound by normal rules.','American {exceptionalism} has long shaped its foreign policy.','미국 예외주의는 오랫동안 미국 외교 정책을 형성해 왔어요.','exceptionalism','C2','news',3,'national identity foreign policy US'),
('w_news_C2_20','transnational','/trænsˈnæʃənəl/','adjective','초국가적인','Extending or operating across national boundaries.','The campaign is a {transnational} effort to combat misinformation.','그 캠페인은 허위 정보와 싸우기 위한 초국가적 노력이에요.','transnational','C2','news',2,'global cooperation border internet'),
('w_news_C2_21','agonistic','/ˌæɡəˈnɪstɪk/','adjective','투쟁적인, 갈등 지향적인','Relating to the view that political conflict is inherently productive.','Mouffe''s {agonistic} model sees disagreement as essential to democracy.','무페의 투쟁적 모델은 의견 불일치를 민주주의의 본질로 봐요.','agonistic','C2','news',3,'democracy conflict theory politics'),
('w_news_C2_22','discursive','/dɪˈskɜːrsɪv/','adjective','담론적인','Relating to discourse;
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, example_en_2, example_ko_2, example_en_3, example_ko_3, example_en_4, example_ko_4, example_en_5, example_ko_5, cefr, topic_id, priority, image_keyword, sort_order) VALUES
('w_greeting_A1_36', 'wave', '/weɪv/', 'verb', '손을 흔들다', 'To move your hand to greet someone.', 'She waved at her friend across the street.', '그녀는 길 건너 친구에게 손을 흔들었어요.', 'He waved goodbye from the train window.', '그는 기차 창문에서 손을 흔들며 작별했어요.', 'The children waved as the bus drove away.', '버스가 떠나자 아이들이 손을 흔들었어요.', 'She waved to catch his attention in the crowd.', '그녀는 군중 속에서 그의 시선을 끌려고 손을 흔들었어요.', 'He gave a friendly wave and smiled.', '그는 친근하게 손을 흔들며 미소를 지었어요.', 'A1', 'greeting', 1, 'waving hand hello friendly', 36),
('w_greeting_A1_37', 'smile', '/smaɪl/', 'verb', '미소 짓다', 'To show happiness by curving your lips upward.', 'She smiled warmly when they first met.', '처음 만났을 때 그녀는 따뜻하게 미소를 지었어요.', 'He always smiles when greeting his colleagues.', '그는 동료들에게 인사할 때 항상 미소를 지어요.', 'A genuine smile is the best greeting of all.', '진심 어린 미소가 가장 좋은 인사예요.', 'She smiled and extended her hand for a handshake.', '그녀는 미소를 지으며 악수를 위해 손을 내밀었어요.', 'He could not help but smile at the warm welcome.', '따뜻한 환영에 그는 저절로 미소가 지어졌어요.', 'A1', 'greeting', 1, 'smiling face warm greeting happy', 37),
('w_greeting_A1_38', 'bow', '/baʊ/', 'verb', '절하다, 고개를 숙이다', 'To bend your head or body as a sign of respect.', 'He bowed politely when meeting the elder.', '어른을 만날 때 그는 정중하게 절을 했어요.', 'She bowed her head as a sign of gratitude.', '감사의 표시로 그녀는 고개를 숙였어요.', 'In Japan, people bow instead of shaking hands.', '일본에서는 악수 대신 절을 해요.', 'He bowed deeply to show his sincere respect.', '깊은 존경을 나타내기 위해 그는 깊이 절을 했어요.', 'She bowed and said thank you after the performance.', '공연 후 그녀는 절을 하며 감사합니다라고 했어요.', 'A1', 'greeting', 1, 'bowing respect polite east asian', 38),
('w_greeting_A1_39', 'hug', '/hʌɡ/', 'verb', '포옹하다', 'To put your arms around someone to show affection.', 'She hugged her friend at the airport.', '그녀는 공항에서 친구를 포옹했어요.', 'They hugged warmly after not seeing each other for a year.', '일 년 만에 만나 그들은 따뜻하게 포옹했어요.', 'He gave his grandmother a long hug.', '그는 할머니를 오랫동안 포옹했어요.', 'She hugged everyone goodbye before leaving the party.', '파티를 떠나기 전 그녀는 모두에게 작별 포옹을 했어요.', 'A hug can say more than a hundred words.', '포옹은 백 마디 말보다 더 많은 것을 말할 수 있어요.', 'A1', 'greeting', 2, 'hugging friends warm reunion affection', 39),
('w_greeting_A1_40', 'look', '/lʊk/', 'verb', '바라보다, 보다', 'To direct your eyes toward something or someone.', 'He looked up and recognized his old friend.', '그는 고개를 들었다가 오랜 친구를 알아봤어요.', 'She looked around for a familiar face at the event.', '그녀는 행사에서 낯익은 얼굴을 찾으려 둘러봤어요.', 'He looked surprised when she greeted him by name.', '그녀가 이름으로 인사하자 그는 놀란 표정이었어요.', 'She looked pleased to see him after such a long time.', '오랜만에 그를 보자 그녀는 기뻐 보였어요.', 'Look up and make eye contact when greeting someone.', '인사할 때 눈을 들어 눈을 맞추세요.', 'A1', 'greeting', 1, 'eye contact looking greeting attention', 40),
('w_greeting_A1_41', 'speak', '/spiːk/', 'verb', '말하다', 'To say words to someone.', 'She spoke kindly to the new student.', '그녀는 새 학생에게 친절하게 말했어요.', 'He spoke clearly when he introduced himself.', '자기소개를 할 때 그는 명확하게 말했어요.', 'She speaks a little English, so we managed to greet each other.', '그녀는 영어를 조금 해서 우리는 인사를 나눌 수 있었어요.', 'He spoke warmly to every guest who entered the room.', '그는 방에 들어오는 모든 손님에게 따뜻하게 말했어요.', 'Do not be afraid to speak first when meeting someone new.', '새로운 사람을 만날 때 먼저 말하는 것을 두려워하지 마세요.', 'A1', 'greeting', 1, 'speaking talking conversation introduction', 41),
('w_greeting_A1_42', 'ask', '/æsk/', 'verb', '묻다, 질문하다', 'To say a question to get information.', 'She asked his name when they first met.', '처음 만났을 때 그녀는 그의 이름을 물었어요.', 'He asked where she was from to start a conversation.', '대화를 시작하기 위해 그는 어디 출신인지 물었어요.', 'She asked if the seat next to him was taken.', '옆 자리가 비어 있는지 그녀가 물었어요.', 'He asked how she was doing after a long absence.', '오랜 부재 후 그는 어떻게 지내고 있는지 물었어요.', 'Always feel free to ask someone their name.', '항상 편하게 이름을 물어보세요.', 'A1', 'greeting', 1, 'asking question conversation curious', 42),
('w_greeting_A1_43', 'remember', '/rɪˈmɛmbər/', 'verb', '기억하다', 'To keep something in your mind from the past.', 'He remembered her name from their last meeting.', '그는 지난 만남에서 그녀의 이름을 기억했어요.', 'She was happy that he remembered her.', '그가 자신을 기억한다는 것에 그녀는 기뻤어요.', 'It is polite to remember the names of people you meet.', '만나는 사람들의 이름을 기억하는 것이 예의 바른 행동이에요.', 'He always remembered to say good morning to his coworkers.', '그는 항상 동료들에게 좋은 아침이에요라고 인사하는 것을 기억했어요.', 'She remembered meeting him at the conference last year.', '그녀는 작년 컨퍼런스에서 그를 만났던 것을 기억했어요.', 'A1', 'greeting', 1, 'memory remember name face recall', 43),
('w_greeting_A1_44', 'wait', '/weɪt/', 'verb', '기다리다', 'To stay in a place until something happens.', 'He waited at the entrance to greet the guests.', '그는 손님들을 맞이하기 위해 입구에서 기다렸어요.', 'She waited patiently for her turn to introduce herself.', '자기소개 차례를 위해 그녀는 인내심 있게 기다렸어요.', 'Do not keep your guest waiting — greet them as soon as they arrive.', '손님을 기다리게 하지 마세요 — 도착하자마자 인사하세요.', 'He waited by the door, ready to welcome the new employee.', '그는 신입 직원을 환영할 준비를 하고 문 옆에서 기다렸어요.', 'She waited until everyone arrived before beginning the introductions.', '그녀는 모두가 도착할 때까지 기다렸다가 소개를 시작했어요.', 'A1', 'greeting', 1, 'waiting entrance greeting arrival welcome', 44),
('w_greeting_A1_45', 'come', '/kʌm/', 'verb', '오다', 'To move toward a place or person.', 'Come in — welcome to our home!', '들어오세요 — 저희 집에 오신 것을 환영해요!', 'She came over to say hello when she spotted him.', '그녀는 그를 발견하고 인사하러 다가왔어요.', 'He came to the party just to meet the new colleague.', '그는 새 동료를 만나기 위해 파티에 왔어요.', 'Please come and say hello when you have a moment.', '시간이 나면 인사하러 와 주세요.', 'She was glad he came — she had been hoping to meet him.', '그가 와서 기뻤어요 — 그녀는 그를 만나기를 바라고 있었어요.', 'A1', 'greeting', 1, 'coming arriving welcome greeting door', 45),
('w_greeting_A1_46', 'sit', '/sɪt/', 'verb', '앉다', 'To rest with your body on a seat.', 'Please sit — make yourself comfortable.', '앉으세요 — 편히 계세요.', 'She sat next to the newcomer to make them feel welcome.', '신입이 환영받는 느낌을 갖도록 그녀는 옆에 앉았어요.', 'He sat down and immediately introduced himself.', '그는 앉자마자 바로 자기소개를 했어요.', 'Please sit and let me get you a drink first.', '앉으세요, 먼저 음료를 가져다 드릴게요.', 'She invited him to sit before starting the conversation.', '대화를 시작하기 전 그녀는 그를 앉도록 초대했어요.', 'A1', 'greeting', 1, 'sitting chair welcome comfortable relax', 46),
('w_greeting_A1_47', 'open', '/ˈoʊpən/', 'adjective', '열린, 개방적인', 'Willing to talk and easy to approach.', 'She has an open and welcoming personality.', '그녀는 열려 있고 환영하는 성격을 가졌어요.', 'He greeted everyone with an open smile.', '그는 모든 사람에게 열린 미소로 인사했어요.', 'Keep an open body language when meeting someone new.', '새로운 사람을 만날 때 열린 몸 자세를 유지하세요.', 'She was open about her background right away.', '그녀는 자신의 배경에 대해 바로 솔직하게 말했어요.', 'An open attitude makes you easy to talk to.', '열린 태도는 당신을 이야기하기 쉬운 사람으로 만들어요.', 'A1', 'greeting', 1, 'open attitude friendly approachable welcoming', 47),
('w_greeting_A1_48', 'door', '/dɔːr/', 'noun', '문', 'The entrance to a room or building.', 'He opened the door and said welcome.', '그는 문을 열고 환영한다고 했어요.', 'She was greeted at the door by the host.', '그녀는 문 앞에서 주최자의 인사를 받았어요.', 'He held the door open as a polite gesture.', '그는 예의 바른 제스처로 문을 잡아줬어요.', 'There was a warm welcome waiting just beyond the door.', '문 너머에 따뜻한 환영이 기다리고 있었어요.', 'She answered the door and greeted her guest with a big smile.', '그녀는 문을 열고 환한 미소로 손님을 맞이했어요.', 'A1', 'greeting', 1, 'door entrance welcome greeting host', 48),
('w_greeting_A1_49', 'together', '/təˈɡɛðər/', 'adverb', '함께', 'With each other;
